# 🔒  SECURITY LAYER 1 — SSRF Protection
# ══════════════════════════════════════════════════

_BLOCKED_NETS = [
    ip_network("127.0.0.0/8"),
    ip_network("10.0.0.0/8"),
    ip_network("172.16.0.0/12"),
    ip_network("192.168.0.0/16"),
    ip_network("169.254.0.0/16"),   # AWS/cloud metadata
    ip_network("100.64.0.0/10"),    # Carrier-grade NAT
    ip_network("0.0.0.0/8"),
    ip_network("::1/128"),
    ip_network("fc00::/7"),
    ip_network("fe80::/10"),
]

def _is_safe_ip(ip_str: str) -> bool:
    try:
        ip_obj = ip_address(ip_str)
        for net in _BLOCKED_NETS:
            if ip_obj in net:
                return False
        return True
    except (AddressValueError, ValueError):
        return False

def is_safe_url(url: str) -> tuple:
    """
    URL ကို validate လုပ်တယ်
    Returns: (is_safe: bool, reason: str)
    """
    if not url or len(url) > 2048:
        return False, "URL too long or empty"

    try:
        parsed = urlparse(url)
    except Exception:
        return False, "Invalid URL format"

    # Scheme စစ်
    if parsed.scheme not in ('http', 'https'):
        return False, f"Scheme '{parsed.scheme}' not allowed (http/https only)"

    # Hostname စစ်
    hostname = parsed.hostname
    if not hostname:
        return False, "No hostname"

    # Null byte / encoded traversal
    if '\x00' in url or '%00' in url:
        return False, "Null byte detected"

    # URL format — allowed chars only
    if not re.match(r'^https?://[^\s<>"{}|\\^`\[\]]+$', url):
        return False, "Invalid characters in URL"

    # DNS resolve + IP check
    try:
        ip_str = socket.gethostbyname(hostname)
        if not _is_safe_ip(ip_str):
            return False, f"IP {ip_str} is in a blocked network range"
    except socket.gaierror:
        return False, f"Cannot resolve hostname: {hostname}"

    return True, "OK"


# ══════════════════════════════════════════════════
# 🔒  SECURITY LAYER 2 — Path Traversal Protection
# ══════════════════════════════════════════════════

def safe_local_path(domain_dir: str, url: str) -> str:
    """
    URL → local path  (path traversal safe)
    """
    parsed = urlparse(url)
    path = parsed.path.lstrip('/')

    if not path or path.endswith('/'):
        path = path + 'index.html'

    _, ext = os.path.splitext(path)
    if not ext:
        path += '.html'

    if parsed.query:
        sq = re.sub(r'[^\w]', '_', parsed.query)[:20]
        base, ext = os.path.splitext(path)
        path = f"{base}_{sq}{ext}"

    # ── Path traversal check ──────────────────────
    local = os.path.normpath(os.path.join(domain_dir, path))
    real_domain = os.path.realpath(domain_dir)
    real_local  = os.path.realpath(os.path.join(domain_dir, path))

    if not real_local.startswith(real_domain + os.sep) and real_local != real_domain:
        # Traversal attempt → fallback to safe hash-based name
        logger.warning(f"Path traversal attempt blocked: {url}")
        safe_name = hashlib.md5(url.encode()).hexdigest()[:16]
        ext_guess = os.path.splitext(parsed.path)[1][:8] or '.bin'
        local = os.path.join(domain_dir, "assets", safe_name + ext_guess)

    os.makedirs(os.path.dirname(local), exist_ok=True)
    return local


# ══════════════════════════════════════════════════
# 🛡️  MARKDOWN SAFETY HELPERS
# ══════════════════════════════════════════════════

def escape_md(text: str) -> str:
    """
    Escape special Markdown v1 characters in dynamic/user-controlled content.
    Safe to embed inside * * bold or ` ` code spans.
    Escapes: _ * ` [ ]
    """
    if not isinstance(text, str):
        text = str(text)
    # In Markdown v1 these chars cause entity parse errors when unbalanced
    for ch in ('\\', '_', '*', '`', '[', ']'):
        text = text.replace(ch, '\\' + ch)
    return text


def _truncate_safe_md(text: str, limit: int = 4000) -> str:
    """
    Truncate *text* to *limit* chars without cutting inside an open Markdown
    entity (*bold*, _italic_, `code`).  Closes any tag left open at the cut.
    """
    if len(text) <= limit:
        return text
    cut = text[:limit]
    # Count opening/closing markers; if odd count → entity is open → trim back
    for marker in ('```', '`', '*', '_'):
        if cut.count(marker) % 2 != 0:
            idx = cut.rfind(marker)
            cut = cut[:idx]
    return cut.rstrip() + "\n_…truncated_"


async def safe_markdown_reply(target, text: str, **kwargs):
    """
    Send/edit with parse_mode='Markdown'.
    Falls back to plain text if Telegram rejects the entities (BadRequest).
    *target* can be a Message (reply_text) or an already-sent message (edit_text).
    """
    text = text or ""
    kwargs.setdefault("parse_mode", "Markdown")
    try:
        if hasattr(target, "edit_text"):
            return await target.edit_text(text, **kwargs)
        else:
            return await target.reply_text(text, **kwargs)
    except BadRequest as e:
        if "parse entities" in str(e).lower() or "can't parse" in str(e).lower():
            kwargs.pop("parse_mode", None)
            plain = re.sub(r'[_*`\[\]]', '', text)   # strip markdown symbols
            try:
                if hasattr(target, "edit_text"):
                    return await target.edit_text(plain[:4000], **kwargs)
                else:
                    return await target.reply_text(plain[:4000], **kwargs)
            except Exception:
                pass
        raise


async def safe_markdown_send(bot_or_ctx, chat_id: int, text: str, **kwargs):
    """
    bot.send_message() wrapper with Markdown safety + entity-parse fallback.
    """
    text = text or ""
    kwargs.setdefault("parse_mode", "Markdown")
    try:
        return await bot_or_ctx.send_message(chat_id=chat_id, text=text, **kwargs)
    except BadRequest as e:
        if "parse entities" in str(e).lower() or "can't parse" in str(e).lower():
            kwargs.pop("parse_mode", None)
            plain = re.sub(r'[_*`\[\]]', '', text)
            try:
                return await bot_or_ctx.send_message(
                    chat_id=chat_id, text=plain[:4000], **kwargs
                )
            except Exception:
                pass
        raise


