_CSP_PROVIDER_MAP = [
    ("www.google.com/recaptcha",      "reCAPTCHA v2/v3",          "HIGH"),
    ("recaptcha.google.com",          "reCAPTCHA Enterprise",     "HIGH"),
    ("hcaptcha.com",                  "hCaptcha",                 "HIGH"),
    ("challenges.cloudflare.com",     "Cloudflare Turnstile",     "HIGH"),
    ("newassets.hcaptcha.com",        "hCaptcha",                 "HIGH"),
    ("arkoselabs.com",                "FunCaptcha/Arkose",        "HIGH"),
    ("funcaptcha.com",                "FunCaptcha",               "HIGH"),
    ("geo.captcha.com",               "GeeTest",                  "HIGH"),
    ("gtcaptcha.com",                 "GeeTest v4",               "HIGH"),
    ("friendlycaptcha.com",           "FriendlyCaptcha",          "HIGH"),
    ("friendlycaptcha.eu",            "FriendlyCaptcha (EU)",     "HIGH"),
    ("captcha.awswaf.com",            "AWS WAF Captcha",          "HIGH"),
    ("datadome.co",                   "DataDome",                 "MEDIUM"),
    ("px-cloud.net",                  "PerimeterX",               "MEDIUM"),
    ("px-cdn.net",                    "PerimeterX",               "MEDIUM"),
    ("mtcaptcha.com",                 "MTCaptcha",                "HIGH"),
    ("p.lu8Y24.com",                  "Kasada",                   "HIGH"),
]

def _csp_captcha_detect(url: str) -> dict:
    """
    HEAD request တစ်ကြောင်းဖြင့် CSP header ကိုကြည့်ပြီး
    captcha provider ကို detect လုပ်သည်။
    """
    result = {
        "providers":      [],
        "csp_raw":        "",
        "feature_policy": "",
        "frame_ancestors": [],
    }
    try:
        r = requests.head(
            url, timeout=8, verify=False, allow_redirects=True,
            headers={"User-Agent": "Mozilla/5.0 (compatible; SecurityScanner/1.0)"}
        )
        headers = {k.lower(): v for k, v in r.headers.items()}
    except Exception as e:
        result["error"] = str(e)
        return result

    csp = headers.get("content-security-policy", "") or \
          headers.get("content-security-policy-report-only", "")
    result["csp_raw"]        = csp[:2000]
    result["feature_policy"] = headers.get("permissions-policy", "")

    if not csp:
        return result

    fa_match = re.search(r"frame-ancestors\s+([^;]+)", csp, re.I)
    if fa_match:
        result["frame_ancestors"] = fa_match.group(1).strip().split()

    csp_lower  = csp.lower()
    seen_names = set()
    for domain_frag, provider_name, confidence in _CSP_PROVIDER_MAP:
        if domain_frag.lower() in csp_lower and provider_name not in seen_names:
            seen_names.add(provider_name)
            result["providers"].append({
                "name":       provider_name,
                "confidence": confidence,
                "csp_domain": domain_frag,
            })
    return result


_PM_SITEKEY_PATTERNS = [
    re.compile(r'"sitekey"\s*:\s*"([A-Za-z0-9_\-]{20,})"',        re.I),
    re.compile(r'"site_key"\s*:\s*"([A-Za-z0-9_\-]{20,})"',       re.I),
    re.compile(r'"k"\s*:\s*"(6[A-Za-z0-9_\-]{38})"',              re.I),
    re.compile(r'"siteKey"\s*:\s*"(0x4[A-Za-z0-9_]{20,})"',       re.I),
    re.compile(r'"sitekey"\s*:\s*"([0-9a-f]{8}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{12})"', re.I),
]
_PM_ACTION_PATTERNS = [
    re.compile(r'"action"\s*:\s*"([A-Za-z0-9_\-/]{1,50})"',       re.I),
    re.compile(r'"challenge-type"\s*:\s*"([^"]{1,40})"',           re.I),
    re.compile(r'"type"\s*:\s*"(captcha|challenge|verify)[^"]*"',  re.I),
]
_PM_SCORE_PATTERNS = [
    re.compile(r'"score"\s*:\s*(0\.\d+)',                          re.I),
    re.compile(r'"minScore"\s*:\s*(0\.\d+)',                       re.I),
    re.compile(r'"threshold"\s*:\s*(0\.\d+)',                      re.I),
]

def _postmessage_sitekey(url: str, progress_cb=None) -> list:
    """
    Playwright ဖြင့် page load လုပ်ပြီး postMessage events ကို
    intercept လုပ်ကာ sitekey ထုတ်သည်။
    """
    try:
        from playwright.sync_api import sync_playwright, TimeoutError as PWTimeout
    except ImportError:
        return []

    if progress_cb: progress_cb("📨 PostMessage intercept — captcha iframe communication...")

    findings  = []
    seen_keys = set()
    pm_log    = []

    INJECT_SCRIPT = """
    window.__pm_captures = [];
    const _origAddEvent = window.addEventListener.bind(window);
    _origAddEvent('message', function(evt) {
        try {
            let raw = typeof evt.data === 'string' ? evt.data : JSON.stringify(evt.data);
            window.__pm_captures.push({ origin: evt.origin, data: raw.slice(0, 4000) });
        } catch(e) {}
    }, true);
    """

    with sync_playwright() as pw:
        browser = pw.chromium.launch(headless=True, args=["--no-sandbox", "--disable-gpu"])
        ctx     = browser.new_context(
            user_agent=(
                "Mozilla/5.0 (Windows NT 10.0; Win64; x64) "
                "AppleWebKit/537.36 (KHTML, like Gecko) "
                "Chrome/124.0.0.0 Safari/537.36"
            ),
            viewport={"width": 1280, "height": 800},
        )
        page = ctx.new_page()
        page.add_init_script(INJECT_SCRIPT)
        try:
            page.goto(url, timeout=20_000, wait_until="networkidle")
        except Exception:
            pass

        try:
            for sel in ['input[type="email"]', 'input[name="email"]', 'input[name="username"]']:
                if page.locator(sel).count() > 0:
                    page.locator(sel).first.fill("test@example.com", timeout=1500)
                    break
            for sel in ['input[type="password"]']:
                if page.locator(sel).count() > 0:
                    page.locator(sel).first.fill("Test@1234!", timeout=1500)
                    break
        except Exception:
            pass

        try:
            for sel in [
                'button[type="submit"]', 'input[type="submit"]',
                'button:text("Login")', 'button:text("Sign in")',
                'button:text("Continue")', 'button:text("Next")',
            ]:
                if page.locator(sel).count() > 0:
                    page.locator(sel).first.click(timeout=2000)
                    page.wait_for_timeout(3000)
                    break
        except Exception:
            pass

        try:
            pm_log = page.evaluate("window.__pm_captures || []")
        except Exception:
            pm_log = []
        browser.close()

    for entry in pm_log:
        data_str = entry.get("data", "")
        origin   = entry.get("origin", "unknown")
        if not data_str:
            continue
        for pat in _PM_SITEKEY_PATTERNS:
            for m in pat.finditer(data_str):
                key = m.group(1).strip()
                if key in seen_keys or len(key) < 10:
                    continue
                seen_keys.add(key)
                action = ""
                for ap in _PM_ACTION_PATTERNS:
                    am = ap.search(data_str)
                    if am:
                        action = am.group(1)
                        break
                score = ""
                for sp in _PM_SCORE_PATTERNS:
                    sm = sp.search(data_str)
                    if sm:
                        score = sm.group(1)
                        break
                cap_type = _classify_enh_sitekey_type(key)
                findings.append({
                    "type":       f"{cap_type} (postMessage)",
                    "site_key":   key,
                    "action":     action,
                    "min_score":  score,
                    "source":     f"postMessage ← iframe origin: {origin[:60]}",
                    "confidence": "CONFIRMED ✅",
                    "raw_msg":    data_str[:200],
                })

    if progress_cb:
        progress_cb(f"📨 postMessage: {len(pm_log)} messages → {len(findings)} sitekeys")
    return findings


_WELLKNOWN_PATHS = [
    ("/.well-known/recaptcha-challenge.json",        "reCAPTCHA Enterprise"),
    ("/.well-known/cloudflare/challenge-platform",   "Cloudflare Turnstile"),
    ("/.well-known/captcha.json",                    "Captcha Config"),
    ("/.well-known/security.txt",                    "Security Policy"),
    ("/.well-known/hcaptcha-challenge",              "hCaptcha"),
    ("/.well-known/apple-developer-merchantid-domain-association", "Apple Pay Merchant"),
    ("/.well-known/assetlinks.json",                 "Android/Google Pay"),
    ("/.well-known/aws-waf-captcha-integration",     "AWS WAF Captcha"),
    ("/.well-known/datadome",                        "DataDome"),
]

def _wellknown_captcha_probe(base_url: str, progress_cb=None) -> list:
    """
    Known /.well-known/ paths များကို probe လုပ်ပြီး
    captcha config, merchant ID, security policy ကို extract လုပ်သည်.
    """
    parsed  = urlparse(base_url)
    origin  = f"{parsed.scheme}://{parsed.netloc}"
    session = requests.Session()
    session.headers.update({"User-Agent": "Mozilla/5.0 (compatible; SecurityResearch/1.0)"})

    if progress_cb: progress_cb("🔍 /.well-known/ captcha config probe...")

    findings = []
    for path, provider in _WELLKNOWN_PATHS:
        probe_url = origin + path
        try:
            r = session.get(probe_url, timeout=6, verify=False, allow_redirects=False)
            if r.status_code != 200:
                continue
            content = r.text[:5000]
            ct      = r.headers.get("content-type", "").lower()
            finding = {
                "type":            provider,
                "path":            path,
                "content_preview": content[:300],
                "status":          r.status_code,
                "content_type":    ct,
            }
            if "json" in ct or content.strip().startswith("{"):
                try:
                    data = json.loads(content)
                    finding["parsed"] = data
                    for field in ("siteKey", "site_key", "key", "publicKey"):
                        if field in data:
                            finding["extracted_key"] = data[field]
                            break
                    if isinstance(data, list) and data and "target" in data[0]:
                        pkg = data[0]["target"].get("package_name", "")
                        finding["android_package"] = pkg
                except json.JSONDecodeError:
                    pass
            if "apple" in provider.lower():
                m = re.search(r'merchant\.[a-z0-9.\-]+', content, re.I)
                if m:
                    finding["merchant_id"] = m.group(0)
            if "security" in path:
                captcha_mentions = [kw for kw in ("recaptcha","hcaptcha","turnstile","captcha","bot") if kw in content.lower()]
                if captcha_mentions:
                    finding["captcha_mentions"] = captcha_mentions
            findings.append(finding)
        except requests.exceptions.ConnectionError:
            continue
        except Exception:
            continue

    if progress_cb:
        progress_cb(f"🔍 well-known: {len(findings)} config files found")
    return findings


def _extract_advanced_captcha_params(html: str, js_sources: dict, page_url: str) -> list:
    """
    HTML + JS source ထဲမှ captcha advanced parameters ကို extract:
    Turnstile action/cData/execution, reCAPTCHA v3 action/score, hCaptcha theme/endpoint
    """
    findings = []
    all_text = html + "\n" + "\n".join(js_sources.values())

    TURNSTILE_ELEM_RE = re.compile(
        r'(?:class=["\'][^"\']*cf-turnstile[^"\']*["\']|data-turnstile)[^>]*>',
        re.I | re.S
    )
    for elem_match in TURNSTILE_ELEM_RE.finditer(html):
        elem   = elem_match.group(0)
        params = {}
        for attr in ("data-sitekey","data-action","data-cdata","data-callback",
                     "data-error-callback","data-expired-callback","data-retry",
                     "data-retry-interval","data-execution","data-appearance",
                     "data-theme","data-size"):
            m = re.search(attr + r'=["\']([^"\']+)["\']', elem, re.I)
            if m:
                params[attr.replace("data-", "")] = m.group(1)
        if not params.get("sitekey"):
            continue
        sk = params.pop("sitekey")
        findings.append({
            "type":       "Cloudflare Turnstile (full params)",
            "site_key":   sk,
            "action":     params.get("action", ""),
            "params":     params,
            "source":     "HTML attribute (cf-turnstile element)",
            "confidence": "CONFIRMED ✅",
            "notes":      _turnstile_param_notes(params),
        })

    TS_RENDER_RE = re.compile(r'turnstile\.render\s*\([^)]*\{([^}]{10,600})\}', re.I | re.S)
    for m in TS_RENDER_RE.finditer(all_text):
        obj_text = m.group(1)
        sk_m     = re.search(r'sitekey\s*:\s*["\']([0-9A-Za-z_\-]{20,})["\']', obj_text, re.I)
        if not sk_m:
            continue
        sk     = sk_m.group(1)
        params = {}
        for field in ("action","cData","callback","execution","retry","appearance","theme"):
            fm = re.search(field + r'\s*:\s*["\']([^"\']{0,100})["\']', obj_text, re.I)
            if fm:
                params[field] = fm.group(1)
        findings.append({
            "type":       "Cloudflare Turnstile (JS render)",
            "site_key":   sk,
            "action":     params.get("action", ""),
            "params":     params,
            "source":     "JS turnstile.render() call",
            "confidence": "HIGH ✅",
            "notes":      _turnstile_param_notes(params),
        })

    RC3_EXECUTE_RE = re.compile(
        r'grecaptcha\.execute\s*\(\s*["\']([0-9A-Za-z_\-]{20,})["\']'
        r'\s*,\s*\{([^}]{0,300})\}',
        re.I | re.S
    )
    for m in RC3_EXECUTE_RE.finditer(all_text):
        sk       = m.group(1)
        obj_text = m.group(2)
        action   = ""
        am = re.search(r'action\s*:\s*["\']([^"\']{1,50})["\']', obj_text, re.I)
        if am:
            action = am.group(1)
        score_threshold = ""
        for sp in [
            re.compile(r'score\s*[<>]=?\s*(0\.\d+)', re.I),
            re.compile(r'threshold\s*[:=]\s*(0\.\d+)', re.I),
            re.compile(r'minScore\s*[:=]\s*(0\.\d+)', re.I),
        ]:
            start  = max(0, m.start() - 500)
            end    = min(len(all_text), m.end() + 500)
            sm     = sp.search(all_text[start:end])
            if sm:
                score_threshold = sm.group(1)
                break
        findings.append({
            "type":            "reCAPTCHA v3 (execute call)",
            "site_key":        sk,
            "action":          action,
            "score_threshold": score_threshold,
            "source":          "JS grecaptcha.execute() call",
            "confidence":      "CONFIRMED ✅",
            "notes": (
                f"Action: '{action}'" +
                (f" | Score threshold: {score_threshold}" if score_threshold else "") +
                (" ⚠️ Score threshold ≥ 0.7 means harder bypass" if score_threshold and float(score_threshold) >= 0.7 else "")
            ),
        })

    HC_RENDER_RE = re.compile(r'hcaptcha\.render\s*\([^)]*\{([^}]{10,600})\}', re.I | re.S)
    for m in HC_RENDER_RE.finditer(all_text):
        obj_text = m.group(1)
        sk_m     = re.search(r'sitekey\s*:\s*["\']([0-9a-f]{8}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{12})["\']', obj_text, re.I)
        if not sk_m:
            continue
        sk     = sk_m.group(1)
        params = {}
        for field in ("theme","size","tabindex","endpoint","host","reportapi","assethost","imghost"):
            fm = re.search(field + r'\s*:\s*["\']([^"\']{0,120})["\']', obj_text, re.I)
            if fm:
                params[field] = fm.group(1)
        custom_endpoint = params.get("endpoint","") or params.get("host","")
        findings.append({
            "type":       "hCaptcha (render params)",
            "site_key":   sk,
            "action":     "",
            "params":     params,
            "source":     "JS hcaptcha.render() call",
            "confidence": "CONFIRMED ✅",
            "notes": (
                (f"⚠️ Custom endpoint: {custom_endpoint}" if custom_endpoint else "") +
                (f" | Theme: {params.get('theme','')}" if params.get("theme") else "")
            ).strip(" |"),
        })

    seen  = set()
    dedup = []
    for f in findings:
        k = f.get("type","") + ":" + f.get("site_key","")
        if k not in seen:
            seen.add(k)
            dedup.append(f)
    return dedup


def _turnstile_param_notes(params: dict) -> str:
    """Turnstile parameter ကို human-readable notes ဖြင့် ရှင်းပြ"""
    notes = []
    ex = params.get("execution", "")
    if ex == "execute":
        notes.append("⚡ Explicit execution mode (programmatic trigger)")
    elif ex == "render":
        notes.append("🖼️ Auto-render mode")
    ap = params.get("appearance", "")
    if ap == "interaction-only":
        notes.append("👁️ Interaction-only (invisible until needed)")
    elif ap == "always":
        notes.append("🔲 Always visible widget")
    if params.get("retry") == "never":
        notes.append("🔒 Retry disabled (strict mode)")
    cdata = params.get("cData", "")
    if cdata:
        notes.append(f"📦 cData: '{cdata[:40]}' (custom context)")
    return " | ".join(notes) if notes else ""


_TRIGGER_SELECTORS = [
    'button[type="submit"]', 'input[type="submit"]',
    'button:has-text("Login")',    'button:has-text("Sign in")',
    'button:has-text("Log in")',   'button:has-text("Sign up")',
    'button:has-text("Register")', 'button:has-text("Continue")',
    'button:has-text("Next")',     'button:has-text("Submit")',
    'button:has-text("Send")',     'button:has-text("Get started")',
    'button:has-text("Create")',   'button:has-text("Join")',
    'form button:first-of-type',
    '[data-testid="submit-button"]', '[data-testid="login-button"]',
    '.submit-btn', '.login-btn', '.btn-primary',
]

_POST_TRIGGER_SITEKEY_PATTERNS = [
    re.compile(r'data-sitekey=["\']([0-9A-Za-z_\-]{20,})["\']',    re.I),
    re.compile(r'data-sitekey=["\']([0-9a-f]{8}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{12})["\']', re.I),
    re.compile(r'recaptcha[^"\']*[?&]k=([0-9A-Za-z_\-]{20,})',     re.I),
    re.compile(r'hcaptcha[^"\']*[?&]sitekey=([0-9a-f\-]{36})',      re.I),
    re.compile(r'challenges\.cloudflare[^"\']*[?&](?:sitekey|k)=([0-9A-Za-z_\-]{20,})', re.I),
]

def _interact_trigger_captcha(url: str, progress_cb=None) -> list:
    """
    Form field ဖြည့်ပြီး submit button click → invisible captcha reveal.
    Before/after DOM diff ဖြင့် newly appeared sitekeys ကို detect.
    """
    try:
        from playwright.sync_api import sync_playwright, TimeoutError as PWTimeout
    except ImportError:
        return []

    if progress_cb: progress_cb("🖱️ Form interaction — hidden captcha trigger...")

    new_findings = []
    seen_keys    = set()

    with sync_playwright() as pw:
        browser = pw.chromium.launch(
            headless=True,
            args=["--no-sandbox","--disable-gpu","--disable-dev-shm-usage"]
        )
        ctx  = browser.new_context(
            user_agent=(
                "Mozilla/5.0 (Windows NT 10.0; Win64; x64) "
                "AppleWebKit/537.36 (KHTML, like Gecko) "
                "Chrome/124.0.0.0 Safari/537.36"
            ),
            viewport={"width": 1280, "height": 800},
        )
        page = ctx.new_page()
        triggered_keys = set()

        def _on_request(req):
            for pat in _POST_TRIGGER_SITEKEY_PATTERNS:
                m = pat.search(req.url)
                if m:
                    triggered_keys.add(m.group(1))

        page.on("request", _on_request)
        try:
            page.goto(url, timeout=18_000, wait_until="networkidle")
        except Exception:
            pass

        before_html = ""
        try:
            before_html = page.content()
            for pat in _POST_TRIGGER_SITEKEY_PATTERNS:
                for m in pat.finditer(before_html):
                    seen_keys.add(m.group(1))
        except Exception:
            pass

        field_fill_pairs = [
            (['input[type="email"]','input[name="email"]','input[name="username"]',
              'input[name="user"]','input[name="login"]','input[id*="email"]'],
             "test@securityresearch.local"),
            (['input[type="password"]','input[name="password"]',
              'input[name="pass"]','input[id*="password"]'],
             "TestPassword@9999"),
            (['input[type="text"][name*="name"]','input[name="firstname"]',
              'input[name="first_name"]'], "Security"),
            (['input[type="tel"]','input[name="phone"]'], "+1-555-000-0000"),
        ]
        for selectors, value in field_fill_pairs:
            for sel in selectors:
                try:
                    loc = page.locator(sel)
                    if loc.count() > 0:
                        loc.first.fill(value, timeout=1500)
                        break
                except Exception:
                    continue

        clicked = False
        for sel in _TRIGGER_SELECTORS:
            try:
                loc = page.locator(sel)
                if loc.count() > 0:
                    loc.first.click(timeout=2000)
                    clicked = True
                    break
            except Exception:
                continue
        if not clicked:
            try:
                page.keyboard.press("Enter")
            except Exception:
                pass

        try:
            page.wait_for_timeout(4000)
        except Exception:
            pass

        after_html = ""
        try:
            after_html = page.content()
        except Exception:
            pass
        browser.close()

    for pat in _POST_TRIGGER_SITEKEY_PATTERNS:
        for m in pat.finditer(after_html):
            key = m.group(1)
            if key not in seen_keys and key not in triggered_keys:
                triggered_keys.add(key)

    for key in triggered_keys:
        cap_type = _classify_enh_sitekey_type(key)
        new_findings.append({
            "type":       f"{cap_type} (interaction-triggered)",
            "site_key":   key,
            "action":     "",
            "source":     "Revealed after form fill + submit click",
            "confidence": "CONFIRMED ✅",
            "notes":      "⚡ Invisible/conditional captcha — only appears after user interaction",
        })

    if progress_cb:
        progress_cb(f"🖱️ Interaction trigger: {len(new_findings)} hidden sitekeys revealed")
    return new_findings


def _classify_enh_sitekey_type(key: str) -> str:
    """Key format ကိုကြည့်ပြီး captcha type classify လုပ်"""
    if re.match(r'^6[A-Za-z0-9_\-]{39}$', key):
        return "reCAPTCHA v2/v3"
    if re.match(r'^[0-9a-f]{8}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{12}$', key, re.I):
        return "hCaptcha"
    if re.match(r'^0x4[A-Za-z0-9_]{20,}$', key):
        return "Cloudflare Turnstile"
    if re.match(r'^[0-9a-f]{32}$', key, re.I):
        return "GeeTest"
    if re.match(r'^[0-9A-Fa-f]{8}-[0-9A-Fa-f]{4}-', key):
        return "FunCaptcha/Arkose"
    return "Unknown Captcha"


def run_live_sitekey_enhancements(url: str, html: str = "", js_sources: dict = None, progress_cb=None) -> dict:
    """
    Enhancement ၅ ခုလုံးကို run ပြီး combined results return။
    _sitekey_sync() ထဲ call လုပ်ပြီး existing findings နှင့် merge လုပ်ရန်။
    """
    js_sources   = js_sources or {}
    all_findings = []
    meta         = {}

    # ① CSP fast detect
    if progress_cb: progress_cb("① CSP header — provider pre-detection...")
    csp_result = _csp_captcha_detect(url)
    meta["csp"] = csp_result
    if csp_result.get("providers"):
        pnames = [p["name"] for p in csp_result["providers"]]
        if progress_cb: progress_cb(f"  → CSP: {', '.join(pnames)} detected")

    # ② /.well-known/ probe
    wk_findings          = _wellknown_captcha_probe(url, progress_cb)
    meta["wellknown_count"] = len(wk_findings)
    meta["wellknown"]       = wk_findings
    for f in wk_findings:
        if f.get("extracted_key"):
            all_findings.append({
                "type":       f["type"] + " (well-known)",
                "site_key":   f["extracted_key"],
                "source":     f["path"],
                "confidence": "CONFIRMED ✅",
            })

    # ③ Advanced param extraction (HTML + JS)
    if html or js_sources:
        if progress_cb: progress_cb("③ Advanced params — action/cData/score extraction...")
        adv = _extract_advanced_captcha_params(html, js_sources, url)
        meta["advanced_params_count"] = len(adv)
        all_findings.extend(adv)

    # ④ PostMessage intercept (Playwright)
    pm_findings              = _postmessage_sitekey(url, progress_cb)
    meta["postmessage_count"] = len(pm_findings)
    all_findings.extend(pm_findings)

    # ⑤ Button interaction → hidden captcha
    inter_findings           = _interact_trigger_captcha(url, progress_cb)
    meta["interaction_count"] = len(inter_findings)
    all_findings.extend(inter_findings)

    meta["total_new"] = len(all_findings)
    return {"all_findings": all_findings, "meta": meta}


# ═══════════════════════════════════════════════════════════════════

def _sitekey_sync(url: str, progress_cb=None) -> dict:
    """
    Try Playwright (DevTools-style) first.
    Falls back to requests-based static scan if Playwright not available.
    Option A: Playwright constructor hooks (grecaptcha/hcaptcha/turnstile).
    Option B: Deep asset fetch for additional JS bundles.
    Phase 2: Real-time network stream intercept for confidence classification.
    """
    # ── Option A: Playwright dynamic hooks (sitekey category) ─────────
    if PLAYWRIGHT_OK:
        if progress_cb: progress_cb("🌐 Dynamic captcha hook intercept...")
        dyn = _playwright_dynamic_scan(url, "sitekey", progress_cb)
    else:
        dyn = {"hooks": {}, "xhr": [], "fetch_": [], "storage": {}}

    # ── Main playwright scan ───────────────────────────────────────────
    result = _sitekey_playwright(url, progress_cb)
    if result.get("error") == "playwright_not_installed":
        if progress_cb: progress_cb("⚠️ Playwright မရှိ — static scan သို့ fallback...")
        result = _sitekey_static(url, progress_cb)

    # ── Option A: merge hook captures into findings ────────────────────
    sk_hook = dyn.get("hooks", {}).get("sitekey", {})
    _hook_type_map = {
        "recaptcha_v2": "reCAPTCHA v2 (dynamic hook)",
        "recaptcha_v3": "reCAPTCHA v3 (dynamic hook)",
        "hcaptcha":     "hCaptcha (dynamic hook)",
        "turnstile":    "Cloudflare Turnstile (dynamic hook)",
    }
    existing_keys = {f.get("site_key", "") for f in result.get("findings", [])}
    for hook_k, type_label in _hook_type_map.items():
        val = sk_hook.get(hook_k, "")
        if val and val not in existing_keys:
            result.setdefault("findings", []).append({
                "type":     type_label,
                "site_key": val,
                "page_url": result.get("page_url", url),   # FIX: always set pageurl
                "source":   "Playwright constructor hook",
                "action":   "",
            })
            existing_keys.add(val)

    # ── Option B: deep asset fetch → re-scan with captcha patterns ─────
    if progress_cb: progress_cb("📦 Deep asset fetch for captcha keys...")
    existing_log = []
    new_assets   = _deep_asset_fetch(url, existing_log, progress_cb)

    if new_assets:
        all_js = {a["url"]: a["response_body"] for a in new_assets}
        html_  = ""
        extra  = _extract_captcha_info(html_, url, all_js)
        for f in extra:
            sk = f.get("site_key", "")
            if sk and sk not in existing_keys:
                f["source"] = f.get("source", "") + " [deep fetch]"
                result.setdefault("findings", []).append(f)
                existing_keys.add(sk)

    # ── Phase 2: Real-time network stream intercept ───────────────────
    if progress_cb: progress_cb("🔴 Phase 2: real-time network stream intercept...")
    live_result = _stream_intercept_sync(url, progress_cb, extra_patterns=_LIVE_SITEKEY_PATTERNS)

    # Scan live response bodies for captcha keys too
    live_all_js = {}
    for req in live_result.get("live_requests", []):
        body = req.get("body", "") or req.get("post_data", "")
        u    = req.get("url", "live")
        if body and len(body) > 20:
            live_all_js[u] = body[:500_000]
    if live_all_js:
        live_extra = _extract_captcha_info("", url, live_all_js)
        for f in live_extra:
            sk = f.get("site_key", "")
            if sk and sk not in existing_keys:
                f["source"] = f.get("source", "") + " [live stream]"
                f["confidence"] = "CONFIRMED ✅"
                result.setdefault("findings", []).append(f)
                existing_keys.add(sk)

    # FIX Bug5: inject session-1 network_log (request URL strings) into live_result
    # so _confidence_crossref.network_log branch can harvest captcha keys from URLs
    # like google.com/recaptcha/api2/anchor?k=6Lxxxxxx
    playwright_network_log = result.get("network_log", [])
    if playwright_network_log:
        live_result["network_log"] = live_result.get("network_log", []) + playwright_network_log

    # ── ENH: scan live response bodies as JSON for embedded sitekey configs ──
    # Some providers embed sitekey inside JSON API responses (e.g. /config.json)
    _sk_seen: set = {f.get("type","") + ":" + f.get("site_key","") for f in result.get("findings",[])}
    _sk_net_log = [
        {"url": r.get("url",""), "response_body": r.get("body",""),
         "response_headers": r.get("headers",{})}
        for r in live_result.get("live_requests", [])
    ]
    # Scan JSON responses for sitekey field names
    _sk_patterns = [
        ("reCAPTCHA sitekey (JSON)", re.compile(r'(?i)"siteKey"\s*:\s*"(6[A-Za-z0-9_\-]{38})"')),
        ("hCaptcha sitekey (JSON)",  re.compile(r'(?i)"sitekey"\s*:\s*"([0-9a-f]{8}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{12})"')),
        ("Turnstile sitekey (JSON)", re.compile(r'(?i)"siteKey"\s*:\s*"(0x4[A-Za-z0-9_]{20,})"')),
        ("Captcha key (response header)", re.compile(r'(?i)x-(?:captcha|recaptcha|hcaptcha)-key:\s*([A-Za-z0-9_\-]{20,})')),
    ]
    for entry in _sk_net_log:
        body = entry.get("response_body", "")
        if not body:
            continue
        for ktype, pat in _sk_patterns:
            for m in pat.finditer(body):
                val = m.group(1).strip()
                dedup = ktype + ":" + val
                if dedup not in _sk_seen and len(val) >= 8:
                    _sk_seen.add(dedup)
                    result.setdefault("findings", []).append({
                        "type":     ktype,
                        "site_key": val,
                        "source":   f"JSON response ← {entry.get('url','')[:70]}",
                        "confidence": "HIGH ✅",
                    })

    # ── LIVE ENHANCEMENTS: CSP + well-known + advanced params + postMessage + interact ──
    if progress_cb: progress_cb("🔑 Live sitekey enhancements (CSP/postMsg/interact)...")
    _enh_html     = result.get("html", "")
    _enh_js       = {a["url"]: a["response_body"] for a in new_assets} if new_assets else {}
    live_enh      = run_live_sitekey_enhancements(url, _enh_html, _enh_js, progress_cb)
    for f in live_enh["all_findings"]:
        sk = f.get("site_key", "")
        if sk and sk not in existing_keys:
            result.setdefault("findings", []).append(f)
            existing_keys.add(sk)
    result["live_enhancements"] = live_enh["meta"]

    result["live_result"] = live_result
    return result


def _merge_live_results(results: list) -> dict:
    """
    ENH S1: Merge multiple live_result dicts into one.
    All live_requests, live_findings, sse_frames, network_log, response_bodies combined.
    """
    merged = {
        "live_requests":   [],
        "live_findings":   [],
        "sse_frames":      [],
        "network_log":     [],
        "response_bodies": {},
    }
    seen_req_urls = set()
    for lr in results:
        if not lr:
            continue
        for req in lr.get("live_requests", []):
            uid = req.get("url", "")[:120]
            if uid not in seen_req_urls:
                seen_req_urls.add(uid)
                merged["live_requests"].append(req)
        merged["live_findings"].extend(lr.get("live_findings", []))
        merged["sse_frames"].extend(lr.get("sse_frames", []))
        merged["network_log"].extend(lr.get("network_log", []))
        merged["response_bodies"].update(lr.get("response_bodies", {}))
    return merged


def _discover_subpage_links(html: str, base_origin: str) -> list:
    """
    ENH S2: Extract actual auth/payment/form page links from HTML <a href>.
    Returns list of full URLs belonging to same origin, filtered by keywords.
    """
    keywords = {
        "login", "signin", "sign-in", "register", "signup", "sign-up",
        "checkout", "cart", "payment", "donate", "donate", "donation",
        "contact", "feedback", "subscribe", "billing", "order", "pay",
        "auth", "account", "join", "membership", "book", "booking",
        "upgrade", "pricing", "plans", "gift", "support",
    }
    found = set()
    for m in re.finditer(r'href=["\']([^"\'#?][^"\']*)["\']', html, re.I):
        href = m.group(1).strip()
        # Resolve relative URLs
        if href.startswith("http"):
            full = href
        elif href.startswith("/"):
            full = base_origin + href
        else:
            continue
        # Same-origin only
        if not full.startswith(base_origin):
            continue
        path_lower = urlparse(full).path.lower()
        if any(kw in path_lower for kw in keywords):
            found.add(full.split("?")[0])  # strip query params
    return list(found)[:20]  # cap at 20 discovered links


def _sitekey_with_subpages(url: str, progress_cb=None) -> dict:
    """
    v20 ENH: Scan main URL + sub-pages concurrently.
    ENH S1: Merge ALL sub-page live_results (not just best one).
    ENH S2: Link-driven sub-page discovery from HTML <a href>.
    ENH S3: Fix js_fetched to reflect actual JS file count.
    """
    parsed      = urlparse(url)
    base_origin = f"{parsed.scheme}://{parsed.netloc}"

    hardcoded_paths = [
        "/contact", "/donate", "/checkout", "/payment",
        "/register", "/signup", "/login", "/cart", "/donation",
        "/get-involved", "/give", "/contribute",
        "/pricing", "/plans", "/subscribe", "/membership",
        "/join", "/support", "/help", "/feedback",
        "/order", "/pay", "/billing", "/upgrade",
        "/sign-in", "/sign-up", "/forgot-password", "/reset-password",
        "/create-account", "/account/login", "/user/login",
        "/auth/login", "/auth/register", "/auth/signup",
        "/contact-us", "/reach-us", "/get-in-touch",
        "/book", "/booking", "/appointment", "/schedule",
    ]

    all_findings  = []
    seen_keys     = set()
    all_live_results = []   # ENH S1: collect ALL live results
    total_js_fetched = [0]  # ENH S3: track actual JS count

    def _scan_one(scan_url: str, label: str) -> tuple:
        """Scan one URL; return (tagged_findings, live_result, js_count)."""
        try:
            res = _sitekey_sync(scan_url)
        except Exception:
            return [], {}, 0
        hits = []
        for f in (res.get("findings") or []):
            dedup = f.get("type", "") + ":" + f.get("site_key", "")
            if dedup in seen_keys:
                continue
            seen_keys.add(dedup)
            tagged = dict(f)
            tagged["source"] = f"[{label}] " + f.get("source", "")
            hits.append(tagged)
        if progress_cb:
            scanned[0] += 1
            progress_cb(f"🔍 Scanning {scanned[0]}/{total} pages... ({label})")
        return hits, res.get("live_result") or {}, res.get("js_fetched", 0)

    scanned = [0]

    # ── ENH S2: Fetch main page HTML first to discover real sub-page links ──
    discovered_urls = []
    try:
        _r = requests.get(url, headers=_get_headers(), timeout=10, verify=False,
                          allow_redirects=True)
        if _r.status_code == 200:
            discovered_urls = _discover_subpage_links(_r.text, base_origin)
            if progress_cb and discovered_urls:
                progress_cb(f"🔗 Discovered {len(discovered_urls)} sub-pages from HTML links")
    except Exception:
        pass

    # Merge discovered + hardcoded, deduplicate
    all_sub_urls = list(dict.fromkeys(
        discovered_urls + [base_origin + p for p in hardcoded_paths]
    ))[:50]  # cap total at 50

    total = 1 + len(all_sub_urls)

    # ── Main URL (serial, first) ──────────────────────────────────────────
    if progress_cb:
        scanned[0] = 1
        progress_cb(f"🔍 Scanning 1/{total} pages... (main URL)")
    main_hits, main_live, main_js = _scan_one(url, "main")
    all_findings.extend(main_hits)
    all_live_results.append(main_live)          # ENH S1
    total_js_fetched[0] += main_js              # ENH S3

    # ── Sub-pages (concurrent, max 4 workers) ────────────────────────────
    def _scan_sub(sub_url: str) -> tuple:
        label = urlparse(sub_url).path or sub_url
        return _scan_one(sub_url, label)

    with concurrent.futures.ThreadPoolExecutor(max_workers=4) as ex:
        futures = {ex.submit(_scan_sub, u): u for u in all_sub_urls}
        sub_results = {}
        try:
            for fut in concurrent.futures.as_completed(futures, timeout=12 * len(all_sub_urls)):
                sub_url = futures[fut]
                try:
                    sub_results[sub_url] = fut.result(timeout=12)
                except Exception:
                    sub_results[sub_url] = ([], {}, 0)
        except concurrent.futures.TimeoutError:
            for fut in futures:
                fut.cancel()

    # ── Merge sub-page results ────────────────────────────────────────────
    for sub_url in all_sub_urls:
        hits, sub_live, sub_js = sub_results.get(sub_url, ([], {}, 0))
        all_findings.extend(hits)
        all_live_results.append(sub_live)       # ENH S1: collect all
        total_js_fetched[0] += sub_js           # ENH S3

    # ENH S1: Merge ALL live_results into one unified result
    merged_live = _merge_live_results(all_live_results)

    return {
        "findings":    all_findings,
        "page_url":    url,
        "js_fetched":  total_js_fetched[0],     # ENH S3: real JS count
        "error":       None,
        "live_result": merged_live,             # ENH S1: merged all pages
    }


# ══════════════════════════════════════════════════════════════════
# 🎯  SITEKEY IMPROVEMENT — Bypass Config Generator
#
#  Unique approach: ရှာတဲ့ key ကို ဘယ် solver service မှာ ဘယ်လို
#  call လုပ်ရမယ်ဆိုတဲ့ ready-to-use config ထုတ်ပေးတယ်
#  + Difficulty score (1-10) တွက်ပေးတယ်
# ══════════════════════════════════════════════════════════════════

_SITEKEY_DIFFICULTY_MAP = {
    "reCAPTCHA v2":           2,   # checkbox — easiest
    "reCAPTCHA v2 Invisible": 4,   # no UI — moderate
    "reCAPTCHA v3":           5,   # score-based
    "reCAPTCHA Enterprise":   8,   # enterprise — hard
    "hCaptcha":               4,
    "hCaptcha Invisible":     5,
    "Turnstile":              3,   # Cloudflare — relatively easy
    "Turnstile Invisible":    5,
    "FriendlyCaptcha":        6,
    "GeeTest":                7,
    "Arkose Labs":            9,   # hardest
}

def _sitekey_difficulty(finding: dict) -> tuple:
    """
    Returns (score: int, label: str, emoji: str)
    Score 1-10: 1=trivial, 10=near-impossible
    Adjusted by: min_score, enterprise, invisible flags
    """
    cap_type = finding.get("type", "")
    base = _SITEKEY_DIFFICULTY_MAP.get(cap_type, 5)

    # Adjust for min_score (v3 only)
    try:
        ms = float(finding.get("min_score") or 0)
        if ms >= 0.9:  base = min(10, base + 3)
        elif ms >= 0.7: base = min(10, base + 2)
        elif ms >= 0.5: base = min(10, base + 1)
    except (TypeError, ValueError):
        pass

    # Adjust for enterprise
    if finding.get("enterprise"):
        base = min(10, base + 2)

    # Adjust for invisible
    if finding.get("invisible"):
        base = min(10, base + 1)

    if base <= 2:   return base, "Trivial",    "🟢"
    elif base <= 4: return base, "Easy",       "🟡"
    elif base <= 6: return base, "Moderate",   "🟠"
    elif base <= 8: return base, "Hard",       "🔴"
    else:           return base, "Very Hard",  "⛔"


def _sitekey_bypass_configs(finding: dict) -> dict:
    """
    Generate solver-service configs for a captcha finding.
    Returns dict with keys: twocaptcha, capsolver, anticaptcha
    """
    cap_type = finding.get("type", "")
    site_key = finding.get("site_key", "")
    page_url = finding.get("page_url", "")
    action   = finding.get("action", "submit")
    min_score = finding.get("min_score") or "0.3"
    invisible = finding.get("invisible", False)
    enterprise = finding.get("enterprise", False)

    configs = {}

    # ── 2captcha ─────────────────────────────────────────────────
    if "reCAPTCHA v3" in cap_type or "Enterprise" in cap_type:
        configs["2captcha"] = {
            "method":    "userrecaptcha",
            "googlekey": site_key,
            "pageurl":   page_url,
            "version":   "v3",
            "action":    action,
            "min_score": str(min_score),
            **({"enterprise": 1} if enterprise else {}),
        }
    elif "reCAPTCHA" in cap_type:
        configs["2captcha"] = {
            "method":    "userrecaptcha",
            "googlekey": site_key,
            "pageurl":   page_url,
            **({"invisible": 1} if invisible else {}),
        }
    elif "hCaptcha" in cap_type:
        configs["2captcha"] = {
            "method":  "hcaptcha",
            "sitekey": site_key,
            "pageurl": page_url,
        }
    elif "Turnstile" in cap_type:
        configs["2captcha"] = {
            "method":  "turnstile",
            "sitekey": site_key,
            "pageurl": page_url,
        }

    # ── capsolver ─────────────────────────────────────────────────
    if "reCAPTCHA v3" in cap_type or "Enterprise" in cap_type:
        t = "ReCaptchaV3EnterpriseTaskProxyLess" if enterprise else "ReCaptchaV3TaskProxyLess"
        configs["capsolver"] = {
            "type":      t,
            "websiteURL": page_url,
            "websiteKey": site_key,
            "pageAction": action,
            "minScore":  float(min_score) if min_score else 0.3,
        }
    elif "reCAPTCHA v2" in cap_type:
        t = "ReCaptchaV2TaskProxyLess"
        configs["capsolver"] = {
            "type":       t,
            "websiteURL": page_url,
            "websiteKey": site_key,
            **({"isInvisible": True} if invisible else {}),
        }
    elif "hCaptcha" in cap_type:
        configs["capsolver"] = {
            "type":       "HCaptchaTaskProxyLess",
            "websiteURL": page_url,
            "websiteKey": site_key,
        }
    elif "Turnstile" in cap_type:
        configs["capsolver"] = {
            "type":       "AntiTurnstileTaskProxyLess",
            "websiteURL": page_url,
            "websiteKey": site_key,
        }

    # ── anticaptcha ───────────────────────────────────────────────
    if "reCAPTCHA v3" in cap_type:
        configs["anticaptcha"] = {
            "type":        "RecaptchaV3TaskProxyless",
            "websiteURL":  page_url,
            "websiteKey":  site_key,
            "minScore":    float(min_score) if min_score else 0.3,
            "pageAction":  action,
        }
    elif "reCAPTCHA" in cap_type:
        configs["anticaptcha"] = {
            "type":       "RecaptchaV2TaskProxyless",
            "websiteURL": page_url,
            "websiteKey": site_key,
            **({"isInvisible": True} if invisible else {}),
        }
    elif "hCaptcha" in cap_type:
        configs["anticaptcha"] = {
            "type":       "HCaptchaTaskProxyless",
            "websiteURL": page_url,
            "websiteKey": site_key,
        }

    return configs


def _format_sitekey_bypass_block(finding: dict) -> list:
    """
    Returns Telegram message lines for one finding's bypass section.
    """
    score, label, emoji = _sitekey_difficulty(finding)
    configs = _sitekey_bypass_configs(finding)

    lines = [
        f"  {emoji} *Difficulty:* `{score}/10` — {label}",
    ]

    if configs.get("capsolver"):
        cfg = configs["capsolver"]
        cfg_str = json.dumps(cfg, indent=2)
        # Keep it short for Telegram — show key fields only
        lines.append(f"  🟢 *Capsolver task type:* `{cfg.get('type','')}`")

    if configs.get("2captcha"):
        cfg = configs["2captcha"]
        lines.append(f"  🔵 *2captcha method:* `{cfg.get('method','')}`")

    if finding.get("action"):
        lines.append(f"  🎯 *Action:* `{finding['action']}`")
    if finding.get("min_score"):
        lines.append(f"  📊 *min\\_score:* `{finding['min_score']}`")

    return lines


def _sitekey_static(url: str, progress_cb=None) -> dict:
    """Fallback: requests-based static HTML + JS scan (no browser)."""
    session = requests.Session()
    session.headers.update(_get_headers())

    if progress_cb: progress_cb("⬇️ Fetching page HTML (static)...")
    try:
        resp = session.get(url, timeout=15, verify=False, allow_redirects=True)
        resp.raise_for_status()
        html     = resp.text
        page_url = resp.url
    except Exception as e:
        return {"error": str(e), "findings": [], "page_url": url}

    final_parsed = urlparse(page_url)
    base_origin  = f"{final_parsed.scheme}://{final_parsed.netloc}"

    def _resolve(src):
        if not src: return None
        src = src.strip()
        if src.startswith('//'): return final_parsed.scheme + ':' + src
        if src.startswith('http'): return src
        if src.startswith('/'): return base_origin + src
        base_path = final_parsed.path.rsplit('/', 1)[0]
        return f"{base_origin}{base_path}/{src}"

    soup = BeautifulSoup(html, 'html.parser')
    js_seen, js_ordered = set(), []

    def _add_js(u):
        if u and u.startswith('http') and u not in js_seen:
            js_seen.add(u); js_ordered.append(u)

    for tag in soup.find_all('script', src=True):
        _add_js(_resolve(tag['src']))

    captcha_sigs_flat = [s for sigs in _CAPTCHA_SCRIPT_SIGS.values() for s in sigs]
    def _prio(u):
        n = u.lower()
        if any(s in n for s in captcha_sigs_flat): return 0
        if any(k in n for k in ('main','app','index','chunk','bundle','vendor','runtime')): return 1
        return 2

    fetch_list = sorted(js_ordered, key=_prio)[:15]

    if progress_cb: progress_cb(f"📦 Fetching {len(fetch_list)} JS files...")
    js_sources = {}
    for js_url in fetch_list:
        try:
            r = session.get(js_url, timeout=10, verify=False)
            if r.status_code == 200 and len(r.text) > 50:
                js_sources[js_url] = r.text[:800_000]
        except Exception:
            pass

    if progress_cb: progress_cb(f"🔍 Scanning {len(js_sources)} JS files...")
    findings = _extract_captcha_info(html, page_url, js_sources)
    return {"findings": findings, "page_url": page_url, "js_fetched": len(js_sources), "error": None}


def _check_robots_permission(url: str) -> dict:
    """
    Fetch robots.txt and check if scanning is allowed for the given URL path.
    Returns {"allowed": bool, "status": str, "note": str}
    """
    try:
        from urllib.robotparser import RobotFileParser
        from urllib.parse import urlparse as _up
        parsed   = _up(url)
        base     = f"{parsed.scheme}://{parsed.netloc}"
        robots_url = base + "/robots.txt"
        rp = RobotFileParser()
        rp.set_url(robots_url)
        rp.read()
        path     = parsed.path or "/"
        ua       = "PhantomScope"
        allowed  = rp.can_fetch(ua, path) and rp.can_fetch("*", path)
        if allowed:
            crawl_delay = rp.crawl_delay("*") or rp.crawl_delay(ua)
            note = (
                f"robots.txt က scanning ခွင့်ပြုသည်"
                + (f" (crawl-delay: {crawl_delay}s)" if crawl_delay else "")
            )
            return {"allowed": True, "status": "✅ Allowed", "note": note}
        else:
            return {
                "allowed": False,
                "status":  "🚫 Disallowed by robots.txt",
                "note":    (
                    f"{parsed.netloc}/robots.txt မှာ `{path}` ကို "
                    "bot scan ခွင့်မပြု — မိမိ site မဟုတ်ပါက scan မလုပ်သင့်ပါ"
                ),
            }
    except Exception as e:
        # robots.txt fetch မရရင် → warning ပြပြီး allow (site မှာ robots.txt မရှိနိုင်)
        return {
            "allowed": True,
            "status":  "⚠️ robots.txt မတွေ့ (allow မည်)",
            "note":    f"robots.txt fetch မရ ({str(e)[:60]}) — site မှာ မရှိနိုင်သည်",
        }


def _get_solver_params(f: dict) -> dict:
    """
    Build per-service solver param dicts for a captcha finding.
    Returns {
        "2captcha":    {...},
        "anticaptcha": {...},
        "capsolver":   {...},
        "ezcaptcha":   {...},
    }
    """
    cap_type  = f.get("type", "")
    sitekey   = f.get("site_key") or f.get("value") or ""
    pageurl   = f.get("page_url", "")
    action    = f.get("action", "")
    min_score = f.get("min_score", "")
    invisible = f.get("invisible", False)
    enterprise = f.get("enterprise", False)
    s_param   = f.get("s_param", "")
    ua        = f.get("user_agent", "")

    # ── 2captcha / Anti-Captcha task type mapping ──────────────────
    def _2cap_task(ct):
        if "Enterprise" in ct:
            return ("RecaptchaV2EnterpriseTaskProxyless" if "v2" in ct.lower() or "v2" in ct
                    else "RecaptchaV3TaskProxyless")
        if "v3" in ct:   return "RecaptchaV3TaskProxyless"
        if "v2" in ct:   return "RecaptchaV2TaskProxyless"
        if "hCaptcha" in ct: return "HCaptchaTaskProxyless"
        if "Turnstile" in ct: return "TurnstileTaskProxyless"
        if "FunCaptcha" in ct: return "FunCaptchaTaskProxyless"
        if "GeeTest" in ct:   return "GeeTestTaskProxyless"
        if "AWS" in ct:       return "RecaptchaV2TaskProxyless"
        return "RecaptchaV2TaskProxyless"

    # ── CapSolver task type mapping ────────────────────────────────
    def _caps_task(ct):
        if "Enterprise" in ct and "v2" in ct: return "ReCaptchaV2EnterpriseTaskProxyLess"
        if "Enterprise" in ct and "v3" in ct: return "ReCaptchaV3EnterpriseTaskProxyLess"
        if "v3" in ct:   return "ReCaptchaV3TaskProxyLess"
        if "v2" in ct or "Enterprise" in ct: return "ReCaptchaV2TaskProxyLess"
        if "hCaptcha" in ct: return "HCaptchaTaskProxyLess"
        if "Turnstile" in ct: return "AntiTurnstileTaskProxyLess"
        if "FunCaptcha" in ct: return "FunCaptchaTaskProxyLess"
        if "GeeTest" in ct:   return "GeeTestTaskProxyLess"
        return "ReCaptchaV2TaskProxyLess"

    # ── Ez-Captcha / NextCaptcha task type mapping ─────────────────
    def _ez_task(ct):
        if "v3" in ct:   return "ReCaptchaV3TaskProxyless"
        if "v2" in ct or "Enterprise" in ct: return "ReCaptchaV2TaskProxyless"
        if "hCaptcha" in ct: return "HCaptchaTaskProxyless"
        if "Turnstile" in ct: return "TurnstileTaskProxyless"
        if "FunCaptcha" in ct: return "FunCaptchaTaskProxyless"
        return "ReCaptchaV2TaskProxyless"

    is_v3 = "v3" in cap_type
    is_hcap = "hCaptcha" in cap_type
    is_turnstile = "Turnstile" in cap_type
    is_funcaptcha = "FunCaptcha" in cap_type

    # ── 2captcha params ────────────────────────────────────────────
    p2c = {"type": _2cap_task(cap_type), "googlekey": sitekey, "pageurl": pageurl}
    if is_hcap:       p2c = {"type": _2cap_task(cap_type), "sitekey": sitekey, "pageurl": pageurl}
    if is_turnstile:  p2c = {"type": _2cap_task(cap_type), "sitekey": sitekey, "pageurl": pageurl}
    if is_funcaptcha: p2c = {"type": _2cap_task(cap_type), "publickey": sitekey, "pageurl": pageurl}
    if is_v3 and action:    p2c["action"]   = action
    if is_v3 and min_score: p2c["min_score"] = min_score
    if not is_v3 and invisible: p2c["invisible"] = "1"
    if enterprise and not is_v3: p2c["enterprise"] = "1"
    if s_param:  p2c["data-s"]    = s_param
    if ua:       p2c["userAgent"] = ua

    # Anti-Captcha uses same format as 2captcha
    pac = dict(p2c)

    # ── CapSolver params ───────────────────────────────────────────
    pcs = {"type": _caps_task(cap_type), "websiteURL": pageurl, "websiteKey": sitekey}
    if is_v3 and action:    pcs["pageAction"] = action
    if is_v3 and min_score: pcs["minScore"]   = float(min_score) if min_score else 0.5
    if not is_v3 and invisible: pcs["isInvisible"] = True
    if s_param: pcs["recaptchaDataSValue"] = s_param
    if ua:      pcs["userAgent"] = ua

    # ── Ez-Captcha / NextCaptcha params ───────────────────────────
    pez = {"type": _ez_task(cap_type), "websiteURL": pageurl, "websiteKey": sitekey}
    if is_v3 and action:    pez["pageAction"] = action
    if is_v3 and min_score: pez["minScore"]   = min_score
    if not is_v3 and invisible: pez["isInvisible"] = True
    if enterprise: pez["enterprisePayload"] = {}

    return {"2captcha": p2c, "anticaptcha": pac, "capsolver": pcs, "ezcaptcha": pez}


async def cmd_sitekey(update: Update, context: ContextTypes.DEFAULT_TYPE):
    """/sitekey <url> — Extract reCAPTCHA/hCaptcha/Turnstile site_key, page_url, action"""
    if not await check_force_join(update, context):
        return

    if not context.args:
        await update.effective_message.reply_text(
            "📌 *Usage:* `/sitekey https://example.com`\n\n"
            "🔑 *Extracts:*\n"
            "  • `site_key` — Captcha public key\n"
            "  • `page_url` — Final URL (after redirects)\n"
            "  • `action`   — reCAPTCHA v3 action name\n\n"
            "🛡️ *Supported Captcha Types:*\n"
            "  • reCAPTCHA v2 _(data-sitekey / grecaptcha.render)_\n"
            "  • reCAPTCHA v3 _(grecaptcha.execute + action)_\n"
            "  • reCAPTCHA Enterprise\n"
            "  • hCaptcha _(UUID format key)_\n"
            "  • Cloudflare Turnstile _(0x4A... / 1x00...)_\n"
            "  • FunCaptcha / Arkose Labs\n"
            "  • GeeTest\n"
            "  • AWS WAF Captcha\n\n"
            "📦 HTML source + JS bundles ကို scan မည်",
            parse_mode='Markdown'
        )
        return

    uid = update.effective_user.id
    allowed, wait = check_rate_limit(uid)
    if not allowed:
        await update.effective_message.reply_text(f"⏳ `{wait}s` စောင့်ပါ", parse_mode='Markdown')
        return

    url = context.args[0].strip()
    if not url.startswith('http'):
        url = 'https://' + url

    safe_ok, reason = is_safe_url(url)
    if not safe_ok:
        await update.effective_message.reply_text(f"🚫 `{escape_md(reason)}`", parse_mode='Markdown')
        return

    domain = urlparse(url).netloc

    msg = await update.effective_message.reply_text(
        f"🔑 *Site Key Extractor*\n🌐 `{escape_md(domain)}`\n\n"
        "⏳ Scan စတင်နေသည်...",
        parse_mode='Markdown'
    )
    await asyncio.sleep(0.5)
    await msg.edit_text(
        f"🔑 *Site Key Extractor*\n🌐 `{escape_md(domain)}`\n\n"
        "🌐 Launching headless browser...\n"
        "📡 Intercepting network requests...\n"
        "🔍 Scanning DOM + console logs...\n⏳",
        parse_mode='Markdown'
    )

    progress_q = []

    async def _prog():
        while True:
            await asyncio.sleep(2)
            if progress_q:
                txt = progress_q[-1]; progress_q.clear()
                try:
                    await msg.edit_text(
                        f"🔑 *Scanning `{escape_md(domain)}`*\n\n{txt}",
                        parse_mode='Markdown')
                except BadRequest:
                    pass

    prog = asyncio.create_task(_prog())
    try:
        result = await asyncio.to_thread(
            _sitekey_with_subpages, url, lambda t: progress_q.append(t)
        )
    except Exception as e:
        prog.cancel()
        await msg.edit_text(f"❌ Error: `{escape_md(e)}`", parse_mode='Markdown')
        return
    finally:
        prog.cancel()

    if result.get("error"):
        await msg.edit_text(
            f"❌ *Fetch error*\n`{result['error']}`",
            parse_mode='Markdown'
        )
        return

    raw_findings = result.get("findings", [])
    live_result  = result.get("live_result") or {"live_requests": [], "live_findings": [], "sse_frames": []}
    page_url     = result["page_url"]
    js_count     = result.get("js_fetched", 0)
    live_reqs    = len(live_result.get("live_requests", []))

    # Cross-reference: use site_key as the "value" field for confidence scoring
    for f in raw_findings:
        if "value" not in f:
            f["value"] = f.get("site_key", "")
    findings_xref = _confidence_crossref(raw_findings, live_result)
    # Restore site_key field
    for orig, f in zip(raw_findings, findings_xref[:len(raw_findings)]):
        f["site_key"] = orig.get("site_key", f.get("value", ""))
        for k in ("page_url","action","invisible","min_score","enterprise",
                  "theme","size","badge","s_param","hl","co","callback","user_agent"):
            if k in orig:
                f[k] = orig[k]

    confirmed   = [f for f in findings_xref if "CONFIRMED" in f.get("confidence","")]
    high_live   = [f for f in findings_xref if f.get("confidence","").startswith("HIGH")]
    static_only = [f for f in findings_xref if "STATIC" in f.get("confidence","")]
    findings    = findings_xref

    # ─── No captcha found ───────────────────────
    if not findings:
        await msg.edit_text(
            f"🔑 *Site Key Extractor — `{escape_md(domain)}`*\n"
            f"━━━━━━━━━━━━━━━━━━━━\n\n"
            f"📭 *Captcha မတွေ့ပါ*\n\n"
            f"🌐 Page URL: `{escape_md(page_url)}`\n"
            f"📡 Static: `{escape_md(js_count)}` | Live: `{escape_md(live_reqs)}`\n\n"
            "_Network requests, DOM, console logs အကုန် scan ပြီးပါပြီ_\n"
            "_Site မှာ Captcha မပါ သို့မဟုတ် render ပြီးမှ load ဖြစ်နိုင်သည်_",
            parse_mode='Markdown'
        )
        return

    # ─── Build report ────────────────────────────
    _TYPE_ICON = {
        "reCAPTCHA v2":          "🔵",
        "reCAPTCHA v3":          "🟣",
        "reCAPTCHA Enterprise":  "🟤",
        "hCaptcha":              "🟡",
        "Cloudflare Turnstile":  "🟠",
        "FunCaptcha":            "🔴",
        "GeeTest":               "🟢",
        "AWS WAF Captcha":       "⚪",
        "DataDome":              "🟤",
        "PerimeterX/HUMAN":      "🔶",
        "FriendlyCaptcha":       "🔷",
        "MTCaptcha":             "🔹",
        "Akamai Bot Manager":    "🟥",
    }

    # Deduplicated ordering: CONFIRMED → HIGH → STATIC
    seen_keys = set()
    ordered   = []
    for f, badge in (
        [(f, "✅ CONFIRMED") for f in confirmed] +
        [(f, "🔴 HIGH-LIVE") for f in high_live if f not in confirmed] +
        [(f, "⚠️ STATIC")   for f in static_only]
    ):
        sk = f.get("site_key", "") or f.get("value", "")
        if sk and sk in seen_keys:
            continue
        seen_keys.add(sk)
        ordered.append((f, badge))
    # Include remaining findings not yet categorized
    for f in findings:
        sk = f.get("site_key", "") or f.get("value", "")
        if sk not in seen_keys:
            seen_keys.add(sk)
            ordered.append((f, f.get("confidence", "⚠️ STATIC")))

    lines = [
        f"🔑 *Site Key Extractor — `{escape_md(domain)}`*",
        f"━━━━━━━━━━━━━━━━━━━━",
        f"🌐 Page URL: `{escape_md(page_url)}`",
        f"📡 Static: `{escape_md(js_count)}` JS | Live: `{escape_md(live_reqs)}` requests",
        f"✅ CONFIRMED: `{len(confirmed)}` | 🔴 Live: `{len(high_live)}` | ⚠️ Static: `{len(static_only)}`",
        f"🔑 Found: `{len(ordered)}` captcha instance(s)",
        "",
    ]

    _CAPTCHA_TYPES = {
        "reCAPTCHA", "hCaptcha", "Turnstile", "FunCaptcha",
        "GeeTest", "AWS WAF", "DataDome", "PerimeterX",
        "FriendlyCaptcha", "MTCaptcha", "Akamai",
    }

    entry_num = 0
    for f, badge in ordered:
        cap_type = f.get("type", "")
        sk       = f.get("site_key", "") or f.get("value", "") or "N/A"

        # JWT / non-captcha tokens ဖယ်ရှား
        if not any(ct in cap_type for ct in _CAPTCHA_TYPES):
            continue

        entry_num += 1
        icon = next((v for k, v in _TYPE_ICON.items() if k in cap_type), "🔑")

        # Key format validation
        clean_type = cap_type.replace(" ⚠️ (key not found)", "").strip()
        validator  = _KEY_VALIDATORS.get(clean_type)
        fmt_ok     = ""
        if sk and sk != "N/A" and validator:
            fmt_ok = " ✔️" if validator(sk) else " ✖️"

        lines.append(f"*{icon} [{entry_num}]* {badge}{fmt_ok} *{escape_md(cap_type)}*")
        _sk_safe = sk.replace("`", "'")
        lines.append(f"  🔑 `{_sk_safe}`")
        page = f.get("page_url", "")
        if page:
            _pg_safe = page[:80].replace("`", "'")
            lines.append(f"  🌐 `{_pg_safe}`")
        if f.get("action"):
            lines.append(f"  ⚡ `{f['action']}`")
        if f.get("invisible"):
            lines.append(f"  👁️ invisible")
        if f.get("min_score"):
            lines.append(f"  📊 score: `{f['min_score']}`")
        if f.get("enterprise"):
            lines.append(f"  🏢 enterprise")
        src = f.get("source", "")[:60]
        if src:
            lines.append(f"  📂 _{escape_md(src)}_")

        # ── Clean JSON-style solver params ──────────────────────
        sp_fields = {}
        sp_fields["type"]    = cap_type
        sp_fields["sitekey"] = sk
        if page:
            sp_fields["pageurl"] = page
        if f.get("action"):
            sp_fields["action"]    = f["action"]
        if f.get("enterprise"):
            sp_fields["enterprise"] = 1
        if f.get("min_score"):
            sp_fields["min_score"]  = float(f["min_score"])
        if f.get("invisible"):
            sp_fields["invisible"]  = 1
        if f.get("s_param"):
            sp_fields["data-s"]     = f["s_param"][:40]

        # Align values like JSON
        max_klen = max(len(k) for k in sp_fields)
        json_rows = []
        keys = list(sp_fields.keys())
        for idx2, (k, v) in enumerate(sp_fields.items()):
            pad    = " " * (max_klen - len(k))
            comma  = "," if idx2 < len(keys) - 1 else ""
            if isinstance(v, str):
                v_safe = v.replace("`", "'").replace("\\", "/")
                json_rows.append(f'  "{k}":{pad} "{v_safe}"{comma}')
            else:
                json_rows.append(f'  "{k}":{pad} {v}{comma}')
        json_block = "\n".join(["{"] + json_rows + ["}"])
        lines.append(f"```\n{json_block}\n```")
        lines.append("")

    lines.append("━━━━━━━━━━━━━━━━━━")
    lines.append("⚠️ _Authorized testing only_")
    lines.append("📄 _Full solver params — JSON export ကိုကြည့်ပါ_")

    report = "\n".join(lines)
    await safe_markdown_reply(msg, _truncate_safe_md(report))

    # ─── Export JSON ─────────────────────────────
    import io as _io
    ts        = datetime.now().strftime("%Y%m%d_%H%M%S")
    safe_d    = re.sub(r'[^\w\-]', '_', domain)
    export = {
        "domain":     domain,
        "page_url":   page_url,
        "scanned_at": datetime.now().isoformat(),
        "js_scanned": js_count,
        "live_requests_captured": live_reqs,
        "sse_frames_captured": len(live_result.get("sse_frames", [])),
        "confirmed": len(confirmed),
        "static_only": len(static_only),
        "findings": [
            {
                "type":       f.get("type", ""),
                "sitekey":    f.get("site_key") or f.get("value") or "",
                "pageurl":    f.get("page_url", page_url),
                "action":     f.get("action", ""),
                "enterprise": 1 if f.get("enterprise") else 0,
                "min_score":  float(f["min_score"]) if f.get("min_score") else None,
                "invisible":  1 if f.get("invisible") else 0,
                "data-s":     f.get("s_param", ""),
                "hl":         f.get("hl", ""),
                "co":         f.get("co", ""),
                "callback":   f.get("callback", ""),
                "user_agent": f.get("user_agent", ""),
                # ── Solver-ready format (per-service) ──
                "solver_params": _get_solver_params(f),
            }
            # FIX: exclude non-captcha types that bleed in from keydump/live pipeline
            for f in findings
            if not any(f.get("type", "").startswith(pfx) for pfx in (
                "Live JWT", "Live API", "Live Bearer", "Live AWS",
                "Live Stripe", "Live OpenAI", "Live storage",
                "Authorization", "X-Api-Key", "X-Auth-Token",
            ))
        ],
    }
    json_buf = _io.BytesIO(json.dumps(export, indent=2, ensure_ascii=False).encode())
    try:
        await context.bot.send_document(
            chat_id=update.effective_chat.id,
            document=json_buf,
            filename=f"sitekey_{safe_d}_{ts}.json",
            caption=(
                f"🔑 *Site Key Report — `{escape_md(domain)}`*\n"
                f"Found: `{len(findings)}` | JS: `{escape_md(js_count)}`"
            ),
            parse_mode='Markdown'
        )
    except Exception as e:
        logger.warning("Sitekey export error: %s", e)

    # ── Deobfuscation layer — obfuscated JS ထဲ ဖျောက်ထားတဲ့ keys ရှာ ─────────
    try:
        texts_for_deob = {}
        for item in result.get("network_log", []):
            if item.get("content_type","").startswith(("application/javascript","text/javascript")):
                body = item.get("response_body","") or ""
                if body:
                    lbl = item.get("url","?").split("/")[-1][:40]
                    texts_for_deob[lbl] = body
        # Also include HTML
        texts_for_deob["[HTML]"] = result.get("html", "")
        deob_findings = await asyncio.to_thread(_deobfuscate_layer, texts_for_deob)
        if deob_findings:
            high_deob = [f for f in deob_findings if f["in_secret_context"] and f["entropy"] >= 4.5]
            if high_deob:
                deob_lines = [f"\n🧩 *Deobfuscated Secrets — `{escape_md(domain)}`*",
                              "━━━━━━━━━━━━━━━━━━━━",
                              f"🔴 High-risk decoded: `{len(high_deob)}`\n"]
                for i, f in enumerate(high_deob[:8], 1):
                    deob_lines.append(f"*[{i}]* `{escape_md(f['method'])}` H=`{f['entropy']}`")
                    deob_lines.append(f"  ✅ `{escape_md(f['decoded'][:80])}`")
                    deob_lines.append(f"  📂 _{escape_md(f['source'])}_\n")
                deob_lines.append("⚠️ _Authorized testing only_")
                await update.effective_message.reply_text(
                    _truncate_safe_md("\n".join(deob_lines)), parse_mode='Markdown')
    except Exception as deob_err:
        logger.debug("sitekey deobfuscate layer error: %s", deob_err)
# ══════════════════════════════════════════════════

def _run_playwright_extract(url: str, js_eval_code: str, progress_cb=None) -> dict:
    """
    v19 UPGRADED Core Engine:
    - networkidle wait (JS SDK တွေ fully load ဖြစ်မှ scan)
    - response body 512KB (Phase 2: 120KB→512KB — webpack chunk အပြည့်ဖမ်း)
    - JS files 60 ခု fetch (Phase 2: 25→60 — code-split apps ပါ)
    - disable-web-security: iframe cross-origin request ဖမ်းနိုင်
    - Interactive simulation: scroll + payment button click
    - window globals deep scan: __NEXT_DATA__, __nuxt__, Stripe, etc.
    - All frames (including payment iframes) traversal
    """
    try:
        from playwright.sync_api import sync_playwright, TimeoutError as PWTimeout
    except ImportError:
        return {"error": "playwright_not_installed", "html": "", "network_log": [],
                "console_log": [], "dom_result": None, "page_url": url}

    network_log  = []
    console_log  = []
    page_url_ref = [url]
    _seen_urls   = set()

    with sync_playwright() as pw:
        _px = proxy_manager.get_proxy()
        _pw_proxy = None
        if _px:
            from urllib.parse import urlparse as _up
            _pp = _up(_px.get("http") or _px.get("https", ""))
            _pw_proxy = {"server": f"{_pp.scheme}://{_pp.hostname}:{_pp.port}"}
            if _pp.username:
                _pw_proxy["username"] = _pp.username
                _pw_proxy["password"] = _pp.password or ""

        browser = pw.chromium.launch(
            headless=True,
            args=[
                "--no-sandbox",
                "--disable-dev-shm-usage",
                "--disable-blink-features=AutomationControlled",
                "--disable-web-security",                          # iframe cross-origin ဖမ်းနိုင်
                "--disable-features=IsolateOrigins,site-per-process",
                "--allow-running-insecure-content",
                "--disable-gpu",
            ]
        )
        ctx = browser.new_context(
            user_agent=(
                "Mozilla/5.0 (Windows NT 10.0; Win64; x64) "
                "AppleWebKit/537.36 (KHTML, like Gecko) "
                "Chrome/122.0.0.0 Safari/537.36"
            ),
            viewport={"width": 1440, "height": 900},
            ignore_https_errors=True,
            proxy=_pw_proxy,
            java_script_enabled=True,
            extra_http_headers={
                "Accept-Language": "en-US,en;q=0.9",
                "Accept": "text/html,application/xhtml+xml,application/xml;q=0.9,*/*;q=0.8",
                "Sec-Fetch-Dest": "document",
                "Sec-Fetch-Mode": "navigate",
                "Sec-Fetch-Site": "none",
                "Sec-Fetch-User": "?1",
                "Upgrade-Insecure-Requests": "1",
            }
        )
        # Advanced stealth init
        ctx.add_init_script("""
            Object.defineProperty(navigator, 'webdriver', {get: () => undefined});
            Object.defineProperty(navigator, 'plugins', {get: () => [1,2,3,4,5]});
            Object.defineProperty(navigator, 'languages', {get: () => ['en-US','en']});
            window.chrome = {runtime: {}, loadTimes: function(){}, csi: function(){}, app: {}};
            Object.defineProperty(navigator, 'permissions', {
                get: () => ({query: () => Promise.resolve({state: 'granted'})})
            });
        """)
        page = ctx.new_page()

        def _add_network(url_str, method, post_data, response_body):
            if url_str not in _seen_urls:
                _seen_urls.add(url_str)
                network_log.append({
                    "url": url_str,
                    "method": method,
                    "post_data": post_data[:3000] if post_data else "",
                    "response_body": response_body[:524288] if response_body else "",
                })

        def _on_request(req):
            try:
                pd = req.post_data or ""
            except Exception:
                pd = ""
            _add_network(req.url, req.method, pd, "")

        def _on_response(resp):
            # ── Body ကို JS / JSON / text response တွေမှာ ဖမ်းသည် ──
            ct = resp.headers.get("content-type", "").lower()
            is_js   = any(x in ct for x in ("javascript", "ecmascript"))
            is_json = "json" in ct
            is_text = "text" in ct
            if not (is_js or is_json or is_text):
                return
            if resp.status not in (200, 201):
                return
            try:
                body = resp.body().decode("utf-8", errors="ignore")
            except Exception:
                return
            # Update existing entry or add new
            for entry in network_log:
                if entry["url"] == resp.url:
                    if not entry["response_body"]:
                        entry["response_body"] = body[:524288]
                    return
            _add_network(resp.url, "GET", "", body[:524288])

        page.on("request",  _on_request)
        page.on("response", _on_response)
        page.on("console",  lambda m: console_log.append(m.text[:500]))

        # ── Phase 3 Fix 1: WebSocket frame capture ──
        _ws_frames = []
        def _on_websocket(ws):
            ws_url = ws.url
            def _on_frame_sent(payload):
                if payload and len(str(payload)) > 4:
                    _ws_frames.append({"dir": "send", "url": ws_url,
                                       "payload": str(payload)[:500]})
            def _on_frame_recv(payload):
                if payload and len(str(payload)) > 4:
                    _ws_frames.append({"dir": "recv", "url": ws_url,
                                       "payload": str(payload)[:500]})
            ws.on("framesent",   _on_frame_sent)
            ws.on("framereceived", _on_frame_recv)
        page.on("websocket", _on_websocket)

        # ── Step 1: Initial page load — wait for networkidle ──
        try:
            page.goto(url, wait_until="load", timeout=30_000)
            page_url_ref[0] = page.url
        except PWTimeout:
            page_url_ref[0] = page.url
        except Exception as e:
            browser.close()
            return {"error": str(e), "html": "", "network_log": [],
                    "console_log": [], "dom_result": None, "page_url": url}

        # Wait for JS SDKs to fully initialize
        try:
            page.wait_for_load_state("networkidle", timeout=12_000)
        except Exception:
            pass
        page.wait_for_timeout(2000)

        # ── Step 2: Interactive simulation — trigger lazy-load JS ──
        try:
            # Scroll in steps (trigger IntersectionObserver lazy loads)
            for pct in [0.25, 0.5, 0.75, 1.0]:
                page.evaluate(f"window.scrollTo(0, document.body.scrollHeight * {pct})")
                page.wait_for_timeout(600)
            page.evaluate("window.scrollTo(0, 0)")
            page.wait_for_timeout(400)

            # Click payment / donate triggers to load payment SDKs
            _payment_selectors = [
                # Donation forms (GiveWP, Stripe Checkout, PayPal)
                "input[name='give-amount']", "input[name='amount']",
                "button[data-amount]", ".give-btn-level",
                "[class*='donate']", "[id*='donate']",
                "[class*='payment']", "[id*='payment']",
                # Generic checkout / submit
                "button[type='submit']", "input[type='submit']",
                "button[class*='checkout']", "button[class*='pay']",
                # Form fields (focus triggers captcha widget init)
                "input[type='email']", "input[type='text']:first-of-type",
                # Card number fields (Stripe Elements)
                ".__PrivateStripeElement", "[class*='StripeElement']",
                "iframe[name*='__privateStripeFrame']",
            ]
            for sel in _payment_selectors:
                try:
                    el = page.query_selector(sel)
                    if el and el.is_visible():
                        el.scroll_into_view_if_needed()
                        page.wait_for_timeout(200)
                        try:
                            el.click(timeout=1500)
                        except Exception:
                            pass
                        page.wait_for_timeout(300)
                except Exception:
                    pass

            # Wait for SDK network activity after interactions
            try:
                page.wait_for_load_state("networkidle", timeout=8_000)
            except Exception:
                pass
            page.wait_for_timeout(1500)

        except Exception:
            pass

        # ── Step 3: Fetch external JS bundles not yet captured ──
        try:
            js_urls_on_page = page.evaluate("""() =>
                [...document.querySelectorAll('script[src]')]
                    .map(s => s.src)
                    .filter(s => s.startsWith('http'))
            """) or []
        except Exception:
            js_urls_on_page = []

        # Also probe common manifest endpoints for chunk discovery
        from urllib.parse import urlparse as _up_js
        _base_parsed = _up_js(page_url_ref[0])
        _origin = f"{_base_parsed.scheme}://{_base_parsed.netloc}"
        _manifest_paths = [
            "/asset-manifest.json", "/webpack-manifest.json",
            "/__manifest__", "/static/js/main.chunk.js",
            "/js/app.js", "/js/main.js",
        ]
        for mp in _manifest_paths:
            murl = _origin + mp
            if murl not in _seen_urls:
                try:
                    r = ctx.request.get(murl, timeout=5000)
                    if r.ok and "json" in r.headers.get("content-type",""):
                        body = r.text()
                        _add_network(murl, "GET", "", body)
                        # Extract chunk URLs from manifest
                        import re as _re
                        for chunk_url in _re.findall(r'"(https?://[^"]+\.js)"', body):
                            if chunk_url not in _seen_urls:
                                js_urls_on_page.append(chunk_url)
                except Exception:
                    pass

        # ── Phase 2: Link header preload + dynamic import() chunk discovery ──
        import re as _re2
        # 1. HTTP Link header
        try:
            _link_resp = ctx.request.get(page_url_ref[0], timeout=5000)
            _link_hdr  = _link_resp.headers.get("link", "") or _link_resp.headers.get("Link", "")
            for _lm in _re2.finditer(r'<([^>]+\.js)>', _link_hdr):
                _lurl = _lm.group(1)
                if not _lurl.startswith("http"):
                    _lurl = _origin + (_lurl if _lurl.startswith("/") else "/" + _lurl)
                if _lurl not in _seen_urls:
                    js_urls_on_page.append(_lurl)
        except Exception:
            pass

        # 2. Dynamic import() / require.ensure() chunk URLs in already-fetched JS
        _dyn_pat = _re2.compile(r'(?:import\(|require\.ensure\(\[?)["\']([^"\']+\.js)["\']')
        for _entry in list(network_log):
            for _dm in _dyn_pat.finditer(_entry.get("response_body", "")[:80000]):
                _chunk = _dm.group(1)
                if not _chunk.startswith("http"):
                    _chunk = _origin + ("/" if not _chunk.startswith("/") else "") + _chunk
                if _chunk not in _seen_urls:
                    js_urls_on_page.append(_chunk)

        # 3. Next.js _buildManifest chunk list
        try:
            _bm_urls = _re2.findall(r'/_next/static/[^"\']+/_buildManifest\.js', html)
            for _bmu in _bm_urls[:2]:
                _bm_full = _origin + _bmu
                if _bm_full not in _seen_urls:
                    _bmr = ctx.request.get(_bm_full, timeout=5000)
                    if _bmr.ok:
                        _add_network(_bm_full, "GET", "", _bmr.text())
                        for _nc in _re2.findall(r'"(/[^"]+\.js)"', _bmr.text()):
                            _ncu = _origin + _nc
                            if _ncu not in _seen_urls:
                                js_urls_on_page.append(_ncu)
        except Exception:
            pass

        # Deduplicate chunk list
        js_urls_on_page = list(dict.fromkeys(js_urls_on_page))

        # Fetch uncaptured JS files (up to 60, Phase 2)
        fetched = 0
        for js_url in js_urls_on_page:
            if fetched >= 60:
                break
            if js_url in _seen_urls:
                existing = next((e for e in network_log if e["url"] == js_url), None)
                if existing and existing["response_body"]:
                    continue
            try:
                r = ctx.request.get(js_url, timeout=10000)
                if r.ok:
                    body = r.text()
                    _add_network(js_url, "GET", "", body[:524288])
                    fetched += 1
            except Exception:
                pass

        # ── Step 4: Deep window globals scan ──
        _DEEP_GLOBALS_JS = """() => {
            const out = {};
            // Payment SDK globals
            const payGlobals = [
                'Stripe', 'stripe', 'stripePublishableKey',
                'STRIPE_PUBLISHABLE_KEY', 'NEXT_PUBLIC_STRIPE_PUBLISHABLE_KEY',
                'REACT_APP_STRIPE_KEY', 'STRIPE_KEY',
                'paypal', 'PayPal', 'PAYPAL_CLIENT_ID',
                'braintree', 'square', 'razorpay',
                'Adyen', 'adyen', 'klarna', 'Klarna',
            ];
            payGlobals.forEach(k => {
                try {
                    const v = window[k];
                    if (v !== undefined && v !== null) {
                        if (typeof v === 'string') out[k] = v;
                        else if (typeof v === 'function' && v._apiKey) out[k+'._apiKey'] = v._apiKey;
                        else if (typeof v === 'object') {
                            try { out[k] = JSON.stringify(v).substring(0, 400); } catch(e) {}
                        }
                    }
                } catch(e) {}
            });

            // Framework env objects
            const envObjects = {
                '__NEXT_DATA__': window.__NEXT_DATA__,
                '__NUXT__': window.__NUXT__,
                '__APP_CONFIG__': window.__APP_CONFIG__,
                '__ENV__': window.__ENV__,
                '_env_': window._env_,
                'ENV': window.ENV,
                'appConfig': window.appConfig,
                'siteConfig': window.siteConfig,
                'wpApiSettings': window.wpApiSettings,
                'woocommerce_params': window.woocommerce_params,
                'give_global_vars': window.give_global_vars,
            };
            Object.entries(envObjects).forEach(([k,v]) => {
                if (!v) return;
                try {
                    const s = typeof v === 'string' ? v : JSON.stringify(v);
                    if (s && s.length > 5) out[k] = s.substring(0, 2000);
                } catch(e) {}
            });

            // Scan all window keys for anything key/token/secret-like
            Object.keys(window).forEach(k => {
                try {
                    const kl = k.toLowerCase();
                    if (kl.includes('key') || kl.includes('token') ||
                        kl.includes('secret') || kl.includes('stripe') ||
                        kl.includes('paypal') || kl.includes('api')) {
                        const v = window[k];
                        if (typeof v === 'string' && v.length > 8 && v.length < 300) {
                            out['win:'+k] = v;
                        }
                    }
                } catch(e) {}
            });

            // localStorage + sessionStorage
            try {
                const ls = {};
                for (let i=0; i<localStorage.length; i++) {
                    const k = localStorage.key(i);
                    const v = localStorage.getItem(k) || '';
                    if (v.length > 5 && v.length < 500) ls[k] = v;
                }
                if (Object.keys(ls).length) out['__localStorage__'] = JSON.stringify(ls);
            } catch(e) {}

            // Meta tags (publishable keys often here)
            const metaKeys = {};
            document.querySelectorAll('meta').forEach(m => {
                const n = m.name || m.getAttribute('property') || '';
                const c = m.content || '';
                if (c.length > 5 && (n.includes('key') || n.includes('token') ||
                    n.includes('stripe') || n.includes('paypal') || n.includes('id'))) {
                    metaKeys[n] = c;
                }
            });
            if (Object.keys(metaKeys).length) out['__meta__'] = JSON.stringify(metaKeys);

            // All iframe srcs (payment iframes)
            const iframes = [];
            document.querySelectorAll('iframe').forEach(f => {
                const src = f.src || f.getAttribute('src') || '';
                const name = f.name || '';
                if (src) iframes.push({src: src.substring(0,300), name});
            });
            if (iframes.length) out['__iframes__'] = JSON.stringify(iframes);

            return out;
        }"""

        html = ""
        try:
            html = page.content()
        except Exception:
            pass

        dom_result = None
        try:
            dom_result = page.evaluate(_DEEP_GLOBALS_JS)
        except Exception as e:
            logger.debug("Deep globals JS eval error: %s", e)

        # ── Step 4b: ShadowDOM pierce — Playwright pierce: selector (open roots) ──
        try:
            shadow_inputs = page.query_selector_all(
                "pierce/input[type=hidden], pierce/input[name*=csrf], "
                "pierce/input[name*=token], pierce/input[name*=nonce]"
            )
            shadow_findings = []
            for si in shadow_inputs:
                try:
                    name_attr  = si.get_attribute("name") or si.get_attribute("id") or "shadow-hidden"
                    value_attr = si.input_value() or ""
                    if len(value_attr) >= 8:
                        shadow_findings.append({"name": name_attr, "value": value_attr[:200], "tag": "SHADOW-INPUT"})
                except Exception:
                    pass
            if shadow_findings and dom_result is not None:
                dom_result["__shadow_tokens__"] = shadow_findings
            elif shadow_findings:
                dom_result = {"__shadow_tokens__": shadow_findings}
        except Exception as _se:
            logger.debug("ShadowDOM pierce scan error: %s", _se)

        # ── Step 5: Traverse all frames for payment data ──
        frame_data = []
        try:
            for frame in page.frames:
                if frame == page.main_frame:
                    continue
                frame_url = frame.url or ""
                if not frame_url or frame_url == "about:blank":
                    continue
                frame_data.append(frame_url)
                # Scan frame URL for keys
                try:
                    frame_html = frame.content()
                    if frame_html and len(frame_html) > 100:
                        network_log.append({
                            "url": f"[frame] {frame_url}",
                            "method": "FRAME",
                            "post_data": "",
                            "response_body": frame_html[:60000],
                        })
                except Exception:
                    pass
        except Exception:
            pass
        if frame_data and dom_result is not None:
            dom_result["__frames__"] = json.dumps(frame_data)

        # Wire WS frames into network_log as special entries
        for _wsf in _ws_frames:
            network_log.append({
                "url":           f"[ws] {_wsf['url']}",
                "method":        f"WS:{_wsf['dir'].upper()}",
                "post_data":     _wsf["payload"] if _wsf["dir"] == "send" else "",
                "response_body": _wsf["payload"] if _wsf["dir"] == "recv" else "",
                "content_type":  "application/websocket-frame",
            })
        if _ws_frames and dom_result is not None:
            dom_result["__ws_urls__"] = json.dumps(
                list(dict.fromkeys(f["url"] for f in _ws_frames))[:20]
            )

        browser.close()

    return {
        "error":       None,
        "html":        html,
        "network_log": network_log,
        "console_log": console_log,
        "dom_result":  dom_result,
        "page_url":    page_url_ref[0],
        "ws_frames":   _ws_frames,
    }


def _static_extract(url: str) -> dict:
    """Fallback: requests-based HTML + JS fetch (no browser)."""
    session = requests.Session()
    session.headers.update(_get_headers())
    px = proxy_manager.get_proxy()
    if px:
        session.proxies.update(px)
    try:
        resp = session.get(url, timeout=15, verify=False, allow_redirects=True)
        html = resp.text
        page_url = resp.url
    except Exception as e:
        return {"error": str(e), "html": "", "network_log": [], "page_url": url}

    from urllib.parse import urlparse as _up2
    fp = _up2(page_url)
    base = f"{fp.scheme}://{fp.netloc}"
    soup_s = BeautifulSoup(html, "html.parser")
    network_log = []
    for tag in soup_s.find_all("script", src=True):
        src = tag["src"]
        if src.startswith("//"): src = fp.scheme + ":" + src
        elif src.startswith("/"): src = base + src
        if src.startswith("http"):
            try:
                r2 = session.get(src, timeout=8, verify=False)
                if r2.status_code == 200:
                    network_log.append({"url": src, "method": "GET",
                                        "post_data": "", "response_body": r2.text[:80000]})
            except Exception:
                pass
    return {"error": None, "html": html, "network_log": network_log,
            "console_log": [], "page_url": page_url}


def _gather_all_text(data: dict) -> list:
    """Return list of (text, source_label) from html + all JS.
    Obfuscated JS response bodies are skipped to reduce false positives.
    """
    texts = []
    if data.get("html"):
        texts.append((data["html"], "HTML source"))
    for entry in data.get("network_log", []):
        if entry.get("response_body"):
            body = entry["response_body"]
            is_obf, obf_reason = _is_obfuscated(body)
            if is_obf:
                logger.debug("gather_all_text: skip obfuscated JS %s (%s)",
                             entry['url'][:70], obf_reason)
            else:
                texts.append((body, f"JS: {entry['url'][:70]}"))
        if entry.get("post_data"):
            texts.append((entry["post_data"], f"POST → {entry['url'][:60]}"))
    if data.get("console_log"):
        texts.append(("\n".join(data["console_log"]), "Console logs"))
    return texts


# ══════════════════════════════════════════════════════════════════════
# 🔴  REAL-TIME NETWORK STREAM INTERCEPTOR  (False-positive reducer)
#
#  ယခင် engine: JS/HTML static scan → key ပါရင် report တက်
#  ဒီ engine:   Live XHR/Fetch hook → actual request မှာ သုံးနေမှ HIGH
#
#  လုပ်ဆောင်ချက်:
#   1. JS-level fetch/XHR monkey-patch → request headers + bodies ဖမ်း
#   2. SSE (EventSource) stream frames ဖမ်း
#   3. WebSocket send frames ဖမ်း (existing ws hook နဲ့ merge)
#   4. Confidence scoring: static hit + live usage = CONFIRMED
#   5. _gather_all_text_v2 → live data ပါ merge ထည့်
# ══════════════════════════════════════════════════════════════════════

# JS hook — page ထဲ inject လုပ်ပြီး fetch/XHR/SSE တိုင်းကို intercept
_STREAM_INTERCEPT_JS = """
() => {
    window.__streamLog = window.__streamLog || [];
    const _log = (entry) => { window.__streamLog.push(entry); };

    // ── 1. fetch() hook ────────────────────────────────────────────
    const _origFetch = window.fetch;
    window.fetch = async function(...args) {
        const req = args[0];
        const opts = args[1] || {};
        const url  = (req instanceof Request) ? req.url : String(req);
        const method = opts.method || (req instanceof Request ? req.method : 'GET');
        const headers = {};
        try {
            const h = (req instanceof Request) ? req.headers : new Headers(opts.headers || {});
            h.forEach((v, k) => { headers[k.toLowerCase()] = v; });
        } catch(e) {}
        const bodySnip = typeof opts.body === 'string' ? opts.body.slice(0,500) :
                         (opts.body instanceof URLSearchParams ? opts.body.toString().slice(0,500) : '');
        _log({type:'fetch', url, method, headers, body: bodySnip, ts: Date.now()});

        const resp = await _origFetch.apply(this, args);
        try {
            const ct = resp.headers.get('content-type') || '';
            if (ct.includes('json') || ct.includes('text')) {
                const clone = resp.clone();
                clone.text().then(t => {
                    _log({type:'fetch_response', url, status: resp.status,
                          content_type: ct, body: t.slice(0,2000), ts: Date.now()});
                }).catch(()=>{});
            }
        } catch(e) {}
        return resp;
    };

    // ── 2. XMLHttpRequest hook ─────────────────────────────────────
    const _origXHR = window.XMLHttpRequest;
    function PatchedXHR() {
        const xhr = new _origXHR();
        const meta = {url:'', method:'GET', headers:{}};
        const _origOpen = xhr.open.bind(xhr);
        const _origSend = xhr.send.bind(xhr);
        const _origSetHdr = xhr.setRequestHeader.bind(xhr);
        xhr.open = function(m, u, ...rest) {
            meta.method = m; meta.url = u;
            return _origOpen(m, u, ...rest);
        };
        xhr.setRequestHeader = function(k, v) {
            meta.headers[k.toLowerCase()] = v;
            return _origSetHdr(k, v);
        };
        xhr.send = function(body) {
            _log({type:'xhr', url: meta.url, method: meta.method,
                  headers: meta.headers,
                  body: (typeof body === 'string' ? body.slice(0,500) : ''),
                  ts: Date.now()});
            xhr.addEventListener('load', function() {
                const ct = xhr.getResponseHeader('content-type') || '';
                if (ct.includes('json') || ct.includes('text')) {
                    _log({type:'xhr_response', url: meta.url, status: xhr.status,
                          content_type: ct, body: xhr.responseText.slice(0,2000),
                          ts: Date.now()});
                }
            });
            return _origSend(body);
        };
        return xhr;
    }
    PatchedXHR.prototype = _origXHR.prototype;
    window.XMLHttpRequest = PatchedXHR;

    // ── 3. EventSource (SSE) hook ──────────────────────────────────
    const _origES = window.EventSource;
    if (_origES) {
        window.EventSource = function(url, opts) {
            const es = new _origES(url, opts);
            _log({type:'sse_open', url, ts: Date.now()});
            es.addEventListener('message', function(e) {
                _log({type:'sse_message', url, data: String(e.data).slice(0,1000),
                      ts: Date.now()});
            });
            es.onerror = function() {
                _log({type:'sse_error', url, ts: Date.now()});
            };
            return es;
        };
        window.EventSource.prototype = _origES.prototype;
    }

    // ── 4. navigator.sendBeacon hook ──────────────────────────────
    const _origBeacon = navigator.sendBeacon.bind(navigator);
    navigator.sendBeacon = function(url, data) {
        _log({type:'beacon', url,
              body: (data ? String(data).slice(0,300) : ''),
              ts: Date.now()});
        return _origBeacon(url, data);
    };

    return {status: 'hooks_installed'};
}
"""

# Patterns to extract sensitive values FROM live request headers/bodies
_LIVE_HEADER_PATTERNS = [
    ("Authorization Bearer",  re.compile(r'(?i)^bearer\s+(.+)$')),
    ("Authorization Basic",   re.compile(r'(?i)^basic\s+([A-Za-z0-9+/=]+)$')),
    ("X-Api-Key header",      re.compile(r'.+')),          # full value if header name is x-api-key
    ("X-Auth-Token header",   re.compile(r'.+')),
    ("Stripe-Key header",     re.compile(r'.+')),
]

_LIVE_BODY_PATTERNS = [
    ("Live API key",      re.compile(r'(?i)(?:api[_\-]?key|apikey|access_token|client_secret)\s*[=:&]\s*([A-Za-z0-9_\-]{16,120})')),
    ("Live Bearer token", re.compile(r'(?i)bearer[= ]+([A-Za-z0-9_\-\.]{20,500})')),
    ("Live JWT",          re.compile(r'(eyJ[A-Za-z0-9_\-]+\.eyJ[A-Za-z0-9_\-]+\.[A-Za-z0-9_\-]*)')),
    ("Live AWS key",      re.compile(r'\b(AKIA[0-9A-Z]{16})\b')),
    ("Live Stripe key",   re.compile(r'\b((?:pk|sk|rk)_(?:live|test)_[A-Za-z0-9]{24,})\b')),
    ("Live OpenAI key",   re.compile(r'\b(sk-[A-Za-z0-9]{20,60})\b')),
]

