# New JS eval string — add IndexedDB scan
# ══════════════════════════════════════════════════════════════════
# 🔄  HIDDENKEYS IMPROVEMENT — Token Stability Analysis
#
#  Unique approach: Page ကို 2 ကြိမ် fetch ပြီး token တွေကို
#  နှိုင်းယှဉ်တယ် — Burp Suite CSRF scanner လုပ်တဲ့ approach
#
#  Results:
#   ROTATING  → token ပြောင်းနေ = good security practice
#   STATIC    → token မပြောင်း = potential CSRF weakness
#   ABSENT    → token မရှိ = unprotected form
# ══════════════════════════════════════════════════════════════════

# Token field names to track across fetches
_STABILITY_TOKEN_NAMES = [
    # CSRF tokens
    "_token", "csrf_token", "csrftoken", "_csrf", "xsrf_token",
    "authenticity_token", "__RequestVerificationToken",
    "csrfmiddlewaretoken", "_csrfToken", "csrf_hash",
    # Nonces
    "nonce", "csp-nonce", "wp-nonce",
    # Session/state tokens
    "state", "form_token", "form_key",
    # Framework-specific
    "__VIEWSTATE", "__EVENTVALIDATION",
]

_STABILITY_META_NAMES = [
    "csrf-token", "xsrf-token", "_token", "csrf_token",
    "x-csrf-token", "x-xsrf-token",
]


def _token_stability_check(url: str, progress_cb=None) -> dict:
    """
    Fetch the page twice with independent sessions and compare
    CSRF tokens, nonces, and hidden form values.

    Returns:
        {
          "rotating": [{"name":..., "val1":..., "val2":...}],
          "static":   [{"name":..., "value":...}],
          "absent":   [form_action_url, ...],
          "error":    str | None
        }
    """
    result = {"rotating": [], "static": [], "absent": [], "error": None}

    def _fetch_tokens(session) -> dict:
        """Return {token_name: value} from HTML of one fetch."""
        tokens = {}
        try:
            r = session.get(url, timeout=15, verify=False,
                            allow_redirects=True)
            r.raise_for_status()
            soup = BeautifulSoup(r.text, "html.parser")

            # ── Hidden inputs ────────────────────────────────────────────
            for inp in soup.find_all("input", {"type": "hidden"}):
                name = (inp.get("name") or "").lower().strip()
                val  = inp.get("value", "").strip()
                if name and len(val) >= 6:
                    # Only track known token field names + high-entropy values
                    is_known = any(t in name for t in _STABILITY_TOKEN_NAMES)
                    is_ent   = len(val) > 10 and _entropy(val) > 3.0
                    if is_known or is_ent:
                        tokens[f"input:{name}"] = val

            # ── Meta tags ────────────────────────────────────────────────
            for meta in soup.find_all("meta"):
                name = (meta.get("name") or meta.get("property") or "").lower()
                val  = (meta.get("content") or "").strip()
                if name and len(val) >= 8:
                    if any(t in name for t in _STABILITY_META_NAMES):
                        tokens[f"meta:{name}"] = val

            # ── Forms without any token (ABSENT detection) ────────────────
            for form in soup.find_all("form",
                                      attrs={"method": re.compile(r"post", re.I)}):
                action = form.get("action", url)[:80]
                has_tok = any(
                    any(t in (inp.get("name") or "").lower()
                        for t in _STABILITY_TOKEN_NAMES)
                    for inp in form.find_all("input", {"type": "hidden"})
                )
                if not has_tok:
                    result["absent"].append(action)

        except Exception as e:
            result["error"] = str(e)
        return tokens

    if progress_cb:
        progress_cb("🔄 Fetch #1 — capturing tokens...")

    sess1 = requests.Session()
    sess1.headers.update(_get_headers())
    tokens1 = _fetch_tokens(sess1)

    if result["error"]:
        return result

    if progress_cb:
        progress_cb("🔄 Fetch #2 — comparing token stability...")

    # Small delay to allow server-side token rotation
    import time as _time
    _time.sleep(1.5)

    sess2 = requests.Session()
    sess2.headers.update(_get_headers())
    tokens2 = _fetch_tokens(sess2)

    # ── Compare ──────────────────────────────────────────────────────────────
    all_names = set(tokens1) | set(tokens2)
    for name in sorted(all_names):
        v1 = tokens1.get(name)
        v2 = tokens2.get(name)
        if v1 is None or v2 is None:
            continue   # only present in one fetch — skip
        if v1 != v2:
            result["rotating"].append({
                "name":  name,
                "val1":  v1[:20] + "…" if len(v1) > 20 else v1,
                "val2":  v2[:20] + "…" if len(v2) > 20 else v2,
                "entropy_v1": round(_entropy(v1), 2),
            })
        else:
            result["static"].append({
                "name":    name,
                "value":   v1[:30] + "…" if len(v1) > 30 else v1,
                "entropy": round(_entropy(v1), 2),
            })

    # Dedup absent list
    result["absent"] = list(dict.fromkeys(result["absent"]))[:10]
    return result


def _format_stability_block(stab: dict) -> list:
    """Render token stability results as Telegram message lines."""
    if stab.get("error"):
        return [f"⚠️ Stability check error: `{escape_md(stab['error'][:60])}`"]

    lines = ["", "🔄 *Token Stability Analysis*", "━━━━━━━━━━━━━━━━━━━━"]

    rotating = stab.get("rotating", [])
    static   = stab.get("static",   [])
    absent   = stab.get("absent",   [])

    if rotating:
        lines.append(f"✅ *ROTATING* — `{len(rotating)}` token(s) change per request")
        for t in rotating[:5]:
            lines.append(f"  🟢 `{escape_md(t['name'])}` H=`{t['entropy_v1']}`")
            lines.append(f"     `{escape_md(t['val1'])}` → `{escape_md(t['val2'])}`")

    if static:
        lines.append(f"\n⚠️ *STATIC* — `{len(static)}` token(s) never rotate")
        for t in static[:5]:
            h = t["entropy"]
            risk = "🔴 low entropy" if h < 3.0 else ("🟡 medium entropy" if h < 4.0 else "🟠 high entropy but static")
            lines.append(f"  {risk} `{escape_md(t['name'])}` H=`{h}`")
            lines.append(f"     Value: `{escape_md(t['value'])}`")

    if absent:
        lines.append(f"\n🔴 *ABSENT* — `{len(absent)}` POST form(s) with no CSRF token")
        for a in absent[:4]:
            lines.append(f"  ⛔ `{escape_md(a[:70])}`")

    if not rotating and not static and not absent:
        lines.append("⚪ No token fields detected across 2 fetches")

    return lines


def _hiddenkeys_sync(url: str, progress_cb=None) -> dict:
    """
    2026 Enhanced hidden key scanner.

    Scans:
      1. Hidden form fields (all frameworks)
      2. CSRF / XSRF tokens (30+ frameworks)
      3. Meta tag tokens + CSP nonces
      4. localStorage + sessionStorage
      5. ★ IndexedDB key names (via Playwright)
      6. ★ Cookie security attributes
      7. ★ WebSocket handshake tokens
      8. ★ GraphQL CSRF / operation tokens
      9. ★ Request headers (X-CSRF, Authorization)
      10.★ SvelteKit / Astro / Remix framework tokens
      11.★ Shadow DOM slot scan
      12.★ Service worker registration keys
    """
    try:
        from playwright.sync_api import sync_playwright, TimeoutError as PWTimeout
    except ImportError:
        return {"error": "playwright_not_installed", "findings": [], "requests": 0}

    findings = []
    seen = set()
    request_count = [0]
    live_result = {"live_requests": [], "live_findings": [], "sse_frames": []}

    def _add(typ, val, src, name="", confidence="STATIC", extra=None):
        val = str(val).strip()
        key = typ + ":" + val[:80]
        if key not in seen and len(val) >= 6:
            # ── Phase 1: token quality check ──────────────
            is_valid, _ = _fp_validate_token(val, name)
            if not is_valid:
                return
            # ──────────────────────────────────────────────
            seen.add(key)
            findings.append({
                "type": typ,
                "value": val,
                "name": name,
                "source": src,
                "confidence": confidence,
                **(extra or {}),
            })

    # ── Framework-specific CSRF token names ──────────────────────────────────
    _CSRF_NAMES = [
        # Generic
        "_token", "csrf_token", "csrftoken", "csrf", "xsrf_token", "_csrf",
        "__RequestVerificationToken", "authenticity_token",
        # Laravel
        "laravel_token", "_laravel_token",
        # Django
        "csrfmiddlewaretoken",
        # Rails
        "authenticity_token",
        # ASP.NET
        "__RequestVerificationToken", "__VIEWSTATE", "__EVENTVALIDATION", "__VIEWSTATEGENERATOR",
        # Spring / Java
        "_csrf", "X-CSRF-TOKEN",
        # Symfony
        "_token",
        # CodeIgniter
        "csrf_token_name", "csrf_hash",
        # CakePHP
        "_csrfToken",
        # Yii
        "_csrf-frontend", "_csrf-backend",
        # Angular
        "XSRF-TOKEN",
        # Express (csurf)
        "_csrf",
        # Flask-WTF
        "csrf_token",
        # SvelteKit ★
        "x-sveltekit-action",
        # Remix ★
        "csrf",
        # tRPC
        "x-trpc-source",
        # Astro ★
        "astro-csrf",
        # Next.js
        "__Host-next-auth.csrf-token",
    ]

    # ── Meta token patterns ───────────────────────────────────────────────────
    _META_TOKEN_PATTERNS = [
        (re.compile(r'<meta[^>]+name=["\']csrf-?token["\'][^>]+content=["\']([^"\']{10,})["\']', re.I), "CSRF Meta"),
        (re.compile(r'<meta[^>]+name=["\']xsrf-?token["\'][^>]+content=["\']([^"\']{10,})["\']', re.I), "XSRF Meta"),
        (re.compile(r'<meta[^>]+name=["\']_token["\'][^>]+content=["\']([^"\']{10,})["\']', re.I), "Laravel Token"),
        # CSP nonce
        (re.compile(r"<script[^>]*nonce=['\"]([A-Za-z0-9+/=]{10,})['\"]", re.I), "CSP Nonce"),
        # ★ Next.js action state
        (re.compile(r'action=["\']([A-Za-z0-9+/=]{20,})["\'].*?next-action', re.I), "Next.js Action"),
        # ★ SvelteKit CSRF
        (re.compile(r'__sveltekit_(?:csrf|session)_?[a-z_]*\s*=\s*["\']([^"\']{10,})["\']', re.I), "SvelteKit Token"),
        # ★ Astro page data tokens
        (re.compile(r'<script type=["\']astro-data["\'][^>]*>([^<]{20,})<', re.I), "Astro Page Data"),
        # ★ Remix session data
        (re.compile(r'window\.__remix[A-Za-z]+\s*=\s*["\']([^"\']{20,})["\']', re.I), "Remix Token"),
        # WordPress nonce
        (re.compile(r'var\s+[a-z_]+\s*=\s*\{[^}]*nonce\s*:\s*["\']([a-f0-9]{10})["\']', re.I), "WordPress Nonce"),
    ]

    # ── JS token patterns ─────────────────────────────────────────────────────
    _JS_TOKEN_PATTERNS = [
        (re.compile(r'(?:csrf|xsrf|csrfToken|_token)\s*[=:]\s*["\']([A-Za-z0-9+/=_\-]{10,})["\']', re.I), "JS CSRF"),
        (re.compile(r'window\.__(?:csrf|CSRF|token)[A-Za-z_]*\s*=\s*["\']([^"\']{10,})["\']', re.I), "Window Global"),
        (re.compile(r'headers\s*:\s*\{[^}]*["\']X-CSRF-Token["\']\s*:\s*["\']([^"\']{10,})["\']', re.I), "X-CSRF Header"),
        (re.compile(r'headers\s*:\s*\{[^}]*["\']X-XSRF-TOKEN["\']\s*:\s*["\']([^"\']{10,})["\']', re.I), "X-XSRF Header"),
        # ★ Fetch / Axios request interceptors
        (re.compile(r"axios\.defaults\.headers\.common\[['\"](X-CSRF|Authorization)['\"]]\s*=\s*['\"]([^'\"]{10,})['\"]", re.I), "Axios Header"),
        # ★ tRPC / React Query headers
        (re.compile(r"['\"]x-trpc-source['\"]\s*:\s*['\"]([^'\"]{4,40})['\"]", re.I), "tRPC Source"),
    ]

    with sync_playwright() as pw:
        if progress_cb: progress_cb("🌐 Launching stealth browser (2026 fingerprint)...")

        # ── 2026 Chrome 124 user agent ────────────────────────────────────────
        UA = (
            "Mozilla/5.0 (Windows NT 10.0; Win64; x64) "
            "AppleWebKit/537.36 (KHTML, like Gecko) "
            "Chrome/124.0.0.0 Safari/537.36"
        )

        browser = pw.chromium.launch(
            headless=True,
            args=[
                '--no-sandbox',
                '--disable-dev-shm-usage',
                '--disable-blink-features=AutomationControlled',
                '--disable-web-security',
                '--disable-features=IsolateOrigins,site-per-process',
                '--enable-features=NetworkService,NetworkServiceInProcess',
                '--disable-site-isolation-trials',
                '--ignore-certificate-errors',
            ]
        )

        ctx = browser.new_context(
            user_agent=UA,
            viewport={"width": 1440, "height": 900},
            ignore_https_errors=True,
            java_script_enabled=True,
            extra_http_headers={
                "Accept-Language": "en-US,en;q=0.9",
                "Accept": "text/html,application/xhtml+xml,application/xml;q=0.9,image/avif,image/webp,*/*;q=0.8",
                "Sec-CH-UA": '"Chromium";v="124", "Google Chrome";v="124", "Not-A.Brand";v="99"',
                "Sec-CH-UA-Mobile": "?0",
                "Sec-CH-UA-Platform": '"Windows"',
                "Sec-Fetch-Dest": "document",
                "Sec-Fetch-Mode": "navigate",
                "Sec-Fetch-Site": "none",
                "Sec-Fetch-User": "?1",
                "Upgrade-Insecure-Requests": "1",
            }
        )

        # Anti-bot evasion
        ctx.add_init_script("""
            Object.defineProperty(navigator, 'webdriver', {get: () => undefined});
            Object.defineProperty(navigator, 'plugins', {get: () => [1,2,3,4,5]});
            Object.defineProperty(navigator, 'languages', {get: () => ['en-US','en']});
            Object.defineProperty(navigator, 'platform', {get: () => 'Win32'});
            Object.defineProperty(navigator, 'hardwareConcurrency', {get: () => 8});
            Object.defineProperty(navigator, 'deviceMemory', {get: () => 8});
            Object.defineProperty(screen, 'colorDepth', {get: () => 24});
            window.chrome = {runtime: {}, loadTimes: () => {}, csi: () => {}};
            window.Notification = {permission: 'default'};
        """)

        page = ctx.new_page()
        captured_headers = {}

        def _on_request(req):
            request_count[0] += 1
            h = req.headers
            # Capture CSRF headers from real requests
            for hname in ['x-csrf-token', 'x-xsrf-token', 'x-requested-with',
                          'x-csrftoken', 'csrf-token', 'authorization']:
                if hname in h:
                    _add(f"Request Header: {hname}", h[hname],
                         f"Live request → {req.url[:60]}", confidence="CONFIRMED-LIVE")
            live_result["live_requests"].append({
                "url": req.url[:200], "method": req.method,
                "headers": dict(h),
            })

        def _on_response(resp):
            # Capture tokens from Set-Cookie headers
            sc = resp.headers.get("set-cookie", "")
            if sc:
                for pat in [r'XSRF-TOKEN=([^;]{10,})', r'csrf[_-]?token=([^;]{10,})',
                            r'laravel_session=([^;]{10,})']:
                    m = re.search(pat, sc, re.I)
                    if m:
                        _add("Cookie Token", m.group(1),
                             f"Set-Cookie ← {resp.url[:60]}", confidence="CONFIRMED-LIVE")

        def _on_ws(ws):
            ws.on("framesent",   lambda p: live_result["sse_frames"].append({"dir":"sent",  "data":str(p)[:200]}))
            ws.on("framereceived", lambda p: _scan_ws_frame(str(p)))

        def _scan_ws_frame(frame: str):
            for pat in [r'"token"\s*:\s*"([^"]{10,})"',
                        r'"csrf"\s*:\s*"([^"]{10,})"',
                        r'"Authorization"\s*:\s*"([^"]{10,})"']:
                m = re.search(pat, frame, re.I)
                if m:
                    _add("WebSocket Token", m.group(1),
                         "WebSocket frame", confidence="CONFIRMED-LIVE")

        page.on("request",  _on_request)
        page.on("response", _on_response)
        page.on("websocket", _on_ws)

        if progress_cb: progress_cb("📡 Loading page (intercepting all traffic)...")

        try:
            page.goto(url, wait_until="load", timeout=35_000)
        except Exception as e:
            browser.close()
            return {"error": str(e), "findings": [], "requests": request_count[0]}

        try:
            page.wait_for_load_state("networkidle", timeout=12_000)
        except Exception:
            pass

        if progress_cb: progress_cb("🔍 Scanning DOM, shadow DOM, storage...")

        html = page.content()

        # ── 1. Hidden form inputs ──────────────────────────────────────────────
        try:
            hidden_inputs = page.evaluate("""() => {
                const results = [];
                // Regular hidden inputs
                document.querySelectorAll('input[type="hidden"], input[type="text"][readonly]').forEach(el => {
                    if (el.name && el.value && el.value.length >= 6) {
                        results.push({name: el.name, value: el.value, tag: 'input'});
                    }
                });
                // Shadow DOM deep scan ★
                function scanShadow(root) {
                    if (root.shadowRoot) {
                        root.shadowRoot.querySelectorAll('input[type="hidden"]').forEach(el => {
                            if (el.name && el.value && el.value.length >= 6) {
                                results.push({name: el.name, value: el.value, tag: 'shadow-input'});
                            }
                        });
                        root.shadowRoot.querySelectorAll('*').forEach(scanShadow);
                    }
                }
                document.querySelectorAll('*').forEach(scanShadow);
                return results;
            }""")
            for inp in (hidden_inputs or []):
                name = inp.get("name", "")
                val  = inp.get("value", "")
                tag  = inp.get("tag", "input")
                is_csrf = any(t in name.lower() for t in
                              ['token', 'csrf', 'xsrf', 'nonce', 'key', 'secret'])
                typ = "CSRF Token" if is_csrf else "Hidden Input"
                confidence = "CONFIRMED" if is_csrf else "STATIC"
                _add(typ, val, f"DOM hidden {tag}", name=name, confidence=confidence)
        except Exception:
            pass

        # ── 2. Meta tag scan (include shadow DOM) ─────────────────────────────
        for pat, label in _META_TOKEN_PATTERNS:
            for m in pat.finditer(html):
                _add(label, m.group(1), "HTML meta/head", confidence="STATIC")

        # ── 3. JS patterns in inline scripts ─────────────────────────────────
        for pat, label in _JS_TOKEN_PATTERNS:
            for m in pat.finditer(html):
                g = m.group(1) if m.lastindex == 1 else m.group(2)
                if g:
                    _add(label, g, "Inline JS", confidence="STATIC")

        # ── 4. localStorage + sessionStorage ─────────────────────────────────
        try:
            storage = page.evaluate("""() => {
                const result = {};
                const keywordRe = /token|csrf|xsrf|nonce|session|auth|key|secret/i;
                for (let s of [['localStorage', localStorage], ['sessionStorage', sessionStorage]]) {
                    for (let i = 0; i < s[1].length; i++) {
                        const k = s[1].key(i);
                        const v = s[1].getItem(k);
                        if (k && v && keywordRe.test(k + v) && v.length >= 6) {
                            result[s[0] + ':' + k] = v;
                        }
                    }
                }
                return result;
            }""")
            for k, v in (storage or {}).items():
                store, name = k.split(":", 1)
                _add(f"{store} Token", str(v)[:200], store, name=name, confidence="STATIC")
        except Exception:
            pass

        # ★ 5. IndexedDB key names ─────────────────────────────────────────────
        try:
            idb_keys = page.evaluate("""() => new Promise(resolve => {
                const results = [];
                const keywordRe = /token|csrf|session|auth|key|nonce/i;
                const dbs = indexedDB.databases
                    ? indexedDB.databases().then(list => {
                        if (!list || list.length === 0) { resolve(results); return; }
                        let pending = list.length;
                        list.forEach(info => {
                            try {
                                const req = indexedDB.open(info.name);
                                req.onsuccess = () => {
                                    const db = req.result;
                                    const stores = Array.from(db.objectStoreNames);
                                    stores.forEach(s => {
                                        if (keywordRe.test(s)) results.push({db: info.name, store: s});
                                        const tx = db.transaction(s, 'readonly');
                                        const os = tx.objectStore(s);
                                        const kr = os.getAllKeys();
                                        kr.onsuccess = () => {
                                            (kr.result || []).forEach(k => {
                                                if (keywordRe.test(String(k)))
                                                    results.push({db: info.name, store: s, key: String(k)});
                                            });
                                        };
                                    });
                                    db.close();
                                    if (--pending === 0) resolve(results);
                                };
                                req.onerror = () => { if (--pending === 0) resolve(results); };
                            } catch(e) { if (--pending === 0) resolve(results); }
                        });
                    }).catch(() => resolve(results))
                    : resolve(results);
            })""",  # timeout
            )
            for item in (idb_keys or []):
                val = f"{item.get('db','?')}/{item.get('store','?')}"
                if item.get('key'):
                    val += f"[{item['key']}]"
                _add("IndexedDB Key Reference", val, "IndexedDB", confidence="STATIC")
        except Exception:
            pass

        # ★ 6. Service Worker registration check ──────────────────────────────
        try:
            sw_info = page.evaluate("""async () => {
                if (!navigator.serviceWorker) return [];
                const regs = await navigator.serviceWorker.getRegistrations();
                return regs.map(r => ({scope: r.scope, url: r.active?.scriptURL}));
            }""")
            for sw in (sw_info or []):
                if sw.get("url"):
                    _add("Service Worker", sw["url"], "ServiceWorker API",
                         name=sw.get("scope", ""), confidence="STATIC")
        except Exception:
            pass

        # ★ 7. GraphQL CSRF / operation token detection ────────────────────────
        try:
            gql_tokens = page.evaluate("""() => {
                const results = [];
                // Apollo Client cache
                if (window.__APOLLO_STATE__) {
                    const keys = Object.keys(window.__APOLLO_STATE__);
                    keys.filter(k => /token|auth|csrf/i.test(k)).forEach(k => {
                        results.push({type: 'Apollo Cache Key', value: k});
                    });
                }
                // Relay store
                if (window.__RELAY_STORE__) {
                    results.push({type: 'Relay Store', value: JSON.stringify(window.__RELAY_STORE__).slice(0, 200)});
                }
                return results;
            }""")
            for item in (gql_tokens or []):
                _add(item.get("type", "GraphQL Token"), item.get("value", ""),
                     "GraphQL/Apollo", confidence="STATIC")
        except Exception:
            pass

        # ★ 8. Cookie attribute scan ───────────────────────────────────────────
        try:
            cookies = ctx.cookies()
            for cookie in cookies:
                name = cookie.get("name", "")
                val  = cookie.get("value", "")
                is_csrf = any(t in name.lower() for t in ['csrf', 'xsrf', 'token', 'sess'])
                if is_csrf and val and len(val) >= 6:
                    attrs = []
                    if not cookie.get("httpOnly"): attrs.append("⚠️ NOT HttpOnly")
                    if not cookie.get("secure"):   attrs.append("⚠️ NOT Secure")
                    if cookie.get("sameSite", "").lower() == "none": attrs.append("⚠️ SameSite=None")
                    _add("Cookie Token", val[:200], "Cookie jar",
                         name=name,
                         confidence="CONFIRMED",
                         extra={"security_flags": ", ".join(attrs) if attrs else "OK"})
        except Exception:
            pass

        # ── ENH10: data-* attribute scan ──────────────────────────────────────
        try:
            data_attrs = page.evaluate("""() => {
                const results = [];
                const attrNames = [
                    'data-token','data-auth','data-user','data-session',
                    'data-key','data-nonce','data-csrf','data-xsrf',
                    'data-api-key','data-access-token','data-bearer',
                    'data-user-id','data-account','data-identity',
                ];
                document.querySelectorAll('*').forEach(el => {
                    attrNames.forEach(attr => {
                        const v = el.getAttribute(attr);
                        if (v && v.length >= 6) {
                            results.push({
                                name: attr, value: v,
                                tag: el.tagName, id: el.id || ''
                            });
                        }
                    });
                });
                return results;
            }""")
            for item in (data_attrs or []):
                _add(f"DOM data-* Token ({item.get('name','')})",
                     item.get("value",""),
                     f"DOM: <{item.get('tag','?')}> #{item.get('id','')}",
                     name=item.get("name",""),
                     confidence="STATIC")
        except Exception:
            pass

        # ── ENH11: __INITIAL_STATE__ / Redux / Vuex hydration mining ──────────
        try:
            state_tokens = page.evaluate("""() => {
                const results = [];
                const stateKeys = [
                    '__INITIAL_STATE__', '__REDUX_STATE__', '__PRELOADED_STATE__',
                    '__NEXT_DATA__', '__NUXT__', '__APP_STATE__', '__STORE__',
                    '__INITIAL_PROPS__', '__RELAY_STORE__',
                ];
                const tokenKeys = /token|auth|csrf|session|key|nonce|secret|jwt|bearer/i;
                stateKeys.forEach(sk => {
                    try {
                        const obj = window[sk];
                        if (!obj) return;
                        function walk(o, path, depth) {
                            if (depth > 7 || !o) return;
                            if (typeof o === 'object') {
                                Object.keys(o).forEach(k => {
                                    const v = o[k];
                                    const fullPath = path + '.' + k;
                                    if (typeof v === 'string' && v.length >= 8 && tokenKeys.test(k)) {
                                        results.push({source: sk + fullPath, value: v.substring(0,200), name: k});
                                    }
                                    walk(v, fullPath, depth + 1);
                                });
                            }
                        }
                        try { walk(typeof obj === 'string' ? JSON.parse(obj) : obj, '', 0); }
                        catch(e) {}
                    } catch(e) {}
                });
                return results;
            }""")
            for item in (state_tokens or []):
                _add("Framework State Token",
                     item.get("value",""),
                     item.get("source","window state"),
                     name=item.get("name",""),
                     confidence="STATIC")
        except Exception:
            pass

        # ── ENH12: Cookie entropy ranking ─────────────────────────────────────
        try:
            from math import log2 as _log2
            all_cookies_ent = ctx.cookies()
            def _entropy(s):
                if not s: return 0.0
                freq = {}
                for c in s:
                    freq[c] = freq.get(c, 0) + 1
                return -sum((v/len(s)) * _log2(v/len(s)) for v in freq.values())

            entropy_cookies = []
            for cookie in all_cookies_ent:
                val = cookie.get("value","")
                if len(val) >= 12:
                    h = _entropy(val)
                    if h >= 3.5:
                        entropy_cookies.append((h, cookie))
            entropy_cookies.sort(key=lambda x: -x[0])

            for h, cookie in entropy_cookies[:10]:
                cname = cookie.get("name","")
                cval  = cookie.get("value","")
                flags = []
                if not cookie.get("httpOnly"): flags.append("⚠️ NOT HttpOnly")
                if not cookie.get("secure"):   flags.append("⚠️ NOT Secure")
                ss = cookie.get("sameSite","").lower()
                if ss == "none":  flags.append("⚠️ SameSite=None")
                elif not ss:      flags.append("⚠️ SameSite=?")
                is_csrf = any(t in cname.lower() for t in ['csrf','xsrf','token','sess','auth'])
                _add(f"High-entropy Cookie (H={h:.2f})",
                     cval[:200],
                     "Cookie entropy scan",
                     name=cname,
                     confidence="CONFIRMED" if is_csrf else "STATIC",
                     extra={"security_flags": ", ".join(flags) if flags else "OK",
                            "entropy": round(h, 3)})
        except Exception:
            pass

        # ── ENH13: JWT inline decoder ──────────────────────────────────────────
        try:
            import base64 as _b64, json as _jd
            _JWT_RE = re.compile(
                r'\b(eyJ[A-Za-z0-9_\-]{10,}\.[A-Za-z0-9_\-]{10,}\.[A-Za-z0-9_\-]{10,})\b'
            )
            def _decode_jwt_hidden(token):
                try:
                    parts = token.split(".")
                    if len(parts) != 3: return None
                    pad = lambda s: s + "=" * (-len(s) % 4)
                    header  = _jd.loads(_b64.urlsafe_b64decode(pad(parts[0])))
                    payload = _jd.loads(_b64.urlsafe_b64decode(pad(parts[1])))
                    return {"alg": header.get("alg","?"), "typ": header.get("typ","JWT"),
                            "sub": str(payload.get("sub",""))[:80],
                            "iss": str(payload.get("iss",""))[:80],
                            "exp": payload.get("exp",""),
                            "claims": list(payload.keys())[:12]}
                except Exception:
                    return None

            seen_jwt = set()
            jwt_sources = (
                [(f.get("value",""), f.get("source","")) for f in findings]
                + [(c.get("value",""), f"Cookie:{c.get('name','')}") for c in ctx.cookies()]
            )
            for val, src in jwt_sources:
                for m in _JWT_RE.finditer(str(val)):
                    tok = m.group(1)
                    if tok in seen_jwt: continue
                    seen_jwt.add(tok)
                    decoded = _decode_jwt_hidden(tok)
                    if decoded:
                        summary = (f"alg={decoded['alg']} sub={decoded['sub'][:24]} "
                                   f"iss={decoded['iss'][:24]} "
                                   f"claims=[{','.join(decoded['claims'][:6])}]")
                        _add("JWT Token 🔑",
                             tok[:300],
                             f"JWT from: {src[:60]}",
                             name=summary,
                             confidence="CONFIRMED",
                             extra={"jwt_decoded": decoded})
        except Exception:
            pass

        browser.close()

    # ── ENH: Deep JSON / Response Header scan on captured network log ─────────
    # _hiddenkeys_sync uses Playwright directly; network log stored in live_result
    _hk_net = live_result.get("live_requests", [])
    # Build minimal network_log format from live_requests for ENH helpers
    _hk_net_log = [
        {"url": r.get("url",""), "response_body": r.get("body",""),
         "response_headers": r.get("headers",{}), "post_data": r.get("post_data","")}
        for r in _hk_net
    ]
    _hk_seen: set = {f["type"] + ":" + f["value"][:80] for f in findings}
    _CSRF_PATTERNS = _JS_TOKEN_PATTERNS + _META_TOKEN_PATTERNS
    for ef in _response_header_cookie_scan(_hk_net_log, [], _hk_seen):
        _add(ef["type"], ef["value"], ef["source"])
    for ef in _jwt_payload_scan(
        [(r.get("body",""), f"Live req: {r.get('url','')[:60]}") for r in _hk_net],
        [], _hk_seen
    ):
        _add(ef["type"], ef["value"], ef["source"])
    for ef in _websocket_deep_scan(live_result, [], _hk_seen):
        _add(ef["type"], ef["value"], ef["source"])
    for ef in _deep_json_response_scan(_hk_net_log, [], _hk_seen):
        _add(ef["type"], ef["value"], ef["source"])

    return {
        "findings": findings,
        "requests": request_count[0],
        "live_result": live_result,
        "error": None,
    }


