_FP_PLACEHOLDER_EXACT = {
    "your-api-key", "your_api_key", "your-secret-key", "your_secret_key",
    "your-secret", "your_secret", "changeme", "replace_me", "insert_here",
    "example", "placeholder", "dummy", "fake", "mock", "sample", "test",
    "demo", "xxxx", "xxxxxxxx", "1234567890", "abcdefghijklmnop",
    "sk-xxxx", "sk_live_xxxx", "pk_live_xxxx",
    "akia0000000000000000",
    "aizasyxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxx",
    "ghp_xxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxx",
    "xoxb-xxxx", "sg.xxxx", "hf_xxxx",
    "none", "null", "undefined", "n/a", "na", "test123", "password",
    "secret", "mysecret", "topsecret", "supersecret",
}

_FP_PLACEHOLDER_RE = [
    re.compile(r'^(.)\1{7,}$'),                               # same char ×8+
    re.compile(r'^[xX0\-_]{8,}$'),                            # x/0/dash only
    re.compile(r'(?i)(example|placeholder|your[_\-]?key|your[_\-]?secret'
               r'|insert|replace|changeme|xxxx|dummy|fake|sample'
               r'|test[_\-]?key|demo[_\-]?key|fake[_\-]?key)'),
    re.compile(r'^[a-z]{1,6}[0-9]{1,6}$'),                   # simple word+num
    re.compile(r'^(abc|123|test|demo|fake|null|none|pass)\w{0,10}$', re.I),
]

# Per-type minimum entropy — tuned per key format
_FP_ENTROPY_MIN = {
    "AWS Access Key":    3.2,  # AKIA+16 alphanum — naturally structured
    "AWS Secret":        4.5,
    "Stripe Secret":     4.8,
    "Stripe Public":     4.5,
    "Google API Key":    3.8,
    "Firebase Config":   3.8,
    "GitHub Token":      4.5,
    "GitLab Token":      4.3,
    "Slack Token":       4.0,
    "OpenAI Key":        4.8,
    "Sendgrid Key":      4.5,
    "Twilio Key":        3.8,
    "HuggingFace Token": 3.8,
    "Telegram Token":    3.2,
    "Generic Password":  3.0,
    "Bearer Token":      3.2,
    "Basic Auth Header": 3.5,
    "MongoDB URI":       2.5,  # URIs have structure, lower bar
    "MySQL DSN":         2.5,
    "Private Key Block": 0.0,  # always real
    "JWT Token":         4.0,
    "_default":          3.2,
}

# Minimum realistic lengths per type
_FP_MIN_LEN = {
    "AWS Access Key":   20,
    "AWS Secret":       30,
    "Stripe Secret":    30,
    "OpenAI Key":       40,
    "Sendgrid Key":     50,
    "GitHub Token":     36,
    "GitLab Token":     20,
    "Google API Key":   35,
    "_default":         8,
}


def _fp_is_placeholder(value: str, key_type: str = "") -> tuple:
    """
    Phase 1 FP filter — returns (is_fp: bool, reason: str).
    True  = likely false positive → skip.
    False = looks real → keep.
    """
    v = value.strip()

    # Exact known-bad match
    if v.lower() in _FP_PLACEHOLDER_EXACT:
        return True, "known placeholder"

    # Regex placeholder patterns
    for pat in _FP_PLACEHOLDER_RE:
        if pat.search(v):
            return True, f"placeholder pattern ({pat.pattern[:35]})"

    # Entropy check (requires entropy function — defined below)
    try:
        ent     = _entropy(v)
        min_ent = _FP_ENTROPY_MIN.get(key_type, _FP_ENTROPY_MIN["_default"])
        if len(v) >= 12 and ent < min_ent:
            return True, f"low entropy {ent:.2f} (min {min_ent})"
    except Exception:
        pass

    # Minimum length check
    min_len = _FP_MIN_LEN.get(key_type, _FP_MIN_LEN["_default"])
    if len(v) < min_len:
        return True, f"too short ({len(v)} < {min_len})"

    return False, ""


def _fp_validate_token(value: str, name: str = "") -> tuple:
    """
    /hiddenkeys context-aware token quality check.
    Returns (is_valid: bool, reason: str).
    """
    v = value.strip()
    if len(v) < 8:
        return False, "too short"
    if v.lower() in _FP_PLACEHOLDER_EXACT:
        return False, "placeholder value"
    for pat in _FP_PLACEHOLDER_RE:
        if pat.search(v):
            return False, "placeholder pattern"
    try:
        ent = _entropy(v)
        if ent < 2.8:
            return False, f"low entropy {ent:.2f}"
    except Exception:
        pass
    return True, "ok"


# ═══════════════════════════════════════════════════════════════
# 🛡️  OBFUSCATION DETECTOR — False Positive Reducer
#   Obfuscated JS ကို static regex scan မလုပ်ဘဲ skip မယ်
#   Playwright DOM eval က runtime values ကိုသာ ဖမ်းမယ်
# ═══════════════════════════════════════════════════════════════

def _is_obfuscated(js_text: str) -> tuple:
    """
    Detect obfuscated / heavily packed JS.
    Returns (is_obfuscated: bool, reason: str).

    Scoring (threshold = 4):
      +3  _0x hex variable names  (obfuscator.io style)
      +3  eval(function(p,a,c,k   (JScrambler / packer style)
      +3  string array + rotation  (common obfuscator pattern)
      +2  avg token length > 15   (long hex strings everywhere)
      +2  semicolon density > 5%  (minifier artifact)
      +1  very low whitespace     (< 2% of text)
    """
    if not js_text or len(js_text) < 200:
        return False, ""

    score = 0
    reasons = []
    sample = js_text[:120_000]   # first 120KB သာ စစ် (speed)

    # ── _0x hex var names (obfuscator.io) ──────────────────────
    _0x_count = len(re.findall(r'\b_0x[0-9a-f]{3,6}\b', sample))
    if _0x_count >= 5:
        score += 3
        reasons.append(f"_0x vars={_0x_count}")

    # ── eval(function(p,a,c,k,e,d) packer ──────────────────────
    if re.search(r'eval\s*\(\s*function\s*\(\s*p\s*,\s*a\s*,\s*c\s*,\s*k', sample):
        score += 3
        reasons.append("eval packer")

    # ── String array + rotation pattern ────────────────────────
    # e.g. var _0xabc=['str1','str2',...]; _0xabc[0x1];
    if re.search(r"var\s+_0x[0-9a-f]+\s*=\s*\[(?:'[^']*'|\"[^\"]*\"|,\s*){5,}\]", sample):
        score += 3
        reasons.append("string array")

    # ── Average token length (hex-packed code is dense) ────────
    tokens = re.findall(r'[A-Za-z0-9_$]+', sample)
    if tokens:
        avg_len = sum(len(t) for t in tokens) / len(tokens)
        if avg_len > 15:
            score += 2
            reasons.append(f"avg_token={avg_len:.1f}")

    # ── Semicolon density ───────────────────────────────────────
    if len(sample) > 0:
        sc_ratio = sample.count(';') / len(sample)
        if sc_ratio > 0.05:
            score += 2
            reasons.append(f"sc_density={sc_ratio:.3f}")

    # ── Whitespace poverty ──────────────────────────────────────
    ws_ratio = sum(1 for c in sample if c in ' \n\t\r') / max(len(sample), 1)
    if ws_ratio < 0.02:
        score += 1
        reasons.append(f"ws={ws_ratio:.3f}")

    is_obf = score >= 4
    return is_obf, (f"score={score} [{', '.join(reasons)}]" if is_obf else "")


# ═══════════════════════════════════════════════════════════════

def _entropy(s: str) -> float:
    """Calculate Shannon entropy of a string."""
    import math
    if not s:
        return 0.0
    freq = {}
    for c in s:
        freq[c] = freq.get(c, 0) + 1
    length = len(s)
    return -sum((count / length) * math.log2(count / length) for count in freq.values())

# ─── High-entropy string finder ───────────────────────────────
def _find_high_entropy(text: str, threshold: float = 4.2) -> list:
    """
    ENH K1: Context-aware entropy scan — filters false positives.
    - Skip strings adjacent to CSS/asset keywords (className, url, src, hash)
    - Skip known-safe patterns (hex color codes, version strings, UUIDs used as IDs)
    - Apply higher threshold (4.5) for short strings (20-32 chars) to cut noise
    - Tag each result with context snippet for review
    """
    _FP_CONTEXT = re.compile(
        r'(?i)(?:className|class_name|classname|font|color|background|'
        r'url\s*\(|src\s*=|href\s*=|import\s+|require\s*\(|'
        r'version|hash|checksum|integrity|nonce|csrf|_token\b)',
        re.I
    )
    _FP_VALUE = re.compile(
        r'^(?:[0-9a-f]{6}|[0-9a-f]{8}|[0-9a-f]{3})$',  # CSS hex colors
        re.I
    )
    _SECRET_CONTEXT = re.compile(
        r'(?i)(?:key|secret|token|api|auth|pass|cred|private|access|'
        r'bearer|client_secret|webhook|signing)',
        re.I
    )

    candidates = []
    # Scan quoted strings
    for m in re.finditer(r'["\']([A-Za-z0-9+/=_\-]{20,120})["\']', text):
        s = m.group(1)
        if _FP_VALUE.match(s):
            continue
        # Extract surrounding context (±80 chars)
        ctx_start = max(0, m.start() - 80)
        ctx_end   = min(len(text), m.end() + 80)
        ctx       = text[ctx_start:ctx_end]
        # Skip if adjacent to CSS/asset keywords
        if _FP_CONTEXT.search(ctx):
            continue
        ent = _entropy(s)
        # Higher threshold for shorter strings unless secret context found
        min_ent = threshold if _SECRET_CONTEXT.search(ctx) else (4.6 if len(s) < 40 else threshold)
        if ent >= min_ent:
            candidates.append({
                "value":   s,
                "entropy": round(ent, 2),
                "type":    "quoted_string",
                "context": ctx.strip()[:80],
            })
    # hex-32 (API keys, tokens — but not MD5 of static assets)
    for m in re.finditer(r'\b([0-9a-f]{32})\b', text, re.I):
        s = m.group(1)
        ctx_start = max(0, m.start() - 60)
        ctx       = text[ctx_start: m.end() + 60]
        if _FP_CONTEXT.search(ctx):
            continue
        ent = _entropy(s)
        if ent >= 3.8:   # hex-32 is bounded — lower bar with context guard
            candidates.append({
                "value":   s,
                "entropy": round(ent, 2),
                "type":    "hex32",
                "context": ctx.strip()[:80],
            })
    # hex-64 (SHA-256 secrets, long tokens)
    for m in re.finditer(r'\b([0-9a-f]{64})\b', text, re.I):
        s = m.group(1)
        ctx_start = max(0, m.start() - 60)
        ctx       = text[ctx_start: m.end() + 60]
        if _FP_CONTEXT.search(ctx):
            continue
        ent = _entropy(s)
        if ent >= threshold:
            candidates.append({
                "value":   s,
                "entropy": round(ent, 2),
                "type":    "hex64",
                "context": ctx.strip()[:80],
            })
    # Deduplicate and return top 30
    seen = set()
    out  = []
    for c in candidates:
        if c["value"] not in seen:
            seen.add(c["value"])
            out.append(c)
    return sorted(out, key=lambda x: -x["entropy"])[:30]

# ─── Source map fetcher ───────────────────────────────────────
def _fetch_source_maps(js_sources: list, base_url: str) -> list:
    """
    Try to fetch .js.map files for each JS bundle.
    Returns list of (js_url, map_content_text).
    """
    found = []
    for js_url, _ in js_sources[:8]:
        map_url = js_url + ".map"
        try:
            r = requests.get(map_url, timeout=8, verify=False,
                             headers=_get_headers(),
                             proxies=proxy_manager.get_proxy())
            if r.status_code == 200 and "sourcesContent" in r.text:
                found.append((js_url, r.text[:200_000]))
        except Exception:
            pass
    return found

# ─── Playwright-based dynamic scan (network request capture) ──

def _run_playwright_dynamic_keydump(url: str) -> dict:
    """Dynamic keydump via Playwright (Python native)."""
    return _run_playwright_keydump(url)



def _run_playwright_keydump(url: str) -> dict:
    """
    v19 Upgraded keydump dynamic engine:
    - Auth headers from ALL requests + response body token scan
    - localStorage/sessionStorage full dump
    - window globals: auth tokens, API keys, firebase config
    - Source map URL discovery
    - Cookie full capture with domain info
    """
    try:
        from playwright.sync_api import sync_playwright, TimeoutError as PWTimeout
    except ImportError:
        return {"requests": [], "storage": {}, "cookies": [], "_engine": "none"}

    findings = {
        "requests":        [],
        "storage":         {},
        "cookies":         [],
        "window_globals":  {},
        "response_bodies": [],
        "_engine":         "playwright_v19",
    }

    _HDR_INTERESTING = {
        "authorization", "x-api-key", "x-auth-token", "x-access-token",
        "x-client-id", "x-client-secret", "x-app-key", "api-key",
        "x-amz-security-token", "x-firebase-auth", "x-csrf-token",
        "x-session-token", "x-user-token",
    }

    def _filter_headers(hdrs: dict) -> dict:
        out = {}
        for k, v in hdrs.items():
            kl = k.lower()
            if kl in _HDR_INTERESTING or any(
                kw in kl for kw in ("token","key","secret","auth","bearer","session","credential")
            ):
                out[k] = v[:200]
        return out

    try:
        with sync_playwright() as pw:
            browser = pw.chromium.launch(
                headless=True,
                args=[
                    "--no-sandbox", "--disable-dev-shm-usage", "--disable-gpu",
                    "--disable-blink-features=AutomationControlled",
                    "--disable-web-security",
                    "--disable-features=IsolateOrigins,site-per-process",
                ]
            )
            ctx = browser.new_context(
                user_agent=(
                    "Mozilla/5.0 (Windows NT 10.0; Win64; x64) "
                    "AppleWebKit/537.36 (KHTML, like Gecko) "
                    "Chrome/122.0.0.0 Safari/537.36"
                ),
                viewport={"width": 1440, "height": 900},
                ignore_https_errors=True,
            )
            ctx.add_init_script(
                "Object.defineProperty(navigator,'webdriver',{get:()=>undefined});"
                "Object.defineProperty(navigator,'plugins',{get:()=>[1,2,3,4,5]});"
                "window.chrome={runtime:{},loadTimes:function(){},csi:function(){}};"
            )
            page = ctx.new_page()

            def _on_request(req):
                hdrs = _filter_headers(req.headers)
                entry = {"url": req.url[:200], "method": req.method}
                if hdrs:
                    entry["headers"] = hdrs
                try:
                    pd = req.post_data
                    if pd and len(pd) > 3:
                        entry["post_data"] = pd[:500]
                except Exception:
                    pass
                if hdrs or entry.get("post_data"):
                    findings["requests"].append(entry)

            def _on_response(resp):
                ct = resp.headers.get("content-type", "").lower()
                if not any(x in ct for x in ("json", "javascript", "text/plain", "text/html")):
                    return
                if resp.status != 200:
                    return
                try:
                    body = resp.body().decode("utf-8", errors="ignore")
                    if not body or len(body) < 10:
                        return
                    # ── v18: Match _KD_PATTERNS against response body ──────────
                    kd_hits = {}
                    for label, (pat, cat_icon) in _KD_PATTERNS.items():
                        try:
                            raw = re.findall(pat, body, re.IGNORECASE)
                        except Exception:
                            continue
                        flat = []
                        for m in raw:
                            if isinstance(m, tuple):
                                flat.extend([x.strip() for x in m if x and len(x) > 4])
                            else:
                                if m and len(m) > 4:
                                    flat.append(m.strip())
                        if flat:
                            kd_hits[label] = list(dict.fromkeys(flat))[:4]
                    if kd_hits:
                        if "response_hits" not in findings:
                            findings["response_hits"] = {}
                        findings["response_hits"][resp.url[:120]] = kd_hits
                    # ── Original keyword check for full body storage ───────────
                    if any(kw in body for kw in (
                        "token", "api_key", "apikey", "secret", "bearer",
                        "pk_live", "sk_live", "pk_test", "sk_test",
                        "authorization", "credential", "firebase"
                    )):
                        findings["response_bodies"].append({
                            "url":  resp.url[:150],
                            "body": body[:3000],
                        })
                except Exception:
                    pass

            page.on("request",  _on_request)
            page.on("response", _on_response)

            try:
                page.goto(url, wait_until="load", timeout=30_000)
            except PWTimeout:
                pass
            except Exception:
                pass

            try:
                page.wait_for_load_state("networkidle", timeout=10_000)
            except Exception:
                pass

            # Scroll to trigger lazy-loaded auth requests
            try:
                page.evaluate("window.scrollTo(0, document.body.scrollHeight / 2)")
                page.wait_for_timeout(1200)
                page.evaluate("window.scrollTo(0, document.body.scrollHeight)")
                page.wait_for_timeout(1200)
            except Exception:
                pass

            # ── localStorage + sessionStorage ──
            try:
                storage = page.evaluate("""() => {
                    const ls = {}, ss = {};
                    for(let i=0;i<localStorage.length;i++){
                        const k=localStorage.key(i);
                        const v=localStorage.getItem(k)||'';
                        if(v.length < 2000) ls[k]=v;
                    }
                    for(let i=0;i<sessionStorage.length;i++){
                        const k=sessionStorage.key(i);
                        const v=sessionStorage.getItem(k)||'';
                        if(v.length < 2000) ss[k]=v;
                    }
                    return {localStorage: ls, sessionStorage: ss};
                }""")
                findings["storage"] = storage
            except Exception:
                pass

            # ── window globals deep scan ──
            try:
                wg = page.evaluate("""() => {
                    const out = {};
                    const authKeys = [
                        'token','apiKey','api_key','authToken','accessToken',
                        'access_token','userToken','sessionToken','jwtToken',
                        'bearerToken','credential','firebaseConfig',
                        '__FIREBASE_CONFIG__','__AUTH_TOKEN__','currentUser',
                    ];
                    authKeys.forEach(k => {
                        try {
                            const v = window[k];
                            if (v !== undefined && v !== null) {
                                out[k] = typeof v === 'string'
                                    ? v.substring(0,300)
                                    : JSON.stringify(v).substring(0,500);
                            }
                        } catch(e) {}
                    });
                    Object.keys(window).forEach(k => {
                        try {
                            const kl = k.toLowerCase();
                            if ((kl.includes('token') || kl.includes('auth') ||
                                 kl.includes('session') || kl.includes('credential') ||
                                 kl.includes('firebase') || kl.includes('jwt')) && !out[k]) {
                                const v = window[k];
                                if (typeof v === 'string' && v.length > 10 && v.length < 500)
                                    out[k] = v;
                            }
                        } catch(e) {}
                    });
                    return out;
                }""")
                findings["window_globals"] = wg or {}
            except Exception:
                pass

            # ── ENH7: Web Worker bundle scan ──────────────────────────────────
            try:
                workers = page.workers()
                for worker in workers:
                    try:
                        worker_url = worker.url
                        if not worker_url or not worker_url.startswith("http"):
                            continue
                        import urllib.request as _ur
                        req = _ur.Request(worker_url, headers={"User-Agent": "Mozilla/5.0"})
                        with _ur.urlopen(req, timeout=6) as resp:
                            worker_body = resp.read().decode("utf-8", errors="ignore")
                        if len(worker_body) > 50:
                            kd_hits = {}
                            for label, (pat, cat_icon) in _KD_PATTERNS.items():
                                try:
                                    raw = re.findall(pat, worker_body, re.IGNORECASE)
                                except Exception:
                                    continue
                                flat = []
                                for m in raw:
                                    if isinstance(m, tuple):
                                        flat.extend([x.strip() for x in m if x and len(x) > 4])
                                    elif m and len(m) > 4:
                                        flat.append(m.strip())
                                if flat:
                                    kd_hits[f"{label} (worker)"] = list(dict.fromkeys(flat))[:4]
                            if kd_hits:
                                findings.setdefault("worker_hits", {})[worker_url[:120]] = kd_hits
                    except Exception:
                        pass
            except Exception:
                pass

            # ── ENH8: IndexedDB full key-value dump ───────────────────────────
            try:
                idb_data = page.evaluate("""async () => {
                    const result = {};
                    try {
                        const dbs = await indexedDB.databases();
                        for (const dbInfo of dbs) {
                            if (!dbInfo.name) continue;
                            const entries = await new Promise((resolve, reject) => {
                                const req = indexedDB.open(dbInfo.name, dbInfo.version);
                                req.onsuccess = function() {
                                    const db = req.result;
                                    const names = Array.from(db.objectStoreNames);
                                    const storeData = {};
                                    let pending = names.length;
                                    if (!pending) { resolve(storeData); return; }
                                    names.forEach(storeName => {
                                        try {
                                            const tx = db.transaction(storeName, 'readonly');
                                            const store = tx.objectStore(storeName);
                                            const all = store.getAll();
                                            all.onsuccess = function() {
                                                storeData[storeName] = JSON.stringify(
                                                    all.result || []
                                                ).substring(0, 2000);
                                                if (--pending === 0) resolve(storeData);
                                            };
                                            all.onerror = function() {
                                                if (--pending === 0) resolve(storeData);
                                            };
                                        } catch(e) {
                                            if (--pending === 0) resolve(storeData);
                                        }
                                    });
                                };
                                req.onerror = () => reject(req.error);
                                setTimeout(() => resolve({}), 3000);
                            });
                            result[dbInfo.name] = entries;
                        }
                    } catch(e) {
                        result.__error__ = String(e);
                    }
                    return result;
                }""")
                if idb_data and not idb_data.get("__error__"):
                    findings["indexeddb"] = idb_data
                    # Scan IDB values for secrets
                    for db_name, stores in idb_data.items():
                        if isinstance(stores, dict):
                            for store_name, values_str in stores.items():
                                if not values_str:
                                    continue
                                kd_hits = {}
                                for label, (pat, cat_icon) in _KD_PATTERNS.items():
                                    try:
                                        raw = re.findall(pat, values_str, re.IGNORECASE)
                                    except Exception:
                                        continue
                                    flat = [x.strip() if not isinstance(x, tuple) else
                                            next((g.strip() for g in x if g), "") for x in raw]
                                    flat = [v for v in flat if len(v) > 4]
                                    if flat:
                                        kd_hits[f"{label} (idb:{db_name}/{store_name})"] = flat[:4]
                                if kd_hits:
                                    findings.setdefault("idb_hits", {}).update(kd_hits)
            except Exception:
                pass

            # ── Cookies with domain info ──
            try:
                findings["cookies"] = [
                    {"name": c["name"], "value": c["value"][:200], "domain": c.get("domain","")}
                    for c in ctx.cookies()
                ]
            except Exception:
                pass

            # ── Source map candidates ──
            try:
                sm = page.evaluate("""() =>
                    [...document.querySelectorAll('script[src]')]
                        .map(s => s.src + '.map').slice(0,5)
                """)
                findings["source_map_candidates"] = sm or []
            except Exception:
                pass

            browser.close()

    except Exception as e:
        logger.debug("Playwright keydump v19 error: %s", e)

    return findings


# ── v18: Framework globals extractor ──────────────────────────────────────
def _extract_framework_globals(html: str) -> str:
    """
    Extract window/framework state blobs from HTML:
    __NEXT_DATA__, __NUXT__, pageData, __INITIAL_STATE__,
    __REDUX_STATE__, __APP_STATE__, _env_, ENV, config, APP_CONFIG.
    Returns all found JSON/value strings joined into one string.
    """
    parts = []
    patterns = [
        # __NEXT_DATA__ script tag
        re.compile(r'<script[^>]+id=["\']__NEXT_DATA__["\'][^>]*>\s*(\{.{20,}?\})\s*</script>', re.S | re.I),
        # window assignments (inline script vars)
        re.compile(r'window\.__NEXT_DATA__\s*=\s*(\{.{10,50000}?\})\s*;', re.S),
        re.compile(r'window\.__NUXT__\s*=\s*(\{.{10,50000}?\})\s*;', re.S),
        re.compile(r'window\.pageData\s*=\s*(\{.{10,20000}?\})\s*;', re.S),
        re.compile(r'window\.__INITIAL_STATE__\s*=\s*(\{.{10,50000}?\})\s*;', re.S),
        re.compile(r'window\.__REDUX_STATE__\s*=\s*(\{.{10,50000}?\})\s*;', re.S),
        re.compile(r'window\.__APP_STATE__\s*=\s*(\{.{10,50000}?\})\s*;', re.S),
        re.compile(r'window\._env_\s*=\s*(\{.{10,10000}?\})\s*;', re.S),
        re.compile(r'window\.ENV\s*=\s*(\{.{10,10000}?\})\s*;', re.S),
        re.compile(r'window\.config\s*=\s*(\{.{10,10000}?\})\s*;', re.S),
        re.compile(r'window\.APP_CONFIG\s*=\s*(\{.{10,10000}?\})\s*;', re.S),
        re.compile(r'window\.appConfig\s*=\s*(\{.{10,10000}?\})\s*;', re.S),
        # var/const/let assignments at top level in script tags
        re.compile(r'(?:var|let|const)\s+__NEXT_DATA__\s*=\s*(\{.{10,50000}?\})\s*;', re.S),
    ]
    for pat in patterns:
        for m in pat.finditer(html):
            blob = m.group(1).strip()
            if blob and len(blob) > 10:
                parts.append(blob[:20000])  # cap per-blob at 20KB
    return "\n".join(parts)


def _extract_html_comments(html: str) -> str:
    """
    Extract all HTML comments <!-- ... --> with content length > 10.
    Useful for finding dev notes, debug info, API keys left in comments.
    """
    comments = re.findall(r'<!--([\s\S]*?)-->', html)
    return "\n".join(c.strip() for c in comments if len(c.strip()) > 10)


# ─── Master keydump engine ────────────────────────────────────
def _probe_env_files(base_url: str) -> list:
    """
    Phase 2: Probe common .env / config file paths that expose secrets.
    Returns list of (path, content_snippet) tuples for found files.
    """
    parsed = urlparse(base_url)
    origin = f"{parsed.scheme}://{parsed.netloc}"
    probe_paths = [
        "/.env",
        "/.env.local",
        "/.env.example",
        "/.env.development",
        "/.env.production",
        "/.env.staging",
        "/.env.test",
        "/.env.backup",
        "/.env.old",
        "/.env.bak",
        "/config/.env",
        "/backend/.env",
        "/app/.env",
        "/api/.env",
        "/.config",
        "/config.env",
        "/application.properties",
        "/application.yml",
        "/secrets.yml",
        "/credentials.yml",
        "/.npmrc",
        "/.netrc",
    ]
    found = []
    seen_content = set()

    def _probe_one(path):
        try:
            r = requests.get(
                origin + path, timeout=6, verify=False,
                headers=_get_headers(),
                proxies=proxy_manager.get_proxy(),
                allow_redirects=False,
            )
            if r.status_code != 200:
                return None
            body = r.text[:8000]
            # Must look like a real env file — not an HTML 200 catch-all
            if "<html" in body.lower() or "<body" in body.lower():
                return None
            # Must contain at least one key=value pattern
            if not re.search(r'[A-Z_]{3,}=.{3,}', body):
                return None
            sig = hashlib.md5(body[:512].encode()).hexdigest()
            if sig in seen_content:
                return None
            seen_content.add(sig)
            return (path, body[:3000])
        except Exception:
            return None

    with concurrent.futures.ThreadPoolExecutor(max_workers=8) as ex:
        futures = {ex.submit(_probe_one, p): p for p in probe_paths}
        for fut in concurrent.futures.as_completed(futures, timeout=30):
            try:
                res = fut.result(timeout=8)
                if res:
                    found.append(res)
            except Exception:
                pass

    return found


def _run_keydump_sync(url: str) -> dict:
    """
    Phase 2 — Full keydump:
      1. Static HTML + JS bundles
      2. Pattern scan (50+ _KD_PATTERNS)
      3. High-entropy (threshold 4.2, down from 4.5)
      4. Source map extraction + scan
      5. .env file probe (20 paths)
      6. Dynamic via Playwright
    """
    out = {
        "url":          url,
        "js_count":     0,
        "by_category":  {},
        "high_entropy": [],
        "source_maps":  [],
        "env_files":    [],   # NEW: .env probe results
        "dynamic":      {"requests": [], "storage": {}, "cookies": []},
        "raw_hits":     {},
        "errors":       [],
    }

    # ── 1. Fetch static HTML + JS bundles ────────────────────────────────────
    try:
        data = _scrape_full(url, max_js=20)
    except Exception as e:
        out["errors"].append(f"Fetch error: {e}")
        return out

    if not data["html"]:
        out["errors"].append("Page fetch failed — site may block bots")
        return out

    # Inline <script> blocks
    inline_scripts = []
    try:
        soup_kd = BeautifulSoup(data["html"], "html.parser")
        for tag in soup_kd.find_all("script"):
            if not tag.get("src") and tag.string:
                txt = tag.string.strip()
                if len(txt) > 30:
                    inline_scripts.append(txt)
    except Exception:
        pass

    fw_globals    = _extract_framework_globals(data["html"])
    html_comments = _extract_html_comments(data["html"])
    corpus_parts  = (
        [data["html"]]
        + inline_scripts
        + [js for _, js in data["js_sources"]]
    )
    if fw_globals:
        corpus_parts.append(fw_globals)
    if html_comments:
        corpus_parts.append(html_comments)
    corpus = "\n".join(corpus_parts)
    out["js_count"]      = len(data["js_sources"])
    out["inline_scripts"] = len(inline_scripts)

    # ── 2. Pattern scan — with global dedup set ──────────────────────────────
    _global_kd_seen: set = set()   # ENH K4: dedup across all scan phases

    def _kd_pattern_scan(text_corpus: str, source_tag: str = "") -> None:
        """Scan corpus through all _KD_PATTERNS, add to out with dedup."""
        for label, (pat, cat_icon) in _KD_PATTERNS.items():
            try:
                raw = re.findall(pat, text_corpus, re.IGNORECASE)
            except Exception:
                continue
            flat = []
            for m in raw:
                if isinstance(m, tuple):
                    flat.extend([x.strip() for x in m if x and len(x) > 4])
                else:
                    if m and len(m) > 4:
                        flat.append(m.strip())
            for val in flat:
                dedup_key = label + ":" + val[:80]
                if dedup_key in _global_kd_seen:
                    continue
                _global_kd_seen.add(dedup_key)
                tag_label = f"{label}{' ' + source_tag if source_tag else ''}"
                out["raw_hits"].setdefault(tag_label, [])
                if len(out["raw_hits"][tag_label]) < 8:
                    out["raw_hits"][tag_label].append(val)
                out["by_category"].setdefault(cat_icon, {}).setdefault(tag_label, [])
                if len(out["by_category"][cat_icon][tag_label]) < 8:
                    out["by_category"][cat_icon][tag_label].append(val)

    _kd_pattern_scan(corpus)  # main corpus

    # ── 3. High-entropy — threshold 4.2 (was 4.5) ────────────────────────────
    # Lowering from 4.5 → 4.2 catches more real secrets (AWS, GCP tokens,
    # random API keys) while hex-32/hex-64 patterns add structural coverage.
    out["high_entropy"] = _find_high_entropy(corpus, threshold=4.2)

    # ── 4. Source maps ────────────────────────────────────────────────────────
    try:
        maps = _fetch_source_maps(data["js_sources"], url)
        if maps:
            for js_url, map_text in maps:
                _kd_pattern_scan(map_text, f"(sourcemap: {js_url[-40:]})")
            out["source_maps"] = [js_url for js_url, _ in maps]
    except Exception as e:
        out["errors"].append(f"Sourcemap: {e}")

    # ── 5. .env file probe ────────────────────────────────────────────────────
    try:
        env_files = _probe_env_files(url)
        out["env_files"] = env_files
        for env_path, env_body in env_files:
            _kd_pattern_scan(env_body, f"({env_path})")
    except Exception as e:
        out["errors"].append(f"Env probe: {e}")

    # ── ENH5: __NEXT_DATA__ / __NUXT__ deep JSON walk ─────────────────────────
    try:
        import json as _json
        def _walk_json_secrets(obj, path="", depth=0):
            """Recursively walk JSON and collect high-entropy / pattern-matched values."""
            if depth > 8 or not obj:
                return
            if isinstance(obj, dict):
                for k, v in obj.items():
                    _walk_json_secrets(v, f"{path}.{k}", depth + 1)
            elif isinstance(obj, list):
                for i, v in enumerate(obj[:20]):
                    _walk_json_secrets(v, f"{path}[{i}]", depth + 1)
            elif isinstance(obj, str) and len(obj) > 8:
                for label, (pat, cat_icon) in _KD_PATTERNS.items():
                    try:
                        if re.search(pat, obj, re.IGNORECASE):
                            bucket = out["by_category"].setdefault(cat_icon, {})
                            jlabel = f"{label} (__NEXT_DATA__{path})"
                            bucket.setdefault(jlabel, []).append(obj[:120])
                    except Exception:
                        pass
                # also entropy check
                try:
                    from math import log2
                    freq = {}
                    for c in obj:
                        freq[c] = freq.get(c, 0) + 1
                    entropy = -sum((v/len(obj)) * log2(v/len(obj)) for v in freq.values())
                    if entropy >= 4.2 and len(obj) >= 16:
                        out["by_category"].setdefault("🔒", {}).setdefault(
                            f"High-entropy (__NEXT_DATA__{path})", []
                        ).append(obj[:120])
                except Exception:
                    pass

        # Scan Next.js / Nuxt / generic framework JSON blobs in HTML
        for pattern_str in [
            r'<script[^>]+id=["\']__NEXT_DATA__["\'][^>]*>([^<]{10,})<',
            r'window\.__NUXT__\s*=\s*(\{.*?\})\s*(?:;|</script>)',
            r'window\.__INITIAL_STATE__\s*=\s*(\{.*?\})\s*(?:;|</script>)',
            r'window\.__REDUX_STATE__\s*=\s*(\{.*?\})\s*(?:;|</script>)',
            r'window\.__PRELOADED_STATE__\s*=\s*(\{.*?\})\s*(?:;|</script>)',
        ]:
            for m in re.finditer(pattern_str, corpus, re.DOTALL | re.IGNORECASE):
                try:
                    blob = _json.loads(m.group(1))
                    _walk_json_secrets(blob)
                except Exception:
                    pass
    except Exception as e:
        out["errors"].append(f"NEXT_DATA walk: {e}")

    # ── ENH6: WASM binary secret scan ─────────────────────────────────────────
    try:
        # FIX K3: js_sources is list of (url, text) tuples — pass correctly
        wasm_hits = _scan_wasm_secrets(url, data.get("js_sources", []))
        if wasm_hits:
            bucket = out["by_category"].setdefault("🔒", {})
            for wh in wasm_hits:
                label = f"{wh.get('type','WASM secret')} (wasm)"
                val   = wh.get("value", "")[:80]
                dedup_key = label + ":" + val
                if dedup_key not in _global_kd_seen:
                    _global_kd_seen.add(dedup_key)
                    bucket.setdefault(label, []).append(val)
    except Exception as e:
        out["errors"].append(f"WASM scan: {e}")

    # ── 6. Dynamic via Playwright ─────────────────────────────────────────────
    try:
        dyn = _run_playwright_dynamic_keydump(url)
        out["dynamic"] = dyn

        for store_name, store_data in dyn.get("storage", {}).items():
            if not isinstance(store_data, dict):
                continue
            store_corpus = "\n".join(
                f"{k}={v}" for k, v in store_data.items() if v
            )
            if store_corpus:
                _kd_pattern_scan(store_corpus, f"({store_name})")
    except Exception as e:
        out["errors"].append(f"Dynamic: {e}")

    # ── 7. Real-time network stream intercept (Phase 2) ───────────────────────
    try:
        live_result = _stream_intercept_sync(url, extra_patterns=_LIVE_API_PATTERNS)
        out["live_result"] = live_result
        live_corpus = "\n".join(
            (req.get("body","") or req.get("post_data",""))
            for req in live_result.get("live_requests", [])
            if req.get("body") or req.get("post_data")
        )
        if live_corpus:
            # ENH K4: use shared scan fn — dedup across all phases
            _kd_pattern_scan(live_corpus, "[live stream]")
        # Entropy scan on live bodies too
        if live_corpus:
            live_entropy = _find_high_entropy(live_corpus, threshold=4.2)
            for item in live_entropy:
                item["source"] = "live stream"
                # ENH K4: dedup entropy hits too
                if item["value"] not in {e["value"] for e in out["high_entropy"]}:
                    out["high_entropy"].append(item)
            out["high_entropy"] = sorted(
                out["high_entropy"], key=lambda x: -x.get("entropy", 0)
            )[:50]
    except Exception as e:
        out["errors"].append(f"Live stream: {e}")
        out["live_result"] = {"live_requests": [], "live_findings": [], "sse_frames": []}

    # ── ENH: Deep JSON / Response Header / JWT / WebSocket scan on keydump ────
    try:
        _kd_live   = out.get("live_result") or {}
        _kd_net    = [
            {"url": r.get("url",""), "response_body": r.get("body",""),
             "response_headers": r.get("headers",{}), "post_data": r.get("post_data","")}
            for r in _kd_live.get("live_requests", [])
        ]
        # Collect all pattern tuples from _KD_PATTERNS for ENH helpers
        _kd_pats = [(lbl, pat) for lbl, (pat, _) in _KD_PATTERNS.items()]
        _kd_seen: set = set()
        # Build all_texts for JWT scan: live request bodies + existing corpus
        _kd_texts = [
            (r.get("body","") or r.get("post_data",""),
             f"Live req: {r.get('url','')[:60]}")
            for r in _kd_live.get("live_requests", [])
            if r.get("body") or r.get("post_data")
        ]

        def _kd_add(typ, val, src):
            """Add finding into keydump out structure."""
            val = str(val).strip()
            if len(val) < 5:
                return
            # Find matching _KD_PATTERNS category
            cat_icon = "🔒"
            for lbl, (_, ci) in _KD_PATTERNS.items():
                if lbl in typ:
                    cat_icon = ci
                    break
            bucket = out["by_category"].setdefault(cat_icon, {})
            bucket.setdefault(typ, [])
            if val not in bucket[typ]:
                bucket[typ].append(val[:120])
            out["raw_hits"].setdefault(typ, [])
            if val not in out["raw_hits"][typ]:
                out["raw_hits"][typ].append(val[:120])

        for ef in _deep_json_response_scan(_kd_net, _kd_pats, _kd_seen):
            _kd_add(ef["type"] + " [JSON response]", ef["value"], ef["source"])

        for ef in _response_header_cookie_scan(_kd_net, _kd_pats, _kd_seen):
            _kd_add(ef["type"], ef["value"], ef["source"])

        for ef in _jwt_payload_scan(_kd_texts, _kd_pats, _kd_seen):
            _kd_add(ef["type"], ef["value"], ef["source"])

        for ef in _websocket_deep_scan(_kd_live, _kd_pats, _kd_seen):
            _kd_add(ef["type"] + " [WebSocket]", ef["value"], ef["source"])

        for ef in _graphql_response_deep_scan(_kd_net, _kd_pats, _kd_seen):
            _kd_add(ef["type"] + " [GraphQL]", ef["value"], ef["source"])

        # Browser storage from dynamic scan
        dyn_storage = out.get("dynamic", {}).get("storage", {})
        for ef in _browser_storage_scan(dyn_storage, _kd_pats, _kd_seen):
            _kd_add(ef["type"] + " [storage]", ef["value"], ef["source"])

    except Exception as _enh_e:
        out["errors"].append(f"ENH scan: {_enh_e}")

    return out


def _kd_confidence(label: str, value: str) -> tuple:
    """
    Phase 3: Assign confidence level to a keydump hit.
    Returns (badge: str, level: str)
      HIGH  — known prefix/format that is unambiguous (AKIA, pk_live_, ghp_, etc.)
      MED   — pattern match with keyword context but no unique prefix
      LOW   — entropy-only or weak-context match
    """
    v = value.strip()
    # ── HIGH confidence: hard vendor prefixes ────────────────────────────────
    HIGH_PREFIXES = (
        "AKIA", "ASIA", "AROA",          # AWS keys
        "AIza",                          # GCP / Firebase
        "dop_v1_",                       # DigitalOcean
        "sk-ant-",                       # Anthropic
        "hf_",                           # HuggingFace
        "ghp_", "gho_", "ghu_",          # GitHub PAT
        "ghs_", "ghr_",                  # GitHub Actions
        "glpat-",                        # GitLab
        "npm_",                          # NPM
        "xoxb-", "xoxp-", "xapp-",      # Slack tokens
        "SG.",                           # SendGrid
        "pk_live_", "pk_test_",          # Stripe publishable
        "sk_live_", "sk_test_",          # Stripe secret
        "whsec_",                        # Stripe webhook
        "rk_live_", "rk_test_",          # Stripe restricted
        "sq0idp-", "sq0atp-",            # Square
        "rzp_live_", "rzp_test_",        # Razorpay
        "AQE",                           # Adyen
        "EAAa",                          # Facebook access token
        "eyJ",                           # JWT (structural)
        "-----BEGIN",                    # PEM private key
        "pk.eyJ",                        # Mapbox
        "sk-",                           # OpenAI (sk- prefix)
        "AC",                            # Twilio SID (AC + 32 hex)
        "mongodb://", "mongodb+srv://",  # DB URIs
        "postgres://", "postgresql://",
        "mysql://", "mysql2://",
        "redis://", "rediss://",
    )
    # HIGH: value starts with a hard prefix
    for prefix in HIGH_PREFIXES:
        if v.startswith(prefix):
            return ("🟢 HIGH", "HIGH")
    # HIGH: label explicitly names a live key
    if any(x in label for x in ("live", "Live", "Private Key", "Secret Key", "Webhook Secret")):
        return ("🟢 HIGH", "HIGH")
    # HIGH: URL-form credentials (contains :// and @ → auth in URI)
    if "://" in v and "@" in v:
        return ("🟢 HIGH", "HIGH")

    # ── MED confidence: keyword-context pattern hits ──────────────────────────
    MED_LABELS = (
        "API Key", "Access Token", "Auth", "Bearer", "Password",
        "Secret", "Credential", "Token", "Client ID", "Client Secret",
        "Firebase", "Analytics", "Tag Manager", "Pixel",
        "reCAPTCHA", "hCaptcha", "Turnstile",
    )
    for kw in MED_LABELS:
        if kw.lower() in label.lower():
            return ("🟡 MED", "MED")
    # MED: long alphanumeric string (≥24 chars, mixed case)
    if len(v) >= 24 and re.search(r'[A-Z]', v) and re.search(r'[a-z]', v) and re.search(r'\d', v):
        return ("🟡 MED", "MED")

    # ── LOW: everything else (short strings, digits-only, analytics IDs) ─────
    return ("⚪ LOW", "LOW")


def _format_keydump_report(result: dict) -> tuple:
    """
    Phase 3 — Full keydump report with per-hit confidence badges.
    Returns (telegram_text: str, full_json: dict)
    """
    url      = result["url"]
    domain   = urlparse(url).netloc
    path     = urlparse(url).path or "/"
    js_cnt   = result["js_count"]
    cats     = result["by_category"]
    entropy  = result["high_entropy"]
    dyn      = result["dynamic"]
    smaps    = result["source_maps"]
    env_files = result.get("env_files", [])

    total_hits = sum(len(v) for cat in cats.values() for v in cat.values())

    # ── Confidence tally ──────────────────────────────────────────────────────
    conf_counts = {"HIGH": 0, "MED": 0, "LOW": 0}
    for cat_data in cats.values():
        for label, vals in cat_data.items():
            for v in vals:
                _, lvl = _kd_confidence(label, v)
                conf_counts[lvl] += 1

    js_mode    = "⚡ JS+Static+Dynamic+LiveStream" if PLAYWRIGHT_OK else "📄 Static+JS"
    inline_cnt = result.get("inline_scripts", 0)
    live_result = result.get("live_result") or {}
    live_reqs   = len(live_result.get("live_requests", []))
    live_labels = [l for l in result.get("raw_hits", {}) if "[live stream]" in l]
    live_hits   = sum(len(result["raw_hits"][l]) for l in live_labels)

    # ── Confidence summary line ───────────────────────────────────────────────
    conf_line = (
        f"🟢 `{conf_counts['HIGH']}` HIGH  "
        f"🟡 `{conf_counts['MED']}` MED  "
        f"⚪ `{conf_counts['LOW']}` LOW"
    )
    live_line = (
        f"🔴 Live stream: `{escape_md(live_reqs)}` requests | "
        f"`{escape_md(live_hits)}` hits from live traffic"
    )

    lines = [
        f"🔑 *KeyDump v22 — Full Scan*",
        f"🌐 `{escape_md(domain)}`",
        f"📁 Path: `{escape_md(path)}`",
        f"━━━━━━━━━━━━━━━━━━━━",
        f"📦 JS: `{escape_md(js_cnt)}` | Inline: `{escape_md(inline_cnt)}` | {js_mode}",
        f"📊 Patterns: `{len(_KD_PATTERNS)}` | Hits: `{escape_md(total_hits)}`",
        conf_line,
        live_line,
        "",
    ]

    if total_hits == 0 and not entropy and not dyn.get("requests"):
        lines += [
            "✅ *Nothing exposed in source*",
            "",
            "_Keys may be server-side only, in env vars, or obfuscated_",
            "",
            f"📌 Scanned: HTML + `{escape_md(js_cnt)}` JS files",
            f"🔍 High-entropy strings checked: `{len(entropy)}`",
        ]
    else:
        # ── Per-category results with confidence badge + exploit hint ─────────
        # Group by severity tier first (CRITICAL → HIGH → MEDIUM → LOW)
        tier_buckets: dict = {"CRITICAL": [], "HIGH": [], "MEDIUM": [], "LOW": []}
        for cat_icon, cat_name in _KD_CATEGORIES.items():
            if cat_icon not in cats:
                continue
            sev = _KD_SEVERITY.get(cat_icon, "MEDIUM")
            tier_buckets.setdefault(sev, []).append((cat_icon, cat_name, cats[cat_icon]))

        for tier in ("CRITICAL", "HIGH", "MEDIUM", "LOW"):
            bucket = tier_buckets.get(tier, [])
            if not bucket:
                continue
            tier_label = _KD_TIER_EMOJI.get(tier, tier)
            lines.append(f"┌─ {tier_label} ─────────────────")
            for cat_icon, cat_name, cat_data in bucket:
                count = sum(len(v) for v in cat_data.values())
                lines.append(f"{cat_icon} *{cat_name}* `({count})`")
                for label, vals in cat_data.items():
                    badge, _ = _kd_confidence(label, vals[0]) if vals else ("⚪ LOW", "LOW")
                    lines.append(f"  ┌ {badge} *{label}*")
                    for v in vals[:3]:
                        safe = v.replace("`", "'")
                        lines.append(f"  └ `{safe[:70]}`")
                    # ── Exploit hint (unique to v18) ──────────────────────
                    hint = _kd_exploit_hint(label)
                    if hint:
                        lines.append(f"  ⚡ _{escape_md(hint[:90])}_")
            lines.append("")

        # ── .env file hits (Phase 2) ─────────────────────────────────────────
        if env_files:
            lines.append(f"📄 *Exposed Config Files* `({len(env_files)})`")
            for env_path, env_body in env_files[:5]:
                lines.append(f"  🟢 HIGH `{escape_md(env_path)}`")
                # Show first 2 non-empty lines of env file
                preview = [l for l in env_body.splitlines() if "=" in l and len(l) > 5]
                for pl in preview[:2]:
                    safe = pl.replace("`", "'")
                    lines.append(f"  └ `{escape_md(safe[:65])}`")
            lines.append("")

        # ── Dynamic / network interception ───────────────────────────────────
        if dyn.get("requests"):
            lines.append(f"🌐 *Network Intercepted Tokens* `({len(dyn['requests'])})`")
            for req in dyn["requests"][:4]:
                lines.append(f"  🔗 `{req['url'][:50]}`")
                for hk, hv in req.get("headers", {}).items():
                    lines.append(f"     `{hk}: {str(hv)[:50]}`")
            lines.append("")

        # ── Auth cookies ─────────────────────────────────────────────────────
        interesting_cookies = [
            c for c in dyn.get("cookies", [])
            if any(k in c["name"].lower() for k in
                   ["token", "auth", "session", "key", "jwt", "access", "secret", "api"])
        ]
        if interesting_cookies:
            lines.append(f"🍪 *Auth Cookies* `({len(interesting_cookies)})`")
            for c in interesting_cookies[:5]:
                badge, _ = _kd_confidence("Token", c["value"])
                _cn = c['name'].replace('`', "'")
                _cv = c['value'][:50].replace('`', "'")
                lines.append(f"  {badge} `{_cn}` = `{_cv}`")
            lines.append("")

        # ── High-entropy strings ──────────────────────────────────────────────
        if entropy:
            lines.append(f"🔬 *High-Entropy Strings* `(H≥4.2)` — `{len(entropy)}` found")
            for item in entropy[:6]:
                badge, _ = _kd_confidence("entropy", item["value"])
                _ev = item['value'][:55].replace('`', "'")
                lines.append(
                    f"  {badge} H=`{item['entropy']}` `{_ev}`"
                )
            lines.append("")

        # ── Source maps ───────────────────────────────────────────────────────
        if smaps:
            lines.append(f"🗺 *Source Maps Found* `({len(smaps)})`")
            for sm in smaps[:3]:
                lines.append(f"  `{escape_md(sm[-60:])}`")
            lines.append("")

    lines += [
        "━━━━━━━━━━━━━━━━━━━━",
        "⚠️ _For authorized/security research use only_",
        "",
        f"💾 Reply with /kdexport to get full JSON report",
    ]

    return "\n".join(lines), result


def _keydump_keyboard(uid: int) -> InlineKeyboardMarkup:
    return InlineKeyboardMarkup([
        [
            InlineKeyboardButton("📋 Show Raw", callback_data=f"kd_raw_{uid}"),
            InlineKeyboardButton("🔬 Entropy", callback_data=f"kd_entropy_{uid}"),
        ],
        [
            InlineKeyboardButton("💾 Export JSON", callback_data=f"kd_json_{uid}"),
        ],
    ])

# Global keydump result cache (per uid)
_kd_cache: dict = {}   # {uid: result_dict}


@user_guard
async def cmd_keydump(update: Update, context: ContextTypes.DEFAULT_TYPE):
    """/keydump <url> — Comprehensive key/token extractor (HTML + JS + Dynamic)"""
    if not context.args:
        await update.effective_message.reply_text(
            "🔑 *KeyDump v18 — Flagship Key Extractor*\n"
            "━━━━━━━━━━━━━━━━━━━━\n\n"
            "*Usage:* `/keydump https://example.com/path/page`\n\n"
            "*Scans ALL of the following at once:*\n"
            f"• {len(_KD_PATTERNS)} regex patterns (TruffleHog/Gitleaks style)\n"
            "• High-entropy string analysis (H > 4.5)\n"
            "• Source map extraction (.js.map)\n"
            "• Browser storage (localStorage, sessionStorage, cookies)\n"
            "• Network request interception (Authorization headers)\n"
            "• All linked JS bundles (up to 15 files)\n\n"
            "*Categories scanned:*\n"
            "☁️ Cloud  🔥 Firebase  💳 Payment  🧬 JWT\n"
            "📱 Social  📊 Analytics  🔒 Secrets  📨 Comms\n\n"
            f"⚡ Dynamic mode: {'✅ Playwright ready' if PLAYWRIGHT_OK else '⚠️ Static only (pip install playwright)'}",
            parse_mode="Markdown"
        )
        return

    uid  = update.effective_user.id
    raw  = context.args[0]
    url  = raw if raw.startswith("http") else "https://" + raw

    # ── Security checks ────────────────────────────────────────
    ok, reason = is_safe_url(url)
    if not ok:
        await update.effective_message.reply_text(
            f"🚫 `{escape_md(reason)}`", parse_mode="Markdown"); return

    ok2, wait = check_rate_limit(uid)
    if not ok2:
        await update.effective_message.reply_text(
            f"⏳ Rate limit — `{wait}s` စောင့်ပါ", parse_mode="Markdown"); return

    domain = urlparse(url).netloc
    path   = urlparse(url).path or "/"

    msg = await update.effective_message.reply_text(
        f"🔑 *KeyDump Scanning...*\n"
        f"🌐 `{escape_md(domain)}`\n"
        f"📁 `{escape_md(path)}`\n\n"
        f"① HTML fetch + JS bundle crawl...\n"
        f"② Pattern matching (`{len(_KD_PATTERNS)}` rules)...\n"
        f"③ Entropy analysis (H≥4.2)...\n"
        f"④ Source map check...\n"
        f"⑤ Dynamic intercept (Playwright)...\n"
        f"⑥ 🔴 Live network stream intercept...",
        parse_mode="Markdown"
    )

    try:
        result = await asyncio.to_thread(_run_keydump_sync, url)
    except Exception as e:
        await msg.edit_text(
            f"❌ *KeyDump Error*\n`{type(e).__name__}: {str(e)[:100]}`",
            parse_mode="Markdown")
        return

    # ENH K5: Cache key = uid+timestamp to prevent concurrent-run overwrite
    import time as _time
    cache_key = f"{uid}_{int(_time.time())}"
    _kd_cache[uid] = result          # still keep uid lookup for callbacks
    _kd_cache[cache_key] = result    # timestamped key for concurrent safety

    report, _ = _format_keydump_report(result)

    total = sum(len(v) for cat in result["by_category"].values() for v in cat.values())
    kb = _keydump_keyboard(uid) if total > 0 or result["high_entropy"] else None

    try:
        if len(report) <= 4000:
            await msg.edit_text(report, parse_mode="Markdown",
                                reply_markup=kb)
        else:
            await msg.edit_text(_truncate_safe_md(report),
                                parse_mode="Markdown", reply_markup=kb)
            await update.effective_message.reply_text(
                report[4000:8000], parse_mode="Markdown")
    except Exception:
        await update.effective_message.reply_text(
            _truncate_safe_md(report), parse_mode="Markdown")

    # ── Deobfuscation layer — keydump JS ထဲ obfuscated secrets ရှာ ──────────
    try:
        texts_for_deob = {}
        for item in result.get("network_log", []):
            ct   = item.get("content_type", "") or ""
            body = item.get("response_body", "") or item.get("body", "") or ""
            if ("javascript" in ct or item.get("url","").endswith(".js")) and body:
                lbl = item.get("url","?").split("/")[-1][:40]
                texts_for_deob[lbl] = body
        texts_for_deob["[HTML]"] = result.get("html", "")
        deob_findings = await asyncio.to_thread(_deobfuscate_layer, texts_for_deob)
        # Only report HIGH risk — in_secret_context + entropy >= 4.5
        high_deob = [f for f in deob_findings
                     if f["in_secret_context"] and f["entropy"] >= 4.5]
        if high_deob:
            deob_lines = [f"🧩 *Deobfuscated Secrets — `{escape_md(domain)}`*",
                          "━━━━━━━━━━━━━━━━━━━━",
                          f"🔴 High-risk decoded: `{len(high_deob)}`\n"]
            for i, f in enumerate(high_deob[:10], 1):
                deob_lines.append(f"*[{i}]* `{escape_md(f['method'])}` H=`{f['entropy']}`")
                deob_lines.append(f"  ✅ `{escape_md(f['decoded'][:80])}`")
                deob_lines.append(f"  📂 _{escape_md(f['source'])}_\n")
            deob_lines.append("⚠️ _Authorized testing only_")
            await update.effective_message.reply_text(
                _truncate_safe_md("\n".join(deob_lines)), parse_mode='Markdown')
    except Exception as deob_err:
        logger.debug("keydump deobfuscate layer error: %s", deob_err)
    """Handle /keydump inline buttons: raw, entropy, json export"""
    query = update.callback_query
    try:
        await query.answer()
    except Exception:
        pass
    data = query.data   # kd_raw_UID | kd_entropy_UID | kd_json_UID

    try:
        parts  = data.split("_")
        action = parts[1]                    # raw / entropy / json
        uid    = int(parts[2])
    except Exception:
        return

    # Only the requesting user can use the buttons
    if query.from_user.id != uid:
        await query.answer("🚫 သင်မဟုတ်ပါ", show_alert=True)
        return

    result = _kd_cache.get(uid)
    if not result:
        await query.answer("⚠️ Cache expired — /keydump ထပ်လုပ်ပါ", show_alert=True)
        return

    if action == "raw":
        lines = ["📋 *Raw Findings*\n"]
        for label, vals in result["raw_hits"].items():
            lines.append(f"*{label}:*")
            for v in vals[:4]:
                lines.append(f"  `{escape_md(v[:80])}`")
            lines.append("")
        text = "\n".join(lines) or "Nothing found"
        try:
            await safe_markdown_reply(query, _truncate_safe_md(text))
        except Exception:
            await safe_markdown_reply(query.message, _truncate_safe_md(text))

    elif action == "entropy":
        entropy = result.get("high_entropy", [])
        if not entropy:
            await query.answer("High-entropy strings မတွေ့ပါ", show_alert=True)
            return
        lines = [f"🔬 *High-Entropy Strings ({len(entropy)})*\n",
                 "_H > 4.5 = likely secret/key_\n"]
        for item in entropy[:15]:
            lines.append(
                f"H=`{item['entropy']}` `{item['value'][:65]}`"
            )
        try:
            await safe_markdown_reply(query, _truncate_safe_md("\n".join(lines)))
        except Exception:
            await safe_markdown_reply(query.message, _truncate_safe_md("\n".join(lines)))

    elif action == "json":
        # Export as JSON file
        try:
            export = {
                "url":         result["url"],
                "scanned_at":  datetime.now().isoformat(),
                "js_bundles":  result["js_count"],
                "findings":    result["raw_hits"],
                "high_entropy": result["high_entropy"],
                "source_maps": result["source_maps"],
                "dynamic":     {
                    "intercepted_requests": result["dynamic"]["requests"],
                    "auth_cookies": [
                        c for c in result["dynamic"].get("cookies", [])
                        if any(k in c["name"].lower() for k in
                               ["token","auth","session","key","jwt"])
                    ],
                },
                "live_stream": {
                    "requests_captured": len(
                        (result.get("live_result") or {}).get("live_requests", [])),
                    "sse_frames": len(
                        (result.get("live_result") or {}).get("sse_frames", [])),
                    "live_hits": [
                        l for l in result.get("raw_hits", {}) if "[live stream]" in l
                    ],
                },
                "errors":      result["errors"],
            }
            import tempfile, os as _os
            tmp = tempfile.NamedTemporaryFile(
                suffix=".json", delete=False, mode="w", encoding="utf-8"
            )
            json.dump(export, tmp, ensure_ascii=False, indent=2)
            tmp.close()

            domain = urlparse(result["url"]).netloc.replace(".", "_")
            ts     = datetime.now().strftime("%Y%m%d_%H%M%S")
            fname  = f"keydump_{domain}_{ts}.json"

            with open(tmp.name, "rb") as f:
                await context.bot.send_document(
                    chat_id=query.from_user.id,
                    document=f,
                    filename=fname,
                    caption=(
                        f"💾 *KeyDump JSON Export*\n"
                        f"🌐 `{result['url'][:60]}`\n"
                        f"📊 `{sum(len(v) for v in export['findings'].values())}` findings"
                    ),
                    parse_mode="Markdown"
                )
            _os.unlink(tmp.name)
            await query.answer("✅ JSON exported!", show_alert=False)
        except Exception as e:
            await query.answer(f"Export error: {e}", show_alert=True)


# ── /kdexport shortcut ────────────────────────────────────────
@user_guard
async def cmd_kdexport(update: Update, context: ContextTypes.DEFAULT_TYPE):
    """/kdexport — Export last keydump result as JSON"""
    uid    = update.effective_user.id
    result = _kd_cache.get(uid)
    if not result:
        await update.effective_message.reply_text(
            "⚠️ Cache မရှိပါ — `/keydump <url>` ကနေ scan ဦးစွာ လုပ်ပါ",
            parse_mode="Markdown"); return

    # Trigger json export inline
    export = {
        "url":          result["url"],
        "scanned_at":   datetime.now().isoformat(),
        "js_bundles":   result["js_count"],
        "findings":     result["raw_hits"],
        "high_entropy": result["high_entropy"],
        "source_maps":  result["source_maps"],
        "dynamic":      result["dynamic"],
        "errors":       result["errors"],
    }
    import tempfile, os as _os
    tmp = tempfile.NamedTemporaryFile(
        suffix=".json", delete=False, mode="w", encoding="utf-8"
    )
    json.dump(export, tmp, ensure_ascii=False, indent=2)
    tmp.close()

    domain = urlparse(result["url"]).netloc.replace(".", "_")
    ts     = datetime.now().strftime("%Y%m%d_%H%M%S")
    fname  = f"keydump_{domain}_{ts}.json"

    with open(tmp.name, "rb") as f:
        await context.bot.send_document(
            chat_id=uid,
            document=f,
            filename=fname,
            caption=(
                f"💾 *KeyDump Export*\n"
                f"🌐 `{result['url'][:60]}`\n"
                f"📊 `{sum(len(v) for v in export['findings'].values())}` total findings"
            ),
            parse_mode="Markdown"
        )
    _os.unlink(tmp.name)



# ══════════════════════════════════════════════════
# 🔐  /oauthscan — OAuth Token & Client Secret Scanner
# ══════════════════════════════════════════════════

_OAUTH_PATTERNS = [
    # OAuth Client IDs
    ("Google OAuth Client ID",
     re.compile(r'\b([0-9]{12,}-[a-z0-9]{32}\.apps\.googleusercontent\.com)\b')),
    # OAuth Client Secrets
    ("Google OAuth Client Secret",
     re.compile(r'(?i)client[_\-]?secret\s*[=:]\s*["\']?(GOCSPX-[A-Za-z0-9_\-]{28,})["\']?')),
    # Generic Client ID
    ("Generic Client ID",
     re.compile(r'(?i)client[_\-]?id\s*[=:]\s*["\']([A-Za-z0-9_\-\.]{20,120})["\']')),
    # Generic Client Secret
    ("Generic Client Secret",
     re.compile(r'(?i)client[_\-]?secret\s*[=:]\s*["\']([A-Za-z0-9_\-\.]{16,120})["\']')),
    # Facebook App ID / Secret
    ("Facebook App ID",
     re.compile(r'(?i)(?:fb|facebook)[_\-]?app[_\-]?id\s*[=:]\s*["\']?([0-9]{10,20})["\']?')),
    ("Facebook App Secret",
     re.compile(r'(?i)(?:fb|facebook)[_\-]?(?:app[_\-]?)?secret\s*[=:]\s*["\']([a-f0-9]{32})["\']')),
    # Twitter / X OAuth
    ("Twitter Consumer Key",
     re.compile(r'(?i)(?:twitter|TWITTER)[_\-]?(?:consumer[_\-]?key|api[_\-]?key)\s*[=:]\s*["\']([A-Za-z0-9]{25,60})["\']')),
    ("Twitter Consumer Secret",
     re.compile(r'(?i)(?:twitter|TWITTER)[_\-]?(?:consumer[_\-]?secret|api[_\-]?secret)\s*[=:]\s*["\']([A-Za-z0-9]{40,80})["\']')),
    # GitHub OAuth App
    ("GitHub OAuth App Secret",
     re.compile(r'(?i)github[_\-]?(?:client[_\-]?secret|oauth[_\-]?secret)\s*[=:]\s*["\']([a-f0-9]{40})["\']')),
    # LinkedIn
    ("LinkedIn Client ID",
     re.compile(r'(?i)linkedin[_\-]?(?:client[_\-]?id|app[_\-]?id)\s*[=:]\s*["\']([A-Za-z0-9]{12,30})["\']')),
    ("LinkedIn Client Secret",
     re.compile(r'(?i)linkedin[_\-]?(?:client[_\-]?secret)\s*[=:]\s*["\']([A-Za-z0-9]{16,40})["\']')),
    # Discord
    ("Discord Client ID",
     re.compile(r'(?i)discord[_\-]?(?:client[_\-]?id|bot[_\-]?id)\s*[=:]\s*["\']?([0-9]{17,20})["\']?')),
    ("Discord Client Secret",
     re.compile(r'(?i)discord[_\-]?(?:client[_\-]?secret|token)\s*[=:]\s*["\']([A-Za-z0-9_\-\.]{20,80})["\']')),
    # Spotify
    ("Spotify Client ID",
     re.compile(r'(?i)spotify[_\-]?client[_\-]?id\s*[=:]\s*["\']([a-f0-9]{32})["\']')),
    ("Spotify Client Secret",
     re.compile(r'(?i)spotify[_\-]?client[_\-]?secret\s*[=:]\s*["\']([a-f0-9]{32})["\']')),
    # Auth0
    ("Auth0 Client ID",
     re.compile(r'(?i)auth0[_\-]?client[_\-]?id\s*[=:]\s*["\']([A-Za-z0-9]{32})["\']')),
    ("Auth0 Client Secret",
     re.compile(r'(?i)auth0[_\-]?client[_\-]?secret\s*[=:]\s*["\']([A-Za-z0-9_\-]{40,100})["\']')),
    # OAuth Bearer / Access Tokens in HTML/JS
    ("OAuth Bearer Token",
     re.compile(r'(?i)(?:bearer|Bearer)\s+([A-Za-z0-9_\-\.]{40,300})')),
    # Okta
    ("Okta Client ID",
     re.compile(r'(?i)okta[_\-]?client[_\-]?id\s*[=:]\s*["\']([A-Za-z0-9]{20,50})["\']')),
    # Generic redirect_uri (OAuth flow leak)
    ("OAuth redirect_uri",
     re.compile(r'(?i)redirect[_\-]?uri\s*[=:]\s*["\']?(https?://[^\s"\'&]{10,200})["\']?')),
]

_OAUTH_JS_EVAL = """() => {
    const results = {};
    const kwds = [
        'clientId','client_id','clientSecret','client_secret',
        'GOOGLE_CLIENT_ID','GOOGLE_CLIENT_SECRET',
        'FACEBOOK_APP_ID','FACEBOOK_APP_SECRET',
        'TWITTER_CONSUMER_KEY','TWITTER_CONSUMER_SECRET',
        'GITHUB_CLIENT_ID','GITHUB_CLIENT_SECRET',
        'AUTH0_CLIENT_ID','SPOTIFY_CLIENT_ID',
        'DISCORD_CLIENT_ID','LINKEDIN_CLIENT_ID',
        'oauthClientId','oauthClientSecret','oAuthKey',
    ];
    kwds.forEach(k => {
        try {
            const v = window[k]
                   || (window.__ENV__ && window.__ENV__[k])
                   || (window._env_ && window._env_[k])
                   || (window.ENV && window.ENV[k])
                   || (window.__NEXT_DATA__ && window.__NEXT_DATA__[k]);
            if (v && typeof v === 'string' && v.length > 8)
                results[k] = v;
        } catch(e) {}
    });
    // Scan meta tags for client_id
    document.querySelectorAll('meta').forEach(m => {
        const n = (m.name || m.getAttribute('property') || '').toLowerCase();
        if ((n.includes('client') || n.includes('oauth') || n.includes('app_id'))
            && m.content && m.content.length > 6) {
            results['meta:' + n] = m.content;
        }
    });
    return results;
}"""

def _oauthscan_sync(url: str, progress_cb=None) -> dict:
    """Improved OAuth scanner — redirect_uri, PKCE, state, implicit, token endpoints."""
    data = _extract_run(url, _OAUTH_JS_EVAL, progress_cb)
    if data.get("error"):
        return {"error": data["error"], "findings": [], "page_url": url}

    findings = []
    seen     = set()
    risks    = []

    def _add(key_type, value, source, risk=None):
        dedup = key_type + ":" + value[:60]
        if dedup in seen or len(value) < 8:
            return
        seen.add(dedup)
        entry = {"type": key_type, "value": value, "source": source}
        if risk:
            entry["risk"] = risk
        findings.append(entry)

    if progress_cb:
        progress_cb("🔍 Scanning OAuth tokens, redirect_uris, PKCE, state params...")

    all_patterns = list(_OAUTH_PATTERNS) + _OAUTH_PATTERNS_EXTRA

    redirect_uris  = []
    state_params   = []
    pkce_found     = False
    implicit_found = []

    for text, label in _gather_all_text(data):
        for key_type, pat in all_patterns:
            for m in pat.finditer(text):
                val = m.group(1) if m.lastindex else m.group(0)
                val = val.strip()
                _add(key_type, val, label)

                if key_type == "OAuth redirect_uri":
                    redirect_uris.append(val)
                elif key_type == "OAuth state param":
                    state_params.append(val)
                elif key_type == "PKCE code_challenge":
                    pkce_found = True
                elif key_type == "Implicit access_token (fragment)":
                    implicit_found.append(val)

    # DOM globals
    for k, v in (data.get("dom_result") or {}).items():
        for key_type, pat in all_patterns:
            m = pat.search(str(v))
            if m:
                val = (m.group(1) if m.lastindex else m.group(0)).strip()
                _add(key_type, val, f"window.{k}")

    # ── Risk analysis ─────────────────────────────
    if redirect_uris:
        _add("redirect_uri summary",
             f"{len(redirect_uris)} uri(s) found: {', '.join(redirect_uris[:3])}",
             "Analysis")
        # Check for open redirect_uri (wildcard or non-https)
        for ru in redirect_uris:
            if ru.startswith("http://"):
                risks.append(f"MEDIUM: redirect_uri uses HTTP (not HTTPS): {ru[:60]}")
            if "*" in ru or ru.endswith("/"):
                risks.append(f"HIGH: Potentially wildcarded redirect_uri: {ru[:60]}")

    if not state_params and redirect_uris:
        risks.append(
            "HIGH: OAuth flow detected but no `state` param found — "
            "CSRF on authorization endpoint possible"
        )

    if implicit_found:
        risks.append(
            "MEDIUM: Implicit flow access_token found in URL fragment — "
            "tokens exposed in browser history / referrer headers"
        )

    if pkce_found:
        findings.append({
            "type":   "PKCE",
            "value":  "code_challenge detected — PKCE in use ✅",
            "source": "Analysis",
        })
    elif redirect_uris:
        risks.append("LOW: No PKCE (code_challenge) detected in OAuth flow")

    # ── Token endpoint probe ──────────────────────
    if progress_cb:
        progress_cb("🔍 Probing token endpoints...")
    parsed = urlparse(url)
    origin = f"{parsed.scheme}://{parsed.netloc}"
    for ep_path in _OAUTH_TOKEN_ENDPOINTS:
        try:
            r = requests.options(
                origin + ep_path, timeout=5, verify=False,
                headers=_get_headers(), proxies=proxy_manager.get_proxy()
            )
            if r.status_code in (200, 405, 401):
                _add(
                    "Token endpoint",
                    origin + ep_path,
                    f"Probe [{r.status_code}]",
                )
        except Exception:
            pass

    return {
        "error":         None,
        "findings":      findings,
        "page_url":      data["page_url"],
        "requests":      len(data.get("network_log", [])),
        "redirect_uris": redirect_uris,
        "state_found":   bool(state_params),
        "pkce":          pkce_found,
        "implicit":      implicit_found,
        "risks":         risks,
    }


# ───────────────────────────────────────────────────────────────────
# [6] REPLACE _hiddenkeys_sync + expand _CSRF_PATTERNS
#     (original: line ~8706)
#     IMPROVEMENTS:
#       + meta[name=csrf-token] scan
#       + CSP header nonce extraction
#       + Service worker (sw.js) scan
#       + 15 new CSRF/token regex patterns
#       + IndexedDB key name enumeration via JS eval
# ───────────────────────────────────────────────────────────────────

# REPLACE _CSRF_PATTERNS entirely with this expanded version:
_WEBHOOK_PATTERNS = [
    # Slack
    ("Slack Incoming Webhook",
     re.compile(r'(https://hooks\.slack\.com/services/T[A-Za-z0-9_]+/B[A-Za-z0-9_]+/[A-Za-z0-9_]+)')),
    ("Slack Workflow Webhook",
     re.compile(r'(https://hooks\.slack\.com/workflows/[A-Za-z0-9_/]+)')),
    # Discord
    ("Discord Webhook",
     re.compile(r'(https://(?:ptb\.|canary\.)?discord(?:app)?\.com/api/webhooks/[0-9]+/[A-Za-z0-9_\-]+)')),
    # Microsoft Teams
    ("MS Teams Webhook",
     re.compile(r'(https://[a-z0-9]+\.webhook\.office\.com/webhookb2/[A-Za-z0-9@%\-_\./]+)')),
    # GitHub Webhooks
    ("GitHub Webhook Secret",
     re.compile(r'(?i)github[_\-]?webhook[_\-]?secret\s*[=:]\s*["\']([A-Za-z0-9_\-]{20,80})["\']')),
    # Telegram Bot Webhook
    ("Telegram Webhook URL",
     re.compile(r'(https://api\.telegram\.org/bot[A-Za-z0-9_:]+/setWebhook[^\s"\'<>]{0,200})')),
    # Zapier
    ("Zapier Webhook",
     re.compile(r'(https://hooks\.zapier\.com/hooks/catch/[A-Za-z0-9/]+)')),
    # IFTTT
    ("IFTTT Webhook",
     re.compile(r'(https://maker\.ifttt\.com/trigger/[^\s"\'<>&]{5,100})')),
    # PagerDuty
    ("PagerDuty Webhook",
     re.compile(r'(https://events\.pagerduty\.com/v2/enqueue[^\s"\'<>]{0,100})')),
    # Generic webhook keyword
    ("Generic Webhook URL",
     re.compile(r'(?i)webhook[_\-]?url\s*[=:]\s*["\']?(https?://[^\s"\'<>&]{15,300})["\']?')),
    # Stripe / Payment webhooks
    ("Stripe Webhook Secret",
     re.compile(r'\b(whsec_[A-Za-z0-9]{32,100})\b')),
    # Generic /webhook endpoint reference
    ("Webhook Endpoint Path",
     re.compile(r'(?i)["\']/(api/)?webhooks?/[A-Za-z0-9_\-/]{3,80}["\']')),
    # Datadog
    ("Datadog Webhook",
     re.compile(r'(https://app\.datadoghq\.com/intake/webhook/[^\s"\'<>]{5,100})')),
    # Jira / Confluence
    ("Atlassian Webhook",
     re.compile(r'(https://[a-z0-9\-]+\.atlassian\.net/rest/webhooks/[^\s"\'<>]{5,150})')),
]

_WEBHOOK_JS_EVAL = """() => {
    const results = {};
    const kwds = [
        'webhookUrl','webhook_url','WEBHOOK_URL',
        'SLACK_WEBHOOK','DISCORD_WEBHOOK','TEAMS_WEBHOOK',
        'slackWebhook','discordWebhook','zapierWebhook',
        'notifyUrl','notify_url','callbackUrl','callback_url',
    ];
    kwds.forEach(k => {
        try {
            const v = window[k]
                   || (window.__ENV__ && window.__ENV__[k])
                   || (window._env_ && window._env_[k])
                   || (window.ENV && window.ENV[k]);
            if (v && typeof v === 'string' && v.startsWith('http'))
                results[k] = v;
        } catch(e) {}
    });
    // Look for fetch/axios calls pointing to webhook-like URLs
    const scripts = document.querySelectorAll('script:not([src])');
    const webhookPat = /https?:\\/\\/hooks\\.(slack|zapier)\\.com[^\\s"'<>]{5,200}/gi;
    scripts.forEach(s => {
        const m = s.textContent.match(webhookPat);
        if (m) m.forEach((url, i) => { results['inline_script_' + i] = url; });
    });
    return results;
}"""

def _webhooks_sync(url: str, progress_cb=None) -> dict:
    data = _extract_run(url, _WEBHOOK_JS_EVAL, progress_cb)
    if data.get("error"):
        return {"error": data["error"], "findings": [], "page_url": url}

    findings = []
    seen = set()

    def _add(key_type, value, source):
        dedup = key_type + ":" + value[:80]
        if dedup in seen or len(value) < 8:
            return
        seen.add(dedup)
        findings.append({"type": key_type, "value": value, "source": source})

    if progress_cb: progress_cb("🪝 Scanning for exposed webhook URLs...")

    for text, label in _gather_all_text(data):
        for key_type, pat in _WEBHOOK_PATTERNS:
            for m in pat.finditer(text):
                val = m.group(1) if m.lastindex else m.group(0)
                _add(key_type, val.strip(), label)

    # DOM globals
    for k, v in (data.get("dom_result") or {}).items():
        for key_type, pat in _WEBHOOK_PATTERNS:
            m = pat.search(str(v))
            if m:
                _add(key_type, (m.group(1) if m.lastindex else m.group(0)), f"window.{k}")

    return {"error": None, "findings": findings, "page_url": data["page_url"],
            "requests": len(data.get("network_log", []))}


async def cmd_webhooks(update: Update, context: ContextTypes.DEFAULT_TYPE):
    """/webhooks <url> — Extract exposed webhook URLs from a site"""
    if not await check_force_join(update, context): return
    if not context.args:
        await update.effective_message.reply_text(
            "📌 *Usage:* `/webhooks https://example.com`\n\n"
            "🪝 *Detects:*\n"
            "  • Slack / Discord / MS Teams webhooks\n"
            "  • Zapier / IFTTT / PagerDuty hooks\n"
            "  • Stripe webhook secrets (`whsec_...`)\n"
            "  • Telegram bot webhook URLs\n"
            "  • Datadog / Atlassian / Generic webhooks\n"
            "  • GitHub webhook secrets\n\n"
            "⚠️ _Authorized testing only_", parse_mode='Markdown')
        return

    uid = update.effective_user.id
    allowed, wait = check_rate_limit(uid)
    if not allowed:
        await update.effective_message.reply_text(f"⏳ `{wait}s` စောင့်ပါ", parse_mode='Markdown')
        return

    url = context.args[0].strip()
    if not url.startswith("http"): url = "https://" + url
    safe_ok, reason = is_safe_url(url)
    if not safe_ok:
        await update.effective_message.reply_text(f"🚫 `{escape_md(reason)}`", parse_mode='Markdown')
        return

    domain = urlparse(url).netloc
    msg = await update.effective_message.reply_text(
        f"🪝 *Webhook Extractor — `{escape_md(domain)}`*\n\n⏳ Scanning...", parse_mode='Markdown')

    progress_q = []
    async def _prog():
        while True:
            await asyncio.sleep(2)
            if progress_q:
                t = progress_q[-1]; progress_q.clear()
                try: await msg.edit_text(
                    f"🪝 *Webhook Extractor — `{escape_md(domain)}`*\n\n{t}", parse_mode='Markdown')
                except: pass
    prog = asyncio.create_task(_prog())

    try:
        result = await asyncio.to_thread(_webhooks_sync, url, lambda t: progress_q.append(t))
    except Exception as e:
        prog.cancel()
        await msg.edit_text(f"❌ `{escape_md(e)}`", parse_mode='Markdown')
        return
    finally:
        prog.cancel()

    if result.get("error"):
        await msg.edit_text(f"❌ `{result['error']}`", parse_mode='Markdown')
        return

    findings = result["findings"]
    page_url = result["page_url"]
    reqs     = result.get("requests", 0)

    if not findings:
        await msg.edit_text(
            f"🪝 *Webhook Extractor — `{escape_md(domain)}`*\n━━━━━━━━━━━━━━━━━━━━\n\n"
            f"📭 No webhook URLs found\n"
            f"🌐 `{escape_md(page_url)}`\n📡 Requests: `{escape_md(reqs)}`",
            parse_mode='Markdown')
        return

    lines = [
        f"🪝 *Webhook Extractor — `{escape_md(domain)}`*",
        "━━━━━━━━━━━━━━━━━━━━",
        f"🌐 `{escape_md(page_url)}`",
        f"📡 Requests: `{escape_md(reqs)}`",
        f"✅ Found: `{len(findings)}`\n",
    ]
    for i, f in enumerate(findings, 1):
        lines.append(f"*[{i}] {f['type']}*")
        lines.append(f"  `{f['value'][:80]}`")
        lines.append(f"  _📂 {f['source'][:60]}_\n")
    lines.append("━━━━━━━━━━━━━━━━━━\n⚠️ _Authorized testing only_")

    report = "\n".join(lines)
    try:
        if len(report) <= 4000:
            await safe_markdown_reply(msg, _truncate_safe_md(report))
        else:
            await safe_markdown_reply(msg, _truncate_safe_md(report))
    except BadRequest:
        await update.effective_message.reply_text(_truncate_safe_md(report), parse_mode='Markdown')


